Skin names must match those defined in the Spine editor project. After switching skins, call `setSlotsToSetupPose()` to ensure all slots pick up the new skin's default attachments. The current animation continues playing with the new skin.

Detect swipe direction by comparing start and end positions:

```typescript
enum SwipeDirection { UP, DOWN, LEFT, RIGHT }

class SwipeDetector {
    private _listener: cc.EventListener;
    private _callback: (dir: SwipeDirection) => void;
    private static readonly MIN_SWIPE_DISTANCE = 50;

    constructor(node: cc.Node, callback: (dir: SwipeDirection) => void) {
        this._callback = callback;
        this._listener = cc.eventManager.addListener({
            event: cc.EventListener.TOUCH_ONE_BY_ONE,
            swallowTouches: true,
            onTouchBegan: (touch: cc.Touch, event: cc.Event): boolean => {
                return true;
            },
            onTouchEnded: (touch: cc.Touch, event: cc.Event): void => {
                const start = touch.getStartLocation();
                const end = touch.getLocation();
                const dx = end.x - start.x;
                const dy = end.y - start.y;
                const absDx = Math.abs(dx);
                const absDy = Math.abs(dy);
                const minDist = SwipeDetector.MIN_SWIPE_DISTANCE;

                if (absDx < minDist && absDy < minDist) {
                    return; // too short, treat as tap
                }

                if (absDx > absDy) {
                    this._callback(dx > 0 ? SwipeDirection.RIGHT : SwipeDirection.LEFT);
                } else {
                    this._callback(dy > 0 ? SwipeDirection.UP : SwipeDirection.DOWN);
                }
            }
        }, node);
    }

    destroy(): void {
        cc.eventManager.removeListener(this._listener);
    }
}

// Usage:
const detector = new SwipeDetector(gameLayer, (dir) => {
    if (dir === SwipeDirection.LEFT) movePieceLeft();
    else if (dir === SwipeDirection.RIGHT) movePieceRight();
});
```

Use `cc.sys.isNative` to branch between JSB file utilities and localStorage:

```typescript
class SaveSystem {
    private static readonly SAVE_FILE = 'save_data.json';
    private static readonly STORAGE_KEY = 'save_data';

    static save(data: object): void {
        const json = JSON.stringify(data);
        if (cc.sys.isNative) {
            const path = cc.path.join(jsb.fileUtils.getWritablePath(), SaveSystem.SAVE_FILE);
            jsb.fileUtils.writeStringToFile(json, path);
            cc.log('Saved to file:', path);
        } else {
            cc.sys.localStorage.setItem(SaveSystem.STORAGE_KEY, json);
            cc.log('Saved to localStorage');
        }
    }

    static load<T>(defaultValue: T): T {
        let raw: string | null = null;
        if (cc.sys.isNative) {
            const path = cc.path.join(jsb.fileUtils.getWritablePath(), SaveSystem.SAVE_FILE);
            if (jsb.fileUtils.isFileExist(path)) {
                raw = jsb.fileUtils.getStringFromFile(path);
            }
        } else {
            raw = cc.sys.localStorage.getItem(SaveSystem.STORAGE_KEY);
        }
        if (!raw) return defaultValue;
        try {
            return JSON.parse(raw) as T;
        } catch (e) {
            cc.error('Failed to parse save data:', e);
            return defaultValue;
        }
    }

    static deleteSave(): void {
        if (cc.sys.isNative) {
            const path = cc.path.join(jsb.fileUtils.getWritablePath(), SaveSystem.SAVE_FILE);
            jsb.fileUtils.removeFile(path);
        } else {
            cc.sys.localStorage.removeItem(SaveSystem.STORAGE_KEY);
        }
    }
}
```

