Layer sprites at different z-orders and move them at different rates:

```typescript
class ParallaxScene extends cc.Scene {
    private backgrounds: { node: cc.Sprite; speed: number }[] = [];

    onEnter(): void {
        super.onEnter();

        const layers = [
            { img: 'bg_sky.png', z: -3, speed: 0.1 },
            { img: 'bg_mountains.png', z: -2, speed: 0.3 },
            { img: 'bg_trees.png', z: -1, speed: 0.6 },
            { img: 'bg_ground.png', z: 0, speed: 1.0 },
        ];

        layers.forEach(cfg => {
            const sprite = new cc.Sprite(cfg.img);
            sprite.setAnchorPoint(cc.p(0, 0));
            sprite.setPosition(0, 0);
            this.addChild(sprite, cfg.z);
            this.backgrounds.push({ node: sprite, speed: cfg.speed });
        });

        this.scheduleUpdate();
    }

    update(dt: number): void {
        const scrollSpeed = 100; // pixels per second
        this.backgrounds.forEach(bg => {
            bg.node.x -= scrollSpeed * bg.speed * dt;
            // Wrap around
            if (bg.node.x <= -bg.node.width) {
                bg.node.x += bg.node.width;
            }
        });
    }
}
```

Use different strategies depending on the search:

```typescript
// 1. Direct child by tag (O(n) on children count)
const child = parent.getChildByTag(42);

// 2. Direct child by name (O(n) on children count)
const named = parent.getChildByName('player');

// 3. Deep recursive search by name
let found: cc.Node | null = null;
root.enumerateChildren('//player', (node) => {
    found = node;
    return true; // stop on first match
});

// 4. Maintain your own lookup map for O(1) access
class NodeRegistry {
    private static map: Map<string, cc.Node> = new Map();

    static register(key: string, node: cc.Node): void {
        this.map.set(key, node);
    }

    static unregister(key: string): void {
        this.map.delete(key);
    }

    static get(key: string): cc.Node | undefined {
        return this.map.get(key);
    }
}

// Register on creation
NodeRegistry.register('player', playerNode);
// Fast lookup
const player = NodeRegistry.get('player');
```

For large scenes, maintain a registry rather than searching the tree every frame.

