```typescript
function drawGrid(
    draw: cc.DrawNode,
    cellSize: number,
    majorEvery: number,
    winSize: cc.Size
): void {
    draw.clear();
    const minorColor = cc.color(60, 60, 60, 100);
    const majorColor = cc.color(100, 100, 100, 180);
    const axisColor = cc.color(150, 150, 150, 255);

    const cols = Math.ceil(winSize.width / cellSize);
    const rows = Math.ceil(winSize.height / cellSize);

    // Vertical lines
    for (let c = 0; c <= cols; c++) {
        const x = c * cellSize;
        const isMajor = c % majorEvery === 0;
        draw.drawSegment(
            cc.p(x, 0), cc.p(x, winSize.height),
            isMajor ? 1 : 0.5,
            isMajor ? majorColor : minorColor
        );
    }

    // Horizontal lines
    for (let r = 0; r <= rows; r++) {
        const y = r * cellSize;
        const isMajor = r % majorEvery === 0;
        draw.drawSegment(
            cc.p(0, y), cc.p(winSize.width, y),
            isMajor ? 1 : 0.5,
            isMajor ? majorColor : minorColor
        );
    }

    // Origin axes
    draw.drawSegment(cc.p(0, 0), cc.p(winSize.width, 0), 1.5, axisColor);
    draw.drawSegment(cc.p(0, 0), cc.p(0, winSize.height), 1.5, axisColor);
}

// Usage:
const gridDraw = new cc.DrawNode();
this.addChild(gridDraw, -1);
const winSize = cc.director.getWinSize();
drawGrid(gridDraw, 32, 4, winSize); // 32px cells, major every 4
```

CharMap is fastest for numeric-only displays:

```typescript
class FPSCounter extends cc.Node {
    private label: cc.Label;
    private frames: number = 0;
    private elapsed: number = 0;

    onEnter(): void {
        super.onEnter();
        // CharMap with digits 0-9 (ASCII 48-57)
        this.label = cc.Label.createWithCharMap('res/fonts/fps_digits.png', 12, 18, 48);
        this.label.setString('60');
        this.label.setAnchorPoint(cc.p(1, 1));
        this.addChild(this.label);

        this.scheduleUpdate();
    }

    update(dt: number): void {
        this.frames++;
        this.elapsed += dt;
        if (this.elapsed >= 0.5) {
            const fps = Math.round(this.frames / this.elapsed);
            this.label.setString(String(fps));
            this.frames = 0;
            this.elapsed = 0;
        }
    }

    onExit(): void {
        this.unscheduleUpdate();
        super.onExit();
    }
}
```

