Practical multi-resolution setup:
```typescript
function setupResolution(): void {
    const designWidth = 960;
    const designHeight = 640;

    cc.view.setDesignResolutionSize(
        designWidth,
        designHeight,
        cc.ResolutionPolicy.SHOW_ALL
    );

    // Adjust content scale based on screen DPI
    const frameSize = cc.view.getFrameSize();
    const scaleFactor = frameSize.height / designHeight;
    cc.director.setContentScaleFactor(scaleFactor);

    cc.log('Design:', designWidth, 'x', designHeight);
    cc.log('Frame:', frameSize.width, 'x', frameSize.height);
    cc.log('Scale factor:', cc.director.getContentScaleFactor());
}
```

