    }
}

class PauseOverlay extends cc.LayerColor {
    constructor() {
        super(cc.color(0, 0, 0, 160));
        this.init();
    }

    init(): boolean {
        const winSize = cc.director.getWinSize();
        this.setContentSize(winSize);

        const label = new cc.LabelTTF('PAUSED', 'Arial', 48);
        label.setPosition(winSize.width / 2, winSize.height / 2);
        this.addChild(label);

        return true;
    }
}

class GameScene {
    private scene: cc.Scene;
    private gameLayer: GameLayer;
    private pauseOverlay: PauseOverlay;
    private isPaused: boolean = false;

    constructor() {
        this.scene = new cc.Scene();
        this.gameLayer = new GameLayer();
        this.pauseOverlay = new PauseOverlay();
        this.pauseOverlay.setVisible(false);

        this.scene.addChild(this.gameLayer, 0);
        this.scene.addChild(this.pauseOverlay, 10);
    }

    togglePause(): void {
        this.isPaused = !this.isPaused;
        this.pauseOverlay.setVisible(this.isPaused);
        if (this.isPaused) {
            cc.director.pause();
        } else {
            cc.director.resume();
        }
    }

    run(): void {
        cc.director.runScene(this.scene);
    }
}
```

The `PauseOverlay` extends `cc.LayerColor` with a semi-transparent black background (alpha 160). It sits above the game layer at z-order 10. Toggling pause shows/hides the overlay and uses `cc.director.pause()`/`resume()` to freeze game logic.

```typescript
cc.sys.localStorage.removeItem(key: string): void
```

Removes a single key-value pair from storage.

```typescript
class ResetManager {
    private static readonly GAME_KEYS = [
        'highscore',
        'current_level',
        'inventory',
        'achievements',
        'player_profile',
        'settings'
    ] as const;

    static resetProgress(): void {
        cc.sys.localStorage.removeItem('highscore');
        cc.sys.localStorage.removeItem('current_level');
        cc.sys.localStorage.removeItem('inventory');
        cc.sys.localStorage.removeItem('achievements');
        cc.log('Progress reset');
    }

    static resetSettings(): void {
        cc.sys.localStorage.removeItem('settings');
        cc.log('Settings reset to defaults');
    }

    static resetAll(): void {
        for (const key of ResetManager.GAME_KEYS) {
            cc.sys.localStorage.removeItem(key);
        }
        cc.log('All data reset');
    }

    static resetWithConfirmation(callback: (confirmed: boolean) => void): void {
        // In practice, show a UI dialog first
        // After confirmation:
        ResetManager.resetAll();
        callback(true);
    }
}

// Usage:
ResetManager.resetProgress();  // keep settings, reset game data
ResetManager.resetAll();       // clear everything
```

Prefer targeted `removeItem` calls over `clear()` to avoid accidentally removing data from other parts of the app.

The `setAnimationListener` method and its callback have these signatures:

```typescript
// Method signature
setAnimationListener(target: object, callback: Function): void

// Callback signature
(trackEntry: spine.TrackEntry, type: number, event: spine.Event) => void
```

For individual listeners:
```typescript
setStartListener(listener: (trackEntry: spine.TrackEntry) => void): void
setEndListener(listener: (trackEntry: spine.TrackEntry) => void): void
```

The `type` parameter in the general listener maps to `sp.AnimationEventType`:
```typescript
