```typescript
class FlippableArmature {
    private _armature: ccs.Armature;
    private _facingRight: boolean = true;

    constructor(name: string, exportJson: string, parent: cc.Node) {
        ccs.armatureDataManager.addArmatureFileInfo(exportJson);
        this._armature = ccs.Armature.create(name);
        parent.addChild(this._armature);
    }

    setFacing(right: boolean): void {
        if (this._facingRight === right) return;
        this._facingRight = right;
        this._armature.setScaleX(right ? 1 : -1);
    }

    isFacingRight(): boolean {
        return this._facingRight;
    }

    getWorldBonePos(boneName: string): cc.Point {
        const bone = this._armature.getBone(boneName);
        if (!bone) return this._armature.getPosition();
        return bone.getWorldPosition();
    }

    getArmature(): ccs.Armature {
        return this._armature;
    }
}

// Usage:
const hero = new FlippableArmature('hero', 'res/hero/hero.ExportJson', this);
hero.getArmature().setPosition(240, 160);
hero.getArmature().animation.play('walk', -1, -1);
hero.setFacing(false);
```

You're right that `drawCircle` only draws the outline. To draw a filled circle, use `drawDot` with the desired radius:

```typescript
const draw = new cc.DrawNode();
this.addChild(draw);

// Filled circle using drawDot
draw.drawDot(cc.p(160, 240), 50, cc.color(255, 0, 0, 200));

// If you need both fill AND outline, combine drawDot + drawCircle:
draw.drawDot(cc.p(160, 240), 50, cc.color(255, 0, 0, 100));      // fill
draw.drawCircle(cc.p(160, 240), 50, 0, 32, false, 2, cc.color(255, 0, 0, 255));  // outline
```

`drawDot` renders a filled circle (a disc) at the given position and radius. Despite its name suggesting a small point, it works with any radius to create filled circles.

Alternatively, for filled polygonal approximation, generate vertices in a circle and use `drawPoly`:
```typescript
const verts: cc.Point[] = [];
for (let i = 0; i < 32; i++) {
    const a = (i / 32) * Math.PI * 2;
    verts.push(cc.p(160 + 50 * Math.cos(a), 240 + 50 * Math.sin(a)));
}
draw.drawPoly(verts, cc.color(255, 0, 0, 100), 2, cc.color(255, 0, 0, 255));
```

