Scale X to 0, swap the texture, then scale back:

```typescript
function flipCard(card: cc.Sprite, frontTexture: string, backTexture: string): void {
    const isShowingFront = card.getUserData()?.showingFront ?? false;
    const newTexture = isShowingFront ? backTexture : frontTexture;

    card.runAction(cc.sequence(
        cc.scaleTo(0.15, 0, 1).easing(cc.easeIn(2)),
        cc.callFunc(() => {
            card.setTexture(newTexture);
            card.setUserData({ showingFront: !isShowingFront });
        }),
        cc.scaleTo(0.15, 1, 1).easing(cc.easeOut(2))
    ));
}

const card = new cc.Sprite('card_back.png');
card.setPosition(200, 200);
card.setUserData({ showingFront: false });
this.addChild(card);

// Flip on tap
flipCard(card, 'card_front.png', 'card_back.png');
```

