Use `cc.sys.capabilities` and `cc.sys.isMobile` to register appropriate listeners:

```typescript
class AdaptiveInputManager extends cc.Layer {
    private _listeners: cc.EventListener[] = [];
    private _moveDirection: cc.Point = cc.p(0, 0);

    onEnter(): void {
        super.onEnter();

        if (cc.sys.capabilities.touches) {
            this.setupTouchInput();
        }
        if (cc.sys.capabilities.keyboard) {
            this.setupKeyboardInput();
        }
        if (cc.sys.capabilities.mouse && !cc.sys.isMobile) {
            this.setupMouseInput();
        }

        cc.log('Input setup for platform:', cc.sys.platform);
        this.scheduleUpdate();
    }

    private setupTouchInput(): void {
        const listener = cc.eventManager.addListener({
            event: cc.EventListener.TOUCH_ONE_BY_ONE,
            swallowTouches: true,
            onTouchBegan: (touch: cc.Touch, event: cc.Event): boolean => {
                return true;
            },
            onTouchMoved: (touch: cc.Touch, event: cc.EventTouch): void => {
                const start = touch.getStartLocation();
                const curr = touch.getLocation();
                const diff = cc.pSub(curr, start);
                const len = cc.pLength(diff);
                this._moveDirection = len > 10 ? cc.pNormalize(diff) : cc.p(0, 0);
            },
            onTouchEnded: (touch: cc.Touch, event: cc.Event): void => {
                this._moveDirection = cc.p(0, 0);
            }
        }, this);
        this._listeners.push(listener);
    }

    private setupKeyboardInput(): void {
        const keys = new Set<number>();
        const listener = cc.eventManager.addListener({
            event: cc.EventListener.KEYBOARD,
            onKeyPressed: (k: cc.KEY) => keys.add(k),
            onKeyReleased: (k: cc.KEY) => keys.delete(k)
        }, this);
        this._listeners.push(listener);
    }

    private setupMouseInput(): void {
        const listener = cc.eventManager.addListener({
            event: cc.EventListener.MOUSE,
            onMouseScroll: (event: cc.EventMouse): void => {
                cc.log('Zoom:', event.getScrollY());
            }
        }, this);
        this._listeners.push(listener);
    }

    onExit(): void {
        this._listeners.forEach(l => cc.eventManager.removeListener(l));
        this._listeners = [];
        super.onExit();
    }
}
```

instruction:
Review this Spine animation code for potential problems:

```typescript
function playCombo(skel: sp.SkeletonAnimation): void {
    skel.setAnimation(0, 'slash1', false);
    skel.addAnimation(0, 'slash2', false, 0);
    skel.addAnimation(0, 'slash3', false, 0);
    skel.addAnimation(0, 'idle', true, 0);
}
```

output:
The code is functionally correct — it queues a 3-hit combo then returns to idle. However, there are improvements to consider:

1. **No mix transitions**: Without `setMix`, transitions between slash1->slash2->slash3->idle will be instant cuts with no blending, which can look jarring.

2. **No way to interrupt**: If the player needs to cancel the combo (e.g., to dodge), there's no mechanism to do so.

3. **Return values ignored**: The `TrackEntry` objects returned by `addAnimation` are not captured, making it impossible to adjust timing or cancel specific entries.

**Improved code:**
```typescript
function setupComboMixes(skel: sp.SkeletonAnimation): void {
    skel.setMix('slash1', 'slash2', 0.05);
    skel.setMix('slash2', 'slash3', 0.05);
    skel.setMix('slash3', 'idle', 0.2);
}

function playCombo(skel: sp.SkeletonAnimation): spine.TrackEntry | null {
    skel.setAnimation(0, 'slash1', false);
    skel.addAnimation(0, 'slash2', false, 0);
    skel.addAnimation(0, 'slash3', false, 0);
    const idleTrack = skel.addAnimation(0, 'idle', true, 0);
    return idleTrack;
}

function cancelCombo(skel: sp.SkeletonAnimation): void {
    skel.setAnimation(0, 'idle', true);
}
```

Setup mixes before the combo and capture return values for potential interruption.

These methods return the touch position in different coordinate systems:

**`touch.getLocation(): cc.Point`** — Returns the position in **GL (game world) coordinates**. Origin is at the bottom-left of the screen. Y increases upward. This is what you should use for game logic and node positioning.

**`touch.getLocationInView(): cc.Point`** — Returns the position in **screen (view) coordinates**. Origin is at the top-left. Y increases downward. This matches browser/OS coordinate conventions.

```typescript
onTouchBegan: (touch: cc.Touch, event: cc.Event): boolean => {
    const glPos = touch.getLocation();         // e.g., { x: 200, y: 300 } (bottom-left origin)
    const screenPos = touch.getLocationInView(); // e.g., { x: 200, y: 180 } (top-left origin)

    // For hit-testing against game nodes, use GL coordinates:
    const nodeLocal = mySprite.convertToNodeSpace(glPos);

    // For interfacing with HTML DOM elements, use screen coordinates:
    // positionDomElement(screenPos.x, screenPos.y);

    return true;
}
```

Similarly, `getPreviousLocation()` vs `getPreviousLocationInView()` and `getStartLocation()` vs `getStartLocationInView()` follow the same pattern.

```typescript
const enum BossPhase { PHASE1 = 1, PHASE2 = 2, PHASE3 = 3 }
const enum BossState { IDLE = 'idle', ATTACK_A = 'attack_a', ATTACK_B = 'attack_b', ATTACK_C = 'attack_c', TRANSITION = 'transition', DEATH = 'death' }

class BossController extends cc.Node {
    private _armature: ccs.Armature;
    private _phase: BossPhase = BossPhase.PHASE1;
    private _state: BossState = BossState.IDLE;
    private _hp: number;
    private _maxHp: number;

    constructor(exportJson: string, name: string, maxHp: number) {
        super();
        this._maxHp = maxHp;
        this._hp = maxHp;
        ccs.armatureDataManager.addArmatureFileInfo(exportJson);
        this._armature = ccs.Armature.create(name);
        this.addChild(this._armature);
        this.setupEvents();
        this.idle();
    }

    private setupEvents(): void {
        this._armature.animation.setMovementEventCallFunc((arm, type, id) => {
            if (type !== ccs.MovementEventType.COMPLETE) return;
            if (id === BossState.TRANSITION) {
                this.idle();
            } else if (id === BossState.DEATH) {
                this.onDeathComplete();
            } else {
                this.idle();
                this.scheduleOnce(() => this.chooseAttack(), 1.0);
            }
        });

        this._armature.animation.setFrameEventCallFunc((bone, evt) => {
            if (evt === 'damage_zone') {
                this.onDamageFrame(bone);
            }
        });
    }

    takeDamage(amount: number): void {
        this._hp = Math.max(0, this._hp - amount);
        const ratio = this._hp / this._maxHp;

        if (this._hp <= 0) {
            this.changeState(BossState.DEATH, 0);
        } else if (ratio < 0.33 && this._phase < BossPhase.PHASE3) {
            this._phase = BossPhase.PHASE3;
            this.changeState(BossState.TRANSITION, 0);
            this._armature.animation.setSpeedScale(1.5);
        } else if (ratio < 0.66 && this._phase < BossPhase.PHASE2) {
            this._phase = BossPhase.PHASE2;
            this.changeState(BossState.TRANSITION, 0);
            this._armature.animation.setSpeedScale(1.2);
        }
    }

    private chooseAttack(): void {
        const attacks = this.getAttacksForPhase();
        const idx = Math.floor(Math.random() * attacks.length);
        this.changeState(attacks[idx], 0);
    }

    private getAttacksForPhase(): BossState[] {
        switch (this._phase) {
            case BossPhase.PHASE1: return [BossState.ATTACK_A];
            case BossPhase.PHASE2: return [BossState.ATTACK_A, BossState.ATTACK_B];
            case BossPhase.PHASE3: return [BossState.ATTACK_A, BossState.ATTACK_B, BossState.ATTACK_C];
        }
    }

    private idle(): void {
        this.changeState(BossState.IDLE, -1);
    }

    private changeState(state: BossState, loop: number): void {
        this._state = state;
        this._armature.animation.play(state, 5, loop);
    }

    private onDamageFrame(bone: ccs.Bone): void {
        const pos = bone.getWorldPosition();
        cc.log('Boss damage zone at:', pos.x, pos.y);
    }

    private onDeathComplete(): void {
        cc.log('Boss defeated');
    }
}
```

instruction:
Find and fix the bug:

```typescript
const sprite = new cc.Sprite('res/hero.png');
sprite.setFlippedX(true);
const child = new cc.Sprite('res/weapon.png');
child.setPosition(20, 0);
sprite.addChild(child);
```

output:
The issue is that `setFlippedX(true)` only flips the sprite's own texture — it does NOT flip child nodes. So the weapon will appear at `(+20, 0)` relative to the hero regardless of the flip, which looks wrong when the hero faces left.

If you want children to flip too, use negative scaleX instead:

Fixed code:
```typescript
const sprite = new cc.Sprite('res/hero.png');
sprite.setScaleX(-1);  // flips texture AND children
const child = new cc.Sprite('res/weapon.png');
child.setPosition(20, 0);
sprite.addChild(child);
```

Or keep `setFlippedX` but manually adjust child positions:
```typescript
const sprite = new cc.Sprite('res/hero.png');
sprite.setFlippedX(true);
const child = new cc.Sprite('res/weapon.png');
child.setPosition(-20, 0);  // negate x when flipped
sprite.addChild(child);
```

