`setItemModel` defines a template widget that `pushBackDefaultItem` clones to create new list items.

**Workflow:**
1. Create a template widget and configure it
2. Set it as the model with `setItemModel`
3. Call `pushBackDefaultItem()` to clone and add it

```typescript
// 1. Create template
const model = new ccui.Button('item_bg.png');
model.setScale9Enabled(true);
model.setSize(cc.size(280, 45));
model.setTitleText('Default');
model.setTitleFontSize(16);

// 2. Set as model
lv.setItemModel(model);

// 3. Clone and add
for (let i = 0; i < 10; i++) {
    lv.pushBackDefaultItem();
    // Customize each clone:
    const item = lv.getItem(i) as ccui.Button;
    item.setTitleText('Item ' + i);
}
```

**vs pushBackCustomItem:**
- `pushBackDefaultItem()` — clones the model
- `pushBackCustomItem(widget)` — adds a specific widget you created

Use the model approach when all items share the same structure. Use custom items when each item is different.

Track hold duration using touch timing and custom events:

```typescript
const AttackEvents = {
    CHARGE_START: 'attack:charge_start',
    CHARGE_UPDATE: 'attack:charge_update',
    CHARGE_RELEASE: 'attack:charge_release'
} as const;

class ChargeAttackController extends cc.Layer {
    private _listener: cc.EventListener;
    private _chargeStart: number = 0;
    private _isCharging: boolean = false;
    private static readonly MAX_CHARGE_TIME = 2.0;

    onEnter(): void {
        super.onEnter();
        this._listener = cc.eventManager.addListener({
            event: cc.EventListener.TOUCH_ONE_BY_ONE,
            swallowTouches: true,
            onTouchBegan: (touch: cc.Touch, event: cc.Event): boolean => {
                this._isCharging = true;
                this._chargeStart = Date.now() / 1000;
                cc.eventManager.dispatchCustomEvent(AttackEvents.CHARGE_START, {
                    position: touch.getLocation()
                });
                return true;
            },
            onTouchMoved: (touch: cc.Touch, event: cc.EventTouch): void => {
                if (!this._isCharging) return;
                const elapsed = Date.now() / 1000 - this._chargeStart;
                const ratio = Math.min(elapsed / ChargeAttackController.MAX_CHARGE_TIME, 1.0);
                cc.eventManager.dispatchCustomEvent(AttackEvents.CHARGE_UPDATE, {
                    ratio: ratio,
                    position: touch.getLocation()
                });
            },
            onTouchEnded: (touch: cc.Touch, event: cc.Event): void => {
                if (!this._isCharging) return;
                this._isCharging = false;
                const elapsed = Date.now() / 1000 - this._chargeStart;
                const ratio = Math.min(elapsed / ChargeAttackController.MAX_CHARGE_TIME, 1.0);
                cc.eventManager.dispatchCustomEvent(AttackEvents.CHARGE_RELEASE, {
                    power: ratio,
                    position: touch.getLocation()
                });
            }
        }, this);
    }

    onExit(): void {
        cc.eventManager.removeListener(this._listener);
        super.onExit();
    }
}

// Charge bar UI listens for updates
cc.eventManager.addCustomListener(AttackEvents.CHARGE_UPDATE, (event: cc.Event) => {
    const data = event.getUserData<{ ratio: number }>();
    chargeBar.setScaleX(data.ratio);
});
```

Use jumpBy for parabolic projectile paths:

```typescript
function fireProjectile(
    parent: cc.Node, from: cc.Point, to: cc.Point,
    height: number, onHit: () => void
): void {
    const bullet = new cc.Sprite('fireball.png');
    bullet.setPosition(from);
    parent.addChild(bullet, 10);

    const dx = to.x - from.x;
    const dy = to.y - from.y;
    const dist = Math.sqrt(dx * dx + dy * dy);
    const duration = dist / 400; // speed

    bullet.runAction(cc.sequence(
        cc.spawn(
            cc.jumpBy(duration, cc.p(dx, dy), height, 1),
            cc.rotateBy(duration, 360 * 2)
        ),
        cc.callFunc(() => {
            bullet.removeFromParent();
            onHit();
        })
    ));
}

fireProjectile(this, cc.p(50, 100), cc.p(350, 100), 120, () => {
    cc.log('Hit!');
});
```

