Use platform detection combined with `cc.director.getSafeAreaRect()` (if available) or manual offsets:

```typescript
class SafeAreaHelper {
    static getInsets(): { top: number; bottom: number; left: number; right: number } {
        const winSize = cc.director.getWinSize();
        const defaults = { top: 0, bottom: 0, left: 0, right: 0 };

        if (!cc.sys.isMobile) return defaults;

        // Try safe area rect from director
        const safeRect = cc.director.getSafeAreaRect();
        if (safeRect) {
            return {
                left: safeRect.x,
                bottom: safeRect.y,
                right: winSize.width - (safeRect.x + safeRect.width),
                top: winSize.height - (safeRect.y + safeRect.height)
            };
        }

        // Fallback: estimate based on platform
        if (cc.sys.platform === cc.sys.IPHONE) {
            return { top: 44, bottom: 34, left: 0, right: 0 };
        }

        return defaults;
    }

    static adjustUI(node: cc.Node): void {
        const insets = SafeAreaHelper.getInsets();
        const winSize = cc.director.getWinSize();

        // Position UI elements within safe area
        const safeWidth = winSize.width - insets.left - insets.right;
        const safeHeight = winSize.height - insets.top - insets.bottom;
        const safeCenterX = insets.left + safeWidth / 2;
        const safeCenterY = insets.bottom + safeHeight / 2;

        node.setPosition(safeCenterX, safeCenterY);
        cc.log('Safe area:', safeWidth, 'x', safeHeight);
    }
}
```

Load resources during a transition scene, then swap:

```typescript
class SmartTransition {
    static go(
        targetFactory: () => cc.Scene,
        resources: string[]
    ): void {
        // Create an intermediate loading scene
        const loadingScene = new cc.Scene();
        const winSize = cc.director.getWinSize();

        const overlay = new cc.LayerColor(cc.color(0, 0, 0));
        loadingScene.addChild(overlay);

        const label = new cc.LabelTTF('Loading...', 'Arial', 18);
        label.setPosition(winSize.width / 2, winSize.height / 2);
        loadingScene.addChild(label);

        // Fade to loading scene
        cc.director.runScene(new cc.TransitionFade(0.3, loadingScene));

        // Start loading after transition completes
        const waitNode = new cc.Node();
        loadingScene.addChild(waitNode);
        waitNode.scheduleOnce(() => {
            if (resources.length === 0) {
                SmartTransition.finalize(targetFactory);
                return;
            }
            cc.loader.load(resources, (err) => {
                if (err) cc.error('Load error:', err);
                SmartTransition.finalize(targetFactory);
            });
        }, 0.4); // wait for fade-in
    }

    private static finalize(factory: () => cc.Scene): void {
        const target = factory();
        cc.director.runScene(new cc.TransitionFade(0.3, target));
    }
}

// Usage:
SmartTransition.go(
    () => new GameScene(),
    ['res/game/atlas.png', 'res/game/level.json']
);
```

