```typescript
const enum CharState {
    IDLE = 'idle',
    WALK = 'walk',
    RUN = 'run',
    ATTACK = 'attack',
    HURT = 'hurt'
}

class CharacterController extends cc.Node {
    private _armature: ccs.Armature;
    private _state: CharState = CharState.IDLE;
    private _facingRight: boolean = true;

    constructor(armatureName: string, exportJson: string) {
        super();
        ccs.armatureDataManager.addArmatureFileInfo(exportJson);
        this._armature = ccs.Armature.create(armatureName);
        this.addChild(this._armature);
        this.setupAnimEvents();
        this.setState(CharState.IDLE);
    }

    private setupAnimEvents(): void {
        this._armature.animation.setMovementEventCallFunc((arm, type, id) => {
            if (type === ccs.MovementEventType.COMPLETE) {
                if (id === CharState.ATTACK || id === CharState.HURT) {
                    this.setState(CharState.IDLE);
                }
            }
        });

        this._armature.animation.setFrameEventCallFunc((bone, eventName) => {
            if (eventName === 'attack_hit') {
                this.onAttackHit();
            }
        });
    }

    setState(state: CharState): void {
        if (this._state === state) return;
        if (this._state === CharState.ATTACK && state !== CharState.HURT) return;

        this._state = state;
        const loop = (state === CharState.IDLE || state === CharState.WALK || state === CharState.RUN) ? -1 : 0;
        this._armature.animation.play(state, 5, loop);
    }

    setFacing(right: boolean): void {
        if (this._facingRight === right) return;
        this._facingRight = right;
        this._armature.setScaleX(right ? 1 : -1);
    }

    attack(): void {
        this.setState(CharState.ATTACK);
    }

    private onAttackHit(): void {
        const handPos = this._armature.getBone('hand_r').getWorldPosition();
        cc.log('Attack hit at:', handPos.x, handPos.y);
    }
}

// Usage:
const hero = new CharacterController('hero', 'res/hero/hero.ExportJson');
hero.setPosition(240, 160);
this.addChild(hero);
hero.setState(CharState.WALK);
hero.setFacing(false); // face left
```

The arrow key constants are:

```typescript
cc.KEY.left  = 37
cc.KEY.up    = 38
cc.KEY.right = 39
cc.KEY.down  = 40
```

Usage for 4-directional movement:

```typescript
class CharacterController extends cc.Layer {
    private _listener: cc.EventListener;
    private _activeKeys: Set<number> = new Set();
    private _player: cc.Node;
    private static readonly SPEED = 150;

    onEnter(): void {
        super.onEnter();
        this._listener = cc.eventManager.addListener({
            event: cc.EventListener.KEYBOARD,
            onKeyPressed: (keyCode: cc.KEY, event: cc.Event): void => {
                this._activeKeys.add(keyCode);
            },
            onKeyReleased: (keyCode: cc.KEY, event: cc.Event): void => {
                this._activeKeys.delete(keyCode);
            }
        }, this);
        this.scheduleUpdate();
    }

    update(dt: number): void {
        const speed = CharacterController.SPEED * dt;
        if (this._activeKeys.has(cc.KEY.left))  this._player.x -= speed;
        if (this._activeKeys.has(cc.KEY.right)) this._player.x += speed;
        if (this._activeKeys.has(cc.KEY.up))    this._player.y += speed;
        if (this._activeKeys.has(cc.KEY.down))  this._player.y -= speed;
    }

    onExit(): void {
        cc.eventManager.removeListener(this._listener);
        super.onExit();
    }
}
```

This supports diagonal movement when two arrow keys are pressed simultaneously.

