Complete the code to implement a touch event that only triggers when the user taps inside a circular region:

```typescript
class CircleButton {
    private _center: cc.Point;
    private _radius: number;
    // TODO: add touch listener that detects taps inside the circle
}
```

output:
```typescript
class CircleButton {
    private _center: cc.Point;
    private _radius: number;
    private _node: cc.Node;
    private _listener: cc.EventListener;
    private _onTap: () => void;

    constructor(node: cc.Node, center: cc.Point, radius: number, onTap: () => void) {
        this._node = node;
        this._center = center;
        this._radius = radius;
        this._onTap = onTap;
    }

    enable(): void {
        this._listener = cc.eventManager.addListener({
            event: cc.EventListener.TOUCH_ONE_BY_ONE,
            swallowTouches: true,
            onTouchBegan: (touch: cc.Touch, event: cc.Event): boolean => {
                const worldPos = touch.getLocation();
                const localPos = this._node.convertToNodeSpace(worldPos);
                const dist = cc.pDistance(localPos, this._center);
                return dist <= this._radius;
            },
            onTouchEnded: (touch: cc.Touch, event: cc.Event): void => {
                const worldPos = touch.getLocation();
                const localPos = this._node.convertToNodeSpace(worldPos);
                const dist = cc.pDistance(localPos, this._center);
                if (dist <= this._radius) {
                    this._onTap();
                }
            }
        }, this._node);
    }

    disable(): void {
        cc.eventManager.removeListener(this._listener);
    }
}

// Usage:
const btn = new CircleButton(myLayer, cc.p(100, 100), 40, () => {
    cc.log('Circle tapped!');
});
btn.enable();
```

The hit test uses `cc.pDistance` to check if the touch is within the circle's radius in both `onTouchBegan` (to claim the touch) and `onTouchEnded` (to confirm the release is still inside).

```typescript
// Get the sprite's index within the batch node's texture atlas
