dialog.setSize(cc.size(340, 120));
dialog.setBackGroundColorType(ccui.Layout.BG_COLOR_SOLID);
dialog.setBackGroundColor(cc.color(10, 10, 30));
dialog.setBackGroundColorOpacity(220);
dialog.setPosition(70, 50);
