`cc.sys.localStorage.clear()` removes ALL stored key-value pairs:

```typescript
cc.sys.localStorage.clear(): void
```

This is destructive — use it carefully:

```typescript
// DANGEROUS: clears everything
cc.sys.localStorage.clear();

// Safer approach: selective clearing
class StorageManager {
    private static readonly GAME_KEYS = [
        'highscore', 'level', 'inventory', 'settings'
    ];
    private static readonly PROTECTED_KEYS = ['device_id', 'first_launch'];

    static clearGameData(): void {
        // Only clear game-related keys, preserve system keys
        for (const key of StorageManager.GAME_KEYS) {
            cc.sys.localStorage.removeItem(key);
        }
        cc.log('Game data cleared');
    }

    static fullReset(): void {
        // Confirm before clearing everything
        cc.log('Performing full storage reset');
        cc.sys.localStorage.clear();
    }

    static resetWithBackup(): void {
        // Save protected data
        const backups: { [key: string]: string } = {};
        for (const key of StorageManager.PROTECTED_KEYS) {
            const val = cc.sys.localStorage.getItem(key);
            if (val) backups[key] = val;
        }

        // Clear all
        cc.sys.localStorage.clear();

        // Restore protected keys
        for (const key in backups) {
            cc.sys.localStorage.setItem(key, backups[key]);
        }
    }
