```typescript
function drawStar(
    draw: cc.DrawNode,
    center: cc.Point,
    outerRadius: number,
    innerRadius: number,
    points: number,
    fillColor: cc.Color,
    lineColor: cc.Color
): void {
    // TODO: draw a star with alternating outer/inner vertices
}
```

output:
```typescript
function drawStar(
    draw: cc.DrawNode,
    center: cc.Point,
    outerRadius: number,
    innerRadius: number,
    points: number,
    fillColor: cc.Color,
    lineColor: cc.Color
): void {
    const verts: cc.Point[] = [];
    const totalVerts = points * 2;
    const angleStep = Math.PI / points;

    for (let i = 0; i < totalVerts; i++) {
        const angle = angleStep * i - Math.PI / 2;
        const r = (i % 2 === 0) ? outerRadius : innerRadius;
        verts.push(cc.p(
            center.x + r * Math.cos(angle),
            center.y + r * Math.sin(angle)
        ));
    }

    draw.drawPoly(verts, fillColor, 2, lineColor);
}

// Usage:
const draw = new cc.DrawNode();
this.addChild(draw);

// 5-pointed star
drawStar(
    draw,
    cc.p(240, 160),
    60,  // outer radius
    25,  // inner radius
    5,   // 5 points
    cc.color(255, 215, 0, 200),  // gold fill
    cc.color(200, 160, 0, 255)   // darker gold border
);
```

The function alternates between outer and inner radius vertices, creating the classic star pattern. Even indices use the outer radius, odd indices use the inner radius.

Use `onMouseMove` to track hover state over a sprite:

```typescript
class TooltipSprite extends cc.Sprite {
    private _listener: cc.EventListener;
    private _tooltip: cc.LabelTTF;
    private _isHovering: boolean = false;

    constructor(filename: string, tooltipText: string) {
        super(filename);
        this._tooltip = new cc.LabelTTF(tooltipText, 'Arial', 14);
        this._tooltip.setVisible(false);
        this._tooltip.setAnchorPoint(0, 0);
        this.addChild(this._tooltip, 100);
    }

    onEnter(): void {
        super.onEnter();
        this._listener = cc.eventManager.addListener({
            event: cc.EventListener.MOUSE,
            onMouseMove: (event: cc.EventMouse): void => {
                const worldPos = event.getLocation();
                const localPos = this.convertToNodeSpace(worldPos);
                const size = this.getContentSize();
                const inside = cc.rectContainsPoint(
                    cc.rect(0, 0, size.width, size.height), localPos
                );

                if (inside && !this._isHovering) {
                    this._isHovering = true;
                    this._tooltip.setVisible(true);
                } else if (!inside && this._isHovering) {
                    this._isHovering = false;
                    this._tooltip.setVisible(false);
                }

                if (inside) {
                    this._tooltip.setPosition(localPos.x + 15, localPos.y + 15);
                }
            }
        }, this);
    }

    onExit(): void {
        cc.eventManager.removeListener(this._listener);
        super.onExit();
    }
}
```

The tooltip label follows the cursor while hovering. It appears when the mouse enters the sprite bounds and hides when it leaves.

```typescript
class SkyBackground extends cc.Layer {
    private skyGradient: cc.LayerGradient;
    private sunsetGradient: cc.LayerGradient;

    constructor() {
        super();
        this.init();
    }

    init(): boolean {
        // Base sky gradient: light blue to deep blue
        this.skyGradient = new cc.LayerGradient(
            cc.color(135, 206, 250, 255),
            cc.color(25, 25, 112, 255),
            cc.p(0, -1)
        );
        this.addChild(this.skyGradient, 0);

        // Sunset overlay: transparent at top, orange at bottom
        this.sunsetGradient = new cc.LayerGradient(
            cc.color(255, 100, 50, 0),
            cc.color(255, 69, 0, 200),
            cc.p(0, -1)
        );
        this.sunsetGradient.setStartOpacity(0);
        this.sunsetGradient.setEndOpacity(200);
        this.addChild(this.sunsetGradient, 1);

        return true;
    }

    transitionToNight(duration: number): void {
        this.scheduleOnce(() => {
            this.skyGradient.setStartColor(cc.color(10, 10, 40, 255));
            this.skyGradient.setEndColor(cc.color(0, 0, 15, 255));
            this.sunsetGradient.setEndOpacity(0);
        }, duration);
    }
}

const scene = new cc.Scene();
scene.addChild(new SkyBackground());
cc.director.runScene(scene);
```

Two `cc.LayerGradient` layers create depth: a base sky gradient and a sunset overlay with transparency. `setStartOpacity(0)` makes the top transparent so the base gradient shows through. `transitionToNight` demonstrates changing gradient colors at runtime for time-of-day effects.

instruction:
Review this code for potential issues:

```typescript
class GameLayer extends cc.Layer {
    onEnter(): void {
        super.onEnter();
        cc.eventManager.addListener({
            event: cc.EventListener.TOUCH_ONE_BY_ONE,
            onTouchBegan: (touch, event) => true,
            onTouchEnded: (touch, event) => {
                this.handleTap(touch.getLocation());
            }
        }, this);

        cc.eventManager.addCustomListener('game:over', (event) => {
            this.showGameOver();
        });
    }
}
```

output:
Issues found:

1. **Memory leak — listeners never removed.** Neither the touch listener nor the custom listener is removed in `onExit()`. This causes leaked listeners that persist after the layer is destroyed.

2. **No reference stored for custom listener.** `addCustomListener` returns a `cc.EventListener` reference needed for later removal.

3. **Missing `swallowTouches`.** Without `swallowTouches: true`, touches will propagate to nodes behind this layer, which may cause unintended behavior.

Fixed code:
```typescript
class GameLayer extends cc.Layer {
    private _touchListener: cc.EventListener;
    private _customListener: cc.EventListener;

    onEnter(): void {
        super.onEnter();
        this._touchListener = cc.eventManager.addListener({
            event: cc.EventListener.TOUCH_ONE_BY_ONE,
            swallowTouches: true,
            onTouchBegan: (touch, event) => true,
            onTouchEnded: (touch, event) => {
                this.handleTap(touch.getLocation());
            }
        }, this);

        this._customListener = cc.eventManager.addCustomListener('game:over', (event) => {
            this.showGameOver();
        });
    }

    onExit(): void {
        cc.eventManager.removeListener(this._touchListener);
        cc.eventManager.removeListener(this._customListener);
        super.onExit();
    }
}
```

