output:
```typescript
class PreloadScene extends cc.Scene {
    private _progressLabel: cc.LabelTTF;
    private _targetSceneFactory: () => cc.Scene;
    private _resources: string[];
    private static readonly TRANSITION_DELAY = 0.3;

    constructor(resources: string[], targetSceneFactory: () => cc.Scene) {
        super();
        this._resources = resources;
        this._targetSceneFactory = targetSceneFactory;
    }

    onEnter(): void {
        super.onEnter();
        const winSize = cc.director.getWinSize();

        const bg = new cc.LayerColor(cc.color(30, 30, 30));
        this.addChild(bg);

        this._progressLabel = new cc.LabelTTF('0%', 'Arial', 28);
        this._progressLabel.setPosition(winSize.width / 2, winSize.height / 2);
        this.addChild(this._progressLabel);

        this.scheduleOnce(() => this.startLoading(), 0.1);
    }

    private startLoading(): void {
        let loaded = 0;
        const total = this._resources.length;

        if (total === 0) {
            this.onComplete();
            return;
        }

        cc.loader.load(this._resources, (err) => {
            loaded++;
            const pct = Math.round((loaded / total) * 100);
            this._progressLabel.setString(pct + '%');

            if (err) {
                cc.error('Failed to load:', err);
            }

            if (loaded >= total) {
                this.onComplete();
            }
        });
    }

    private onComplete(): void {
        this._progressLabel.setString('100%');
        this.scheduleOnce(() => {
            const scene = this._targetSceneFactory();
            cc.director.runScene(new cc.TransitionFade(0.5, scene));
        }, PreloadScene.TRANSITION_DELAY);
    }
}

// Usage:
const resources = ['res/atlas.png', 'res/data.json', 'res/audio/bgm.mp3'];
const preload = new PreloadScene(resources, () => new GameScene());
cc.director.runScene(preload);
```

