// When loading from editor, widgets have actionTags set by the tool.
// You can find widgets by action tag:
function findWidgetByActionTag(root: ccui.Widget, tag: number): ccui.Widget | null {
    if (root.actionTag === tag) return root;
    const children = root.getChildren();
    for (let i = 0; i < children.length; i++) {
        const child = children[i] as ccui.Widget;
        if (child.actionTag !== undefined) {
            const found = findWidgetByActionTag(child, tag);
            if (found) return found;
        }
    }
    return null;
}

