```typescript
class GameLayer extends cc.Layer {
    private _keyListener: cc.EventListener;

    onEnter(): void {
        super.onEnter();
        this._keyListener = cc.eventManager.addListener({
            event: cc.EventListener.KEYBOARD,
            onKeyPressed: (keyCode: cc.KEY, event: cc.Event): void => {
                if (keyCode === cc.KEY.back) {
                    this.onBackPressed();
                }
            }
        }, this);
    }

    private onBackPressed(): void {
        // Option 1: Pop to previous scene
        cc.director.popScene();

        // Option 2: Show exit confirmation
        // showExitDialog();
    }

    onExit(): void {
        cc.eventManager.removeListener(this._keyListener);
        super.onExit();
    }
}
```

`cc.KEY.back` has value 6. The Android menu key is `cc.KEY.menu` (value 18). These only fire on native Android builds, not in browsers.

```typescript
class TouchDebugOverlay extends cc.Layer {
    private _draw: cc.DrawNode;
    private _touchStart: cc.Point | null = null;
    private _touchCurrent: cc.Point | null = null;
    private _touchStartTime: number = 0;

    onEnter(): void {
        super.onEnter();
        this._draw = new cc.DrawNode();
        this.addChild(this._draw, 1000);
        this.scheduleUpdate();

        cc.eventManager.addListener({
            event: cc.EventListener.TOUCH_ONE_BY_ONE,
            swallowTouches: false,
            onTouchBegan: (touch: cc.Touch): boolean => {
                this._touchStart = touch.getLocation();
                this._touchCurrent = touch.getLocation();
                this._touchStartTime = Date.now();
                return true;
            },
            onTouchMoved: (touch: cc.Touch): void => {
                this._touchCurrent = touch.getLocation();
            },
            onTouchEnded: (): void => {
                this._touchStart = null;
                this._touchCurrent = null;
                this._draw.clear();
            }
        }, this);
    }

    update(dt: number): void {
        if (!this._touchStart || !this._touchCurrent) return;
        this._draw.clear();

        // Touch origin
        this._draw.drawDot(this._touchStart, 6, cc.color(0, 255, 0, 200));

        // Current position
        this._draw.drawDot(this._touchCurrent, 4, cc.color(255, 255, 0, 255));

        // Direction line
        this._draw.drawSegment(
            this._touchStart, this._touchCurrent,
            1, cc.color(255, 255, 255, 150)
        );

        // Velocity arrow (exaggerated)
        const delta = cc.pSub(this._touchCurrent, this._touchStart);
        const elapsed = (Date.now() - this._touchStartTime) / 1000;
        if (elapsed > 0.01) {
            const vel = cc.pMult(delta, 1 / elapsed);
            const velEnd = cc.pAdd(this._touchCurrent, cc.pMult(cc.pNormalize(vel), 30));
            this._draw.drawSegment(
                this._touchCurrent, velEnd,
                2, cc.color(255, 100, 0, 255)
            );
        }

        // Distance circle
        const dist = cc.pDistance(this._touchStart, this._touchCurrent);
        this._draw.drawCircle(
            this._touchStart, dist, 0, 32,
            false, 0.5, cc.color(100, 100, 255, 80)
        );
    }
}
```

