        this._progressBar.setAnchorPoint(0, 0.5);
        this._progressBar.setPosition(winSize.width * 0.2, winSize.height / 2 - 20);
        this._progressBar.setScaleX(0);
        this.addChild(this._progressBar);

        this.startLoading();
    }

    private startLoading(): void {
        const resources = [
            'res/game/atlas.png',
            'res/game/atlas.plist',
            'res/game/level.json',
            'res/audio/bgm.mp3'
        ];

        let loaded = 0;
        const total = resources.length;

        cc.loader.load(resources, (err) => {
            if (err) {
                cc.error('Loading failed:', err);
                this._label.setString('Load failed!');
                return;
            }
            loaded++;
            const progress = loaded / total;
            this._progressBar.setScaleX(progress);
            this._label.setString('Loading... ' + Math.round(progress * 100) + '%');

            if (loaded >= total) {
                this.onLoadComplete();
            }
        });
    }

    private onLoadComplete(): void {
        this._label.setString('Complete!');
        this.scheduleOnce(() => {
            cc.director.runScene(new cc.TransitionFade(0.5, new GameScene()));
        }, 0.5);
    }
}
```

Use `cc.GLProgram` to compile and link custom vertex and fragment shaders:

```typescript
// Vertex shader
const vertSrc = `
    attribute vec4 a_position;
    attribute vec2 a_texCoord;
    varying vec2 v_texCoord;
    void main() {
        gl_Position = CC_PMatrix * CC_MVMatrix * a_position;
        v_texCoord = a_texCoord;
    }
`;

// Fragment shader (grayscale effect)
const fragSrc = `
    precision mediump float;
    varying vec2 v_texCoord;
    uniform sampler2D CC_Texture0;
    void main() {
        vec4 color = texture2D(CC_Texture0, v_texCoord);
        float gray = dot(color.rgb, vec3(0.299, 0.587, 0.114));
        gl_FragColor = vec4(vec3(gray), color.a);
    }
`;

// Create and initialize
const program = new cc.GLProgram();
program.initWithString(vertSrc, fragSrc);
program.addAttribute(cc.ATTRIBUTE_NAME_POSITION, cc.VERTEX_ATTRIB_POSITION);
program.addAttribute(cc.ATTRIBUTE_NAME_TEX_COORD, cc.VERTEX_ATTRIB_TEX_COORDS);
program.link();
program.updateUniforms();

// Apply to a sprite
sprite.setShaderProgram(program);
```

The shader uses Cocos2d-x built-in uniforms `CC_PMatrix` and `CC_MVMatrix` for projection and model-view matrices.

```typescript
class AnimPreviewScene extends cc.Scene {
    private _armature: ccs.Armature;
    private _label: cc.LabelTTF;
    private _animIndex: number = 0;
    private _animCount: number = 0;

    onEnter(): void {
        super.onEnter();

        ccs.armatureDataManager.addArmatureFileInfo('res/hero/hero.ExportJson');
        this._armature = ccs.Armature.create('hero');
        this._armature.setPosition(240, 180);
        this.addChild(this._armature);

        this._animCount = this._armature.animation.getMovementCount();

        this._label = new cc.LabelTTF('', 'Arial', 20);
        this._label.setPosition(240, 30);
        this.addChild(this._label);

        // Play first animation
        this.playCurrentAnim();

        // Cycle on completion
        this._armature.animation.setMovementEventCallFunc((arm, type, id) => {
            if (type === ccs.MovementEventType.COMPLETE ||
                type === ccs.MovementEventType.LOOP_COMPLETE) {
                this.scheduleOnce(() => this.nextAnim(), 1.0);
            }
        });

        // Tap to skip
        cc.eventManager.addListener({
            event: cc.EventListener.TOUCH_ONE_BY_ONE,
            onTouchBegan: (): boolean => {
                this.nextAnim();
                return true;
            }
        }, this);
    }

    private nextAnim(): void {
        this._animIndex = (this._animIndex + 1) % this._animCount;
        this.playCurrentAnim();
    }

    private playCurrentAnim(): void {
        this._armature.animation.playWithIndex(this._animIndex, 5, 0);
        const name = this._armature.animation.getCurrentMovementID();
        this._label.setString(this._animIndex + '/' + this._animCount + ': ' + name);
    }
}
```

Use `getBoundingBox()` which recalculates from all bones each call:

```typescript
const armature = ccs.Armature.create('hero');
armature.setPosition(240, 160);
this.addChild(armature);
armature.animation.play('idle', -1, -1);

// Get bounding box
const box: cc.Rect = armature.getBoundingBox();
cc.log('x:', box.x, 'y:', box.y, 'w:', box.width, 'h:', box.height);

// Use for broad-phase collision detection
function checkCollision(armA: ccs.Armature, armB: ccs.Armature): boolean {
    const boxA = armA.getBoundingBox();
    const boxB = armB.getBoundingBox();
    return cc.rectOverlapsRect(boxA, boxB);
}
```

Note: `getBoundingBox()` recalculates from all bones on every call, so it reflects the current animation pose. This can be expensive if called frequently — cache the result per frame if needed.

