```typescript
class GamePauseHandler {
    private wasMusicPlaying: boolean = false;
    private isPaused: boolean = false;

    pause(): void {
        if (this.isPaused) return;
        this.isPaused = true;

        this.wasMusicPlaying = cc.audioEngine.isMusicPlaying();
        if (this.wasMusicPlaying) {
            cc.audioEngine.pauseMusic();
        }
        cc.audioEngine.pauseAllEffects();
    }

    resume(): void {
        if (!this.isPaused) return;
        this.isPaused = false;

        if (this.wasMusicPlaying) {
            cc.audioEngine.resumeMusic();
        }
        cc.audioEngine.resumeAllEffects();
    }

    getIsPaused(): boolean {
        return this.isPaused;
    }
}

// Usage in a game layer:
class GameLayer extends cc.Layer {
    private pauseHandler: GamePauseHandler;

    init(): boolean {
        this.pauseHandler = new GamePauseHandler();
        cc.audioEngine.playMusic('res/audio/bgm_game.mp3', true);
        return true;
    }

    onPauseButton(): void {
        if (this.pauseHandler.getIsPaused()) {
            this.pauseHandler.resume();
            cc.director.resume();
        } else {
            this.pauseHandler.pause();
            cc.director.pause();
        }
    }
}
```

The handler tracks whether music was playing before pause (to avoid resuming music that wasn't playing). `pauseAllEffects` and `resumeAllEffects` handle all active sound effects in one call. The `isPaused` flag prevents double-pause/resume issues.

```typescript
class BezierPathScene extends cc.Layer {
    onEnter(): void {
        super.onEnter();

        const p0 = cc.p(50, 100);
        const c1 = cc.p(100, 350);
        const c2 = cc.p(350, 50);
        const p3 = cc.p(430, 280);

        // 1. Visualize the path with DrawNode
        const draw = new cc.DrawNode();
        this.addChild(draw);

        // Control points and handles
        draw.drawDot(p0, 4, cc.color(0, 255, 0, 255));
        draw.drawDot(p3, 4, cc.color(255, 0, 0, 255));
        draw.drawDot(c1, 3, cc.color(255, 255, 0, 150));
        draw.drawDot(c2, 3, cc.color(255, 255, 0, 150));
        draw.drawSegment(p0, c1, 0.5, cc.color(255, 255, 255, 80));
        draw.drawSegment(p3, c2, 0.5, cc.color(255, 255, 255, 80));

        // The curve itself
        draw.drawCubicBezier(p0, c1, c2, p3, 50, 2, cc.color(0, 200, 255, 200));

        // 2. Move a sprite along the same bezier
        const sprite = new cc.Sprite('res/hero.png');
        sprite.setPosition(p0);
        this.addChild(sprite);

        const bezierConfig: cc.BezierConfig = [
            c1, c2, p3
        ];
        const moveAction = cc.bezierTo(2.0, bezierConfig);
        const repeatAction = cc.sequence(
            moveAction,
            cc.place(p0),
            cc.delayTime(0.5)
        ).repeatForever();

        sprite.runAction(repeatAction);
    }
}
```

The DrawNode renders the static path preview, while `cc.bezierTo` uses the same control points to animate the sprite. This lets players or designers see the trajectory visually.

`ccs.Armature` and `ccs.ActionTimeline` are two different animation systems in CocosStudio:

**ccs.Armature (Skeletal Animation)**
- Uses bones and skeletal deformation
- Best for character animations (walk, run, attack)
- Animations are named movements (e.g., 'idle', 'run')
- Controlled via `armature.animation.play('name')`
- Supports bone manipulation, frame events, movement events
- Exports as `.ExportJson` files

**ccs.ActionTimeline (Timeline Animation)**
- Uses keyframe-based property animation
- Best for UI animations, scene transitions, simple node animations
- Frame-based control (gotoFrame, play range)
- Controlled via `timeline.gotoFrameAndPlay(frame, loop)`
- Exports as `.csb` files
- Runs as a `cc.Action` on any `cc.Node`

```typescript
// Armature approach (character)
ccs.armatureDataManager.addArmatureFileInfo('res/hero.ExportJson');
const hero = ccs.Armature.create('hero');
hero.animation.play('run', -1, -1);

// Timeline approach (UI)
const timeline = ccs.actionManager.loadAnimationActionWithFile('res/ui/popup.csb');
popupNode.runAction(timeline);
timeline.gotoFrameAndPlay(0, false);
```

Use Armature for game characters, ActionTimeline for UI and simple animations.

