Use a scheduled callback combined with localStorage:

```typescript
class AutoSaveManager {
    private _node: cc.Node;
    private _getData: () => object;
    private _dirty: boolean = false;
    private static readonly SAVE_KEY = 'autosave';
    private static readonly SAVE_INTERVAL = 30; // seconds

    constructor(node: cc.Node, getData: () => object) {
        this._node = node;
        this._getData = getData;
    }

    start(): void {
        // Periodic auto-save
        this._node.schedule(() => {
            if (this._dirty) {
                this.save();
            }
        }, AutoSaveManager.SAVE_INTERVAL);

        cc.log('Auto-save started, interval:', AutoSaveManager.SAVE_INTERVAL, 's');
    }

    markDirty(): void {
        this._dirty = true;
    }

    save(): void {
        const data = this._getData();
        const json = JSON.stringify(data);
        cc.sys.localStorage.setItem(AutoSaveManager.SAVE_KEY, json);
        cc.sys.localStorage.setItem(AutoSaveManager.SAVE_KEY + '_time', Date.now().toString());
        this._dirty = false;
        cc.log('Auto-saved at', new Date().toISOString());
    }

    load<T>(defaultValue: T): T {
        const raw = cc.sys.localStorage.getItem(AutoSaveManager.SAVE_KEY);
        if (!raw) return defaultValue;
        try {
            return JSON.parse(raw) as T;
        } catch (e) {
            cc.error('Corrupt auto-save, using default');
            return defaultValue;
        }
    }

    getLastSaveTime(): number {
        const raw = cc.sys.localStorage.getItem(AutoSaveManager.SAVE_KEY + '_time');
        return raw ? parseInt(raw, 10) : 0;
    }

    stop(): void {
        this._node.unscheduleAllCallbacks();
        if (this._dirty) this.save(); // final save
    }
}
```

`compressedInterpolation` controls how the gradient color is interpolated when start and end opacities differ:

```typescript
const grad = new cc.LayerGradient(
    cc.color(255, 0, 0, 255),   // fully opaque red
    cc.color(0, 0, 255, 50)     // nearly transparent blue
);

// Check current state
const isCompressed: boolean = grad.isCompressedInterpolation();

// Enable compressed interpolation
grad.setCompressedInterpolation(true);

// Disable it
grad.setCompressedInterpolation(false);
```

When **enabled** (default is typically `true`), the color interpolation is adjusted to account for differing opacities, producing a more visually uniform gradient. The colors are compressed so that the visible gradient transition appears smoother.

When **disabled**, the raw color values are linearly interpolated without opacity compensation, which can cause the less-opaque end to appear to "blend" with whatever is behind the layer in a less predictable way.

For most use cases, leave compressed interpolation enabled. Only disable it if you need raw linear color interpolation for a specific visual effect.

