Track touch offset and move the node accordingly:

```typescript
function makeDraggable(node: cc.Node): void {
    let dragOffset = cc.p(0, 0);

    const listener = cc.EventListener.create({
        event: cc.EventListener.TOUCH_ONE_BY_ONE,
        swallowTouches: true,
        onTouchBegan: (touch: cc.Touch, event: cc.Event): boolean => {
            const localPt = node.convertTouchToNodeSpace(touch);
            const rect = cc.rect(0, 0, node.width, node.height);
            if (cc.rectContainsPoint(rect, localPt)) {
                const worldPt = touch.getLocation();
                dragOffset = cc.p(node.x - worldPt.x, node.y - worldPt.y);
                return true;
            }
            return false;
        },
        onTouchMoved: (touch: cc.Touch, event: cc.Event): void => {
            const worldPt = touch.getLocation();
            node.setPosition(worldPt.x + dragOffset.x, worldPt.y + dragOffset.y);
        },
        onTouchEnded: (touch: cc.Touch, event: cc.Event): void => {
            cc.log('Dropped at: ' + node.x + ', ' + node.y);
        }
    });

    cc.eventManager.addListener(listener, node);
}

const card = new cc.Sprite('card.png');
card.setPosition(240, 160);
this.addChild(card);
makeDraggable(card);
```

