Complete the code for a safe localStorage wrapper with default values and type conversion:

```typescript
class Storage {
    // TODO: implement getInt, getFloat, getBool, getString with defaults
    // TODO: implement setInt, setFloat, setBool, setString
}
```

output:
```typescript
class Storage {
    static getString(key: string, defaultValue: string = ''): string {
        const raw = cc.sys.localStorage.getItem(key);
        return raw !== null && raw !== undefined ? raw : defaultValue;
    }

    static setString(key: string, value: string): void {
        cc.sys.localStorage.setItem(key, value);
    }

    static getInt(key: string, defaultValue: number = 0): number {
        const raw = cc.sys.localStorage.getItem(key);
        if (!raw) return defaultValue;
        const parsed = parseInt(raw, 10);
        return isNaN(parsed) ? defaultValue : parsed;
    }

    static setInt(key: string, value: number): void {
        cc.sys.localStorage.setItem(key, Math.floor(value).toString());
    }

    static getFloat(key: string, defaultValue: number = 0.0): number {
        const raw = cc.sys.localStorage.getItem(key);
        if (!raw) return defaultValue;
        const parsed = parseFloat(raw);
        return isNaN(parsed) ? defaultValue : parsed;
    }

    static setFloat(key: string, value: number): void {
        cc.sys.localStorage.setItem(key, value.toString());
    }

    static getBool(key: string, defaultValue: boolean = false): boolean {
        const raw = cc.sys.localStorage.getItem(key);
        if (!raw) return defaultValue;
        return raw === 'true';
    }

    static setBool(key: string, value: boolean): void {
        cc.sys.localStorage.setItem(key, value ? 'true' : 'false');
    }

    static getJSON<T>(key: string, defaultValue: T): T {
        const raw = cc.sys.localStorage.getItem(key);
        if (!raw) return defaultValue;
        try {
            return JSON.parse(raw) as T;
        } catch (e) {
            cc.warn('Failed to parse JSON for key:', key);
            return defaultValue;
        }
    }

    static setJSON(key: string, value: object): void {
        cc.sys.localStorage.setItem(key, JSON.stringify(value));
    }

    static remove(key: string): void {
        cc.sys.localStorage.removeItem(key);
    }
}

// Usage:
Storage.setInt('level', 5);
const level = Storage.getInt('level', 1); // 5

Storage.setBool('musicOn', false);
const music = Storage.getBool('musicOn', true); // false
```

The type signature is:

```typescript
cc.EventListener.create(option: EventListenerCreateParam): cc.EventListener
```

Where `EventListenerCreateParam` is a union of listener configuration objects depending on the `event` field:

```typescript
// Touch one-by-one
{
    event: cc.EventListener.TOUCH_ONE_BY_ONE,
    swallowTouches?: boolean,
    onTouchBegan: (touch: cc.Touch, event: cc.Event) => boolean,
    onTouchMoved?: (touch: cc.Touch, event: cc.EventTouch) => void,
    onTouchEnded?: (touch: cc.Touch, event: cc.Event) => void,
    onTouchCancelled?: (touch: cc.Touch, event: cc.Event) => void
}

// Touch all at once
{
    event: cc.EventListener.TOUCH_ALL_AT_ONCE,
    onTouchesBegan?: (touches: cc.Touch[], event: cc.Event) => void,
    onTouchesMoved?: (touches: cc.Touch[], event: cc.Event) => void,
    onTouchesEnded?: (touches: cc.Touch[], event: cc.Event) => void,
    onTouchesCancelled?: (touches: cc.Touch[], event: cc.Event) => void
}

// Keyboard
{
    event: cc.EventListener.KEYBOARD,
    onKeyPressed?: (keyCode: cc.KEY, event: cc.Event) => void,
