```typescript
class AnimationPreviewer {
    private skel: sp.SkeletonAnimation;
    private animations: string[] = ['idle', 'walk', 'run', 'attack', 'jump', 'death'];
    private currentIndex: number = 0;

    constructor(skel: sp.SkeletonAnimation) {
        this.skel = skel;

        // Setup smooth blending between all pairs
        for (let i = 0; i < this.animations.length; i++) {
            const next = (i + 1) % this.animations.length;
            this.skel.setMix(this.animations[i], this.animations[next], 0.2);
        }

        // Listen for completion to advance
        this.skel.setAnimationListener(this, (
            track: spine.TrackEntry,
            type: number,
            event: spine.Event
        ) => {
            if (type === sp.AnimationEventType.COMPLETE) {
                this.advanceToNext();
            }
        });

        // Start first animation (play each once to preview)
        this.playCurrentAnimation();
    }

    private playCurrentAnimation(): void {
        const name = this.animations[this.currentIndex];
        this.skel.setAnimation(0, name, false);
        cc.log('Previewing: ' + name);
    }

    private advanceToNext(): void {
        this.currentIndex = (this.currentIndex + 1) % this.animations.length;
        this.playCurrentAnimation();
    }
}
```

The constructor sets up mix transitions between consecutive animations, registers a COMPLETE listener that advances to the next animation, and starts the first one. Each animation plays once (non-looping) so the COMPLETE event fires exactly once per animation.

