output:
```typescript
function createSpriteAsync(
    texturePath: string,
    parent: cc.Node,
    position: cc.Point,
    callback: (sprite: cc.Sprite) => void
): void {
    cc.textureCache.addImage(texturePath);
    const tex = cc.textureCache.getTextureForKey(texturePath);

    const sprite = new cc.Sprite(tex);
    sprite.setPosition(position);
    parent.addChild(sprite);

    if (sprite.textureLoaded()) {
        callback(sprite);
    } else {
        // If async loading, poll or use event
        sprite.addEventListener('load', () => {
            callback(sprite);
        });
    }
}

// Usage:
createSpriteAsync('res/hero.png', this, cc.p(240, 160), (sprite) => {
    cc.log('Sprite ready, size:', sprite.getContentSize().width, 'x', sprite.getContentSize().height);
    sprite.runAction(cc.fadeIn(0.5));
});
```

Note: In most Cocos2d-x JS setups, texture loading is synchronous and `textureLoaded()` returns true immediately. The async path is a safety net for edge cases.

