instruction:
Review this code for memory management issues:

```typescript
class GameScene extends cc.Scene {
    onEnter(): void {
        super.onEnter();
        cc.spriteFrameCache.addSpriteFrames('res/level1.plist', 'res/level1.png');
        cc.spriteFrameCache.addSpriteFrames('res/level2.plist', 'res/level2.png');
        cc.spriteFrameCache.addSpriteFrames('res/level3.plist', 'res/level3.png');
        // ... create sprites for current level only
    }
}
```

output:
Issues:

1. **Loading all level atlases upfront**: All three atlases are loaded into memory even though only one level is active. This wastes texture memory.

2. **No cleanup on exit**: When transitioning to another scene, the loaded sprite frames and textures remain in memory.

Improved version:
```typescript
class GameScene extends cc.Scene {
    private _currentLevel: number;

    constructor(level: number) {
        super();
        this._currentLevel = level;
    }

    onEnter(): void {
        super.onEnter();
        // Only load the current level's atlas
        const lvl = this._currentLevel;
        cc.spriteFrameCache.addSpriteFrames('res/level' + lvl + '.plist', 'res/level' + lvl + '.png');
        // ... create sprites
    }

    onExit(): void {
        // Clean up when leaving the scene
        const lvl = this._currentLevel;
        cc.spriteFrameCache.removeSpriteFramesFromFile('res/level' + lvl + '.plist');
        cc.textureCache.removeTextureForKey('res/level' + lvl + '.png');
        super.onExit();
    }
}
```

Alternatively, use `cc.spriteFrameCache.removeUnusedSpriteFrames()` and `cc.textureCache.removeUnusedTextures()` for a broader cleanup.

instruction:
Review this code:

```typescript
const sv = new ccui.ScrollView();
sv.setSize(cc.size(300, 400));
sv.setInnerContainerSize(cc.size(300, 1200));
sv.setDirection(ccui.ScrollView.DIR_VERTICAL);
sv.setInertiaScrollEnabled(false);
sv.setBounceEnabled(true);
sv.scrollToBottom(0, true);
this.addChild(sv);
```

output:
**Issues:**

1. **scrollToBottom with duration 0** - Passing `0` for the time parameter makes this effectively a jump, but `jumpToBottom()` is more appropriate and clearer.
2. **Bounce without inertia** - `setBounceEnabled(true)` with `setInertiaScrollEnabled(false)` is an unusual combination. Bounce typically works with inertia; without it, the bounce effect is less noticeable since the scroll stops immediately when the finger lifts.
3. **scrollToBottom before addChild** - Scrolling before the widget is on stage may not work reliably.

**Fix:**

```typescript
const sv = new ccui.ScrollView();
sv.setSize(cc.size(300, 400));
sv.setInnerContainerSize(cc.size(300, 1200));
sv.setDirection(ccui.ScrollView.DIR_VERTICAL);
sv.setInertiaScrollEnabled(true);
sv.setBounceEnabled(true);
this.addChild(sv);
sv.jumpToBottom(); // after adding to scene
```

```typescript
class SelectableUnit extends cc.Node {
    private _sprite: cc.Sprite;
    private _selectionDraw: cc.DrawNode;
    private _selected: boolean = false;

    constructor(frameName: string) {
        super();
        this._sprite = new cc.Sprite(
            cc.spriteFrameCache.getSpriteFrame(frameName)
        );
        this.addChild(this._sprite);

        this._selectionDraw = new cc.DrawNode();
        this.addChild(this._selectionDraw, -1);
    }

    setSelected(selected: boolean): void {
        this._selected = selected;
        this._selectionDraw.clear();

        if (!selected) return;

        const size = this._sprite.getContentSize();
        const hw = size.width / 2 + 4;
        const hh = size.height / 2 + 4;

        // Draw selection ring
        this._selectionDraw.drawCircle(
            cc.p(0, 0), Math.max(hw, hh),
            0, 32, false, 2,
            cc.color(0, 255, 0, 200)
        );

        // Draw corner brackets
        const col = cc.color(0, 255, 0, 255);
        const len = 8;
        // Top-left
        this._selectionDraw.drawSegment(cc.p(-hw, hh), cc.p(-hw + len, hh), 1, col);
        this._selectionDraw.drawSegment(cc.p(-hw, hh), cc.p(-hw, hh - len), 1, col);
        // Top-right
        this._selectionDraw.drawSegment(cc.p(hw, hh), cc.p(hw - len, hh), 1, col);
        this._selectionDraw.drawSegment(cc.p(hw, hh), cc.p(hw, hh - len), 1, col);
        // Bottom-left
        this._selectionDraw.drawSegment(cc.p(-hw, -hh), cc.p(-hw + len, -hh), 1, col);
        this._selectionDraw.drawSegment(cc.p(-hw, -hh), cc.p(-hw, -hh + len), 1, col);
        // Bottom-right
        this._selectionDraw.drawSegment(cc.p(hw, -hh), cc.p(hw - len, -hh), 1, col);
        this._selectionDraw.drawSegment(cc.p(hw, -hh), cc.p(hw, -hh + len), 1, col);
    }
}

// Usage:
const unit = new SelectableUnit('soldier_idle.png');
unit.setPosition(240, 160);
this.addChild(unit);
unit.setSelected(true);
```

`cc.assert` logs an error if the condition is falsy:

```typescript
cc.assert(...args: any[]): void
```

Examples:
```typescript
// Basic assertion
cc.assert(health >= 0, 'Health cannot be negative');

// Validate function parameters
function setSpeed(speed: number): void {
    cc.assert(cc.isNumber(speed), 'Speed must be a number');
    cc.assert(speed >= 0, 'Speed must be non-negative');
    this._speed = speed;
}

// Validate object state
class Player {
    private _sprite: cc.Sprite | null = null;

    init(spritePath: string): void {
        this._sprite = new cc.Sprite(spritePath);
        cc.assert(cc.sys.isObjectValid(this._sprite), 'Failed to create player sprite');
    }

    attack(): void {
        cc.assert(this._sprite !== null, 'Player not initialized');
        // proceed with attack...
    }
}

// Validate configuration
function loadConfig(config: any): void {
    cc.assert(cc.isObject(config), 'Config must be an object');
    cc.assert(cc.isNumber(config.width), 'Config.width must be a number');
    cc.assert(cc.isNumber(config.height), 'Config.height must be a number');
}
```

Unlike `console.assert`, `cc.assert` uses the engine's error logging system and works consistently across native and H5 platforms.

Attach behavior objects to nodes via userData:

```typescript
interface HealthComponent {
    hp: number;
    maxHp: number;
    takeDamage(amount: number): void;
    heal(amount: number): void;
    isDead(): boolean;
}

function addHealthComponent(node: cc.Node, maxHp: number): HealthComponent {
    const comp: HealthComponent = {
        hp: maxHp,
        maxHp: maxHp,
        takeDamage(amount: number): void {
            this.hp = Math.max(0, this.hp - amount);
            if (this.isDead()) {
                node.runAction(cc.sequence(
                    cc.fadeOut(0.3),
                    cc.removeSelf()
                ));
            }
        },
        heal(amount: number): void {
            this.hp = Math.min(this.maxHp, this.hp + amount);
        },
        isDead(): boolean {
            return this.hp <= 0;
        }
    };
    node.setUserData(comp);
    return comp;
}

// Usage:
const enemy = new cc.Sprite('enemy.png');
const health = addHealthComponent(enemy, 100);
health.takeDamage(30);
cc.log('HP: ' + health.hp); // 70
```

Track the start position and only begin dragging after a minimum movement threshold:

```typescript
class DragWithThreshold extends cc.Sprite {
    private _listener: cc.EventListener;
    private _isDragging: boolean = false;
    private static readonly DRAG_THRESHOLD = 8; // pixels

    onEnter(): void {
        super.onEnter();
        this._listener = cc.eventManager.addListener({
            event: cc.EventListener.TOUCH_ONE_BY_ONE,
            swallowTouches: true,
            onTouchBegan: (touch: cc.Touch, event: cc.Event): boolean => {
                const local = this.convertToNodeSpace(touch.getLocation());
                const size = this.getContentSize();
                if (!cc.rectContainsPoint(cc.rect(0, 0, size.width, size.height), local)) {
                    return false;
                }
                this._isDragging = false;
                return true;
            },
            onTouchMoved: (touch: cc.Touch, event: cc.EventTouch): void => {
                if (!this._isDragging) {
                    const start = touch.getStartLocation();
                    const current = touch.getLocation();
                    const dist = cc.pDistance(start, current);
                    if (dist < DragWithThreshold.DRAG_THRESHOLD) {
                        return; // below threshold, ignore
                    }
                    this._isDragging = true;
                    cc.log('Drag started');
                }
                // Now in drag mode
                const delta = touch.getDelta();
                this.x += delta.x;
                this.y += delta.y;
            },
            onTouchEnded: (touch: cc.Touch, event: cc.Event): void => {
                if (!this._isDragging) {
                    cc.log('Tap detected (no drag)');
                } else {
                    cc.log('Drag ended');
                }
                this._isDragging = false;
            }
        }, this);
    }

    onExit(): void {
        cc.eventManager.removeListener(this._listener);
        super.onExit();
    }
}
```

The threshold of 8 pixels distinguishes intentional drags from accidental finger wobble during taps.

