Complete this code to implement a re-usable armature pool for performance:

```typescript
class ArmaturePool {
    private _pool: ccs.Armature[] = [];
    private _armatureName: string;
    // TODO: implement get, release, and preload
}
```

output:
```typescript
class ArmaturePool {
    private _pool: ccs.Armature[] = [];
    private _armatureName: string;
    private _active: Set<ccs.Armature> = new Set();

    constructor(armatureName: string, exportJson: string) {
        this._armatureName = armatureName;
        ccs.armatureDataManager.addArmatureFileInfo(exportJson);
    }

    preload(count: number): void {
        for (let i = 0; i < count; i++) {
            const arm = ccs.Armature.create(this._armatureName);
            arm.setVisible(false);
            this._pool.push(arm);
        }
    }

    get(): ccs.Armature {
        let arm: ccs.Armature;
        if (this._pool.length > 0) {
            arm = this._pool.pop()!;
        } else {
            arm = ccs.Armature.create(this._armatureName);
        }
        arm.setVisible(true);
        arm.animation.stop();
        arm.animation.setSpeedScale(1.0);
        this._active.add(arm);
        return arm;
    }

    release(arm: ccs.Armature): void {
        if (!this._active.has(arm)) return;
        this._active.delete(arm);
        arm.animation.stop();
        arm.setVisible(false);
        arm.removeFromParent(false);
        this._pool.push(arm);
    }

    releaseAll(): void {
        for (const arm of this._active) {
            arm.animation.stop();
            arm.setVisible(false);
            arm.removeFromParent(false);
            this._pool.push(arm);
        }
        this._active.clear();
    }

    getActiveCount(): number {
        return this._active.size;
    }

    getPoolSize(): number {
        return this._pool.length;
    }
}

// Usage:
const pool = new ArmaturePool('bullet_fx', 'res/fx/bullet.ExportJson');
pool.preload(20);

// Spawn
const fx = pool.get();
fx.setPosition(100, 200);
this.addChild(fx);
fx.animation.play('explode', -1, 0);
fx.animation.setMovementEventCallFunc((arm, type) => {
    if (type === ccs.MovementEventType.COMPLETE) {
        pool.release(arm);
    }
});
```

