output:
```typescript
class HealthBar {
    private container: cc.Node;
    private bg: cc.LayerColor;
    private fill: cc.LayerColor;
    private maxWidth: number;

    constructor(width: number, height: number) {
        this.maxWidth = width;
        this.container = new cc.Node();

        this.bg = new cc.LayerColor(
            cc.color(50, 50, 50, 255), width, height
        );
        this.container.addChild(this.bg, 0);

        this.fill = new cc.LayerColor(
            cc.color(0, 200, 0, 255), width, height
        );
        this.container.addChild(this.fill, 1);
    }

    getNode(): cc.Node {
        return this.container;
    }

    setPercent(percent: number): void {
        const clamped = Math.max(0, Math.min(100, percent));
        const fillWidth = (clamped / 100) * this.maxWidth;
        this.fill.changeWidth(fillWidth);

        if (clamped > 50) {
            this.fill = this.updateFillColor(0, 200, 0);
        } else if (clamped > 25) {
            this.fill = this.updateFillColor(255, 165, 0);
        } else {
            this.fill = this.updateFillColor(255, 0, 0);
        }
    }

    private updateFillColor(r: number, g: number, b: number): cc.LayerColor {
        this.fill.setColor(cc.color(r, g, b));
        return this.fill;
    }
}

// Usage:
const hpBar = new HealthBar(200, 20);
hpBar.getNode().setPosition(100, 300);
