instruction:
Fix the bug. The cleanup method crashes because super.cleanup is called at the wrong time:

```typescript
class GameNode extends cc.Node {
    cleanup() {
        super.cleanup();
        this.customResource.release();
    }
}
```

output:
The bug is calling `super.cleanup()` before releasing custom resources. `super.cleanup()` stops all actions and scheduled callbacks, which is fine. However, if `this.customResource` was set up in a callback that cleanup removes, it might be null.

Actually, the bigger concern is order-of-operations. Call super last:

**Fix:**

```typescript
class GameNode extends cc.Node {
    cleanup() {
        // Release custom resources first
        if (this.customResource) {
            this.customResource.release();
            this.customResource = null;
        }
        // Then let parent clean up actions/schedulers
        super.cleanup();
    }
}
```

In lifecycle callbacks, call super first in `onEnter` (setup) and super last in `onExit`/`cleanup` (teardown).

```typescript
function drawLineChart(
    draw: cc.DrawNode,
    origin: cc.Point,
    width: number,
    height: number,
    data: number[]
): void {
    if (data.length < 2) return;
    draw.clear();

    const axisColor = cc.color(200, 200, 200, 255);
    const lineColor = cc.color(0, 200, 255, 255);
    const dotColor = cc.color(255, 255, 0, 255);
    const gridColor = cc.color(80, 80, 80, 100);

    // Draw axes
    draw.drawSegment(origin, cc.p(origin.x, origin.y + height), 1, axisColor);
    draw.drawSegment(origin, cc.p(origin.x + width, origin.y), 1, axisColor);

    // Horizontal grid lines
    const gridLines = 4;
    for (let i = 1; i <= gridLines; i++) {
        const y = origin.y + (height / gridLines) * i;
        draw.drawSegment(
            cc.p(origin.x, y),
            cc.p(origin.x + width, y),
            0.5, gridColor
        );
    }

    // Normalize and plot data
    const maxVal = Math.max(...data);
    const minVal = Math.min(...data);
    const range = maxVal - minVal || 1;
    const stepX = width / (data.length - 1);

    const points: cc.Point[] = data.map((val, i) => {
        const nx = origin.x + i * stepX;
        const ny = origin.y + ((val - minVal) / range) * height;
        return cc.p(nx, ny);
    });

    // Draw line segments
    for (let i = 0; i < points.length - 1; i++) {
        draw.drawSegment(points[i], points[i + 1], 1.5, lineColor);
    }

    // Draw data dots
    draw.drawDots(points, 3, dotColor);
}

// Usage:
const draw = new cc.DrawNode();
this.addChild(draw);
const data = [10, 25, 15, 40, 30, 55, 45, 60];
drawLineChart(draw, cc.p(50, 50), 380, 220, data);
```

