`cc.sys.restartVM()` restarts the JavaScript virtual machine on native (JSB) platforms:

```typescript
cc.sys.restartVM(): void  // JSB only, no-op on H5
```

This completely resets the JS runtime, re-executing all scripts from scratch. Use cases:

```typescript
// Hot reload during development
function devReload(): void {
    if (cc.sys.isNative) {
        cc.log('Restarting VM for hot reload...');
        cc.sys.restartVM();
    } else {
        // On web, just reload the page
        window.location.reload();
    }
}

// Recovery from unrecoverable error
function handleFatalError(error: Error): void {
    cc.error('Fatal error:', error.message);
    // Save state first
    cc.sys.localStorage.setItem('crash_recovery', 'true');
    if (cc.sys.isNative) {
        cc.sys.restartVM();
    }
}

// Language change that requires full restart
function changeLanguage(lang: string): void {
    cc.sys.localStorage.setItem('language', lang);
    if (cc.sys.isNative) {
        cc.sys.restartVM(); // restart to reload all assets in new language
    }
}
```

**Warning:** This destroys ALL JavaScript state — all variables, objects, listeners, and timers are lost. Only use as a last resort. Always save critical state to localStorage before calling.

```typescript
interface AABB {
    readonly center: cc.Point;
    readonly halfSize: cc.Size;
}

function nodeToAABB(node: cc.Node): AABB {
    const box = node.getBoundingBox();
    return {
        center: cc.p(box.x + box.width / 2, box.y + box.height / 2),
        halfSize: cc.size(box.width / 2, box.height / 2)
    };
}

function aabbToRect(aabb: AABB): cc.Rect {
    return cc.rect(
        aabb.center.x - aabb.halfSize.width,
        aabb.center.y - aabb.halfSize.height,
        aabb.halfSize.width * 2,
        aabb.halfSize.height * 2
    );
}

function aabbOverlaps(a: AABB, b: AABB): boolean {
    return cc.rectOverlapsRect(aabbToRect(a), aabbToRect(b));
}

function aabbSeparation(a: AABB, b: AABB): cc.Point {
    const diff = cc.pSub(a.center, b.center);
    const overlapX = a.halfSize.width + b.halfSize.width - Math.abs(diff.x);
    const overlapY = a.halfSize.height + b.halfSize.height - Math.abs(diff.y);

    if (overlapX <= 0 || overlapY <= 0) return cc.p(0, 0);

    if (overlapX < overlapY) {
        return cc.p(diff.x > 0 ? overlapX : -overlapX, 0);
    }
    return cc.p(0, diff.y > 0 ? overlapY : -overlapY);
}

// Usage:
const playerAABB = nodeToAABB(playerSprite);
const wallAABB = nodeToAABB(wallSprite);

if (aabbOverlaps(playerAABB, wallAABB)) {
    const sep = aabbSeparation(playerAABB, wallAABB);
    const pos = playerSprite.getPosition();
    playerSprite.setPosition(cc.pAdd(pos, sep));
}
```

