Complete the code for a scene navigation history with back and forward support:

```typescript
class SceneHistory {
    // TODO: navigateTo, goBack, goForward
}
```

output:
```typescript
interface SceneEntry {
    name: string;
    factory: () => cc.Scene;
}

class SceneHistory {
    private static _history: SceneEntry[] = [];
    private static _index: number = -1;
    private static readonly FADE_TIME = 0.4;

    static navigateTo(name: string, factory: () => cc.Scene): void {
        // Trim forward history when navigating from middle
        if (SceneHistory._index < SceneHistory._history.length - 1) {
            SceneHistory._history = SceneHistory._history.slice(
                0, SceneHistory._index + 1
            );
        }
        SceneHistory._history.push({ name, factory });
        SceneHistory._index = SceneHistory._history.length - 1;
        cc.director.runScene(
            new cc.TransitionFade(SceneHistory.FADE_TIME, factory())
        );
        cc.log('Navigate to:', name);
    }

    static goBack(): boolean {
        if (SceneHistory._index <= 0) {
            cc.warn('No previous scene');
            return false;
        }
        SceneHistory._index--;
        const entry = SceneHistory._history[SceneHistory._index];
        cc.director.runScene(
            new cc.TransitionFade(SceneHistory.FADE_TIME, entry.factory())
        );
        cc.log('Back to:', entry.name);
        return true;
    }

    static goForward(): boolean {
        if (SceneHistory._index >= SceneHistory._history.length - 1) {
            cc.warn('No forward scene');
            return false;
        }
        SceneHistory._index++;
        const entry = SceneHistory._history[SceneHistory._index];
        cc.director.runScene(
            new cc.TransitionFade(SceneHistory.FADE_TIME, entry.factory())
        );
        return true;
    }

    static get currentName(): string {
        return SceneHistory._index >= 0
            ? SceneHistory._history[SceneHistory._index].name
            : 'none';
    }

    static get canGoBack(): boolean {
        return SceneHistory._index > 0;
    }

    static get canGoForward(): boolean {
        return SceneHistory._index < SceneHistory._history.length - 1;
    }
}

// Usage:
SceneHistory.navigateTo('menu', () => new MenuScene());
SceneHistory.navigateTo('game', () => new GameScene());
SceneHistory.goBack(); // returns to menu
```

Create an animated label that rises and fades:

```typescript
function showDamage(parent: cc.Node, damage: number, pos: cc.Point, isCrit: boolean): void {
    const fontSize = isCrit ? 32 : 20;
    const text = isCrit ? damage + '!' : String(damage);

    const label = cc.Label.createWithSystemFont(text, 'Impact', fontSize);
    label.setTextColor(isCrit ? cc.color(255, 50, 50) : cc.color(255, 255, 255));
    label.enableOutline(cc.color(0, 0, 0, 255), isCrit ? 3 : 1);
    label.setPosition(pos.x + (Math.random() - 0.5) * 20, pos.y);
    parent.addChild(label, 999);

    const rise = cc.moveBy(0.8, cc.p(0, 60 + Math.random() * 20));
    const fade = cc.sequence(cc.delayTime(0.4), cc.fadeOut(0.4));

    label.runAction(cc.sequence(
        cc.spawn(rise.easing(cc.easeOut(2)), fade),
        cc.removeSelf()
    ));

    if (isCrit) {
        label.setScale(0);
        label.runAction(cc.sequence(
            cc.scaleTo(0.15, 1.3).easing(cc.easeBackOut()),
            cc.scaleTo(0.1, 1.0)
        ));
    }
}
```

