class DialogBox extends cc.Layer {
    private dimmer: cc.LayerColor;
    private panel: cc.LayerColor;
    private messageLabel: cc.LabelTTF;

    constructor(message: string) {
        super();
        this.initDialog(message);
    }

    private initDialog(message: string): void {
        const winSize = cc.director.getWinSize();

        // Semi-transparent dimmer
        this.dimmer = new cc.LayerColor(cc.color(0, 0, 0, 150));
        this.dimmer.setContentSize(winSize);
        this.addChild(this.dimmer, 0);

        // White panel centered
        const panelW = 300;
        const panelH = 180;
        this.panel = new cc.LayerColor(
            cc.color(240, 240, 240, 255), panelW, panelH
        );
        this.panel.setPosition(
            (winSize.width - panelW) / 2,
            (winSize.height - panelH) / 2
        );
        this.addChild(this.panel, 1);

        // Message text
        this.messageLabel = new cc.LabelTTF(message, 'Arial', 20);
        this.messageLabel.setColor(cc.color(0, 0, 0));
        this.messageLabel.setPosition(panelW / 2, panelH / 2 + 20);
        this.panel.addChild(this.messageLabel);
    }

    show(parent: cc.Node): void {
        this.setOpacity(0);
        parent.addChild(this, 100);
        this.runAction(cc.fadeTo(0.3, 255));
    }

    dismiss(): void {
        this.runAction(
            cc.sequence(
                cc.fadeTo(0.2, 0),
                cc.callFunc(() => this.removeFromParent(true))
            )
        );
    }
}

// Usage:
const dialog = new DialogBox('Game Over! Try again?');
dialog.show(this);
// Later:
dialog.dismiss();
```

The dimmer `cc.LayerColor` covers the full screen with 150/255 alpha. The white panel is a smaller `cc.LayerColor` centered on screen. `show()` fades in the entire dialog, and `dismiss()` fades out then removes it from the parent.

instruction:
Find and fix the bug in this LayerMultiplex code:

```typescript
const layer1 = new cc.Layer();
const layer2 = new cc.Layer();
const multiplex = new cc.LayerMultiplex(layer1, layer2);
scene.addChild(multiplex);

multiplex.switchToAndReleaseMe(1);
// Later...
multiplex.switchTo(0);  // crashes!
```

output:
The bug is using `switchToAndReleaseMe(1)` which releases layer at index 0 (`layer1`). When you later call `switchTo(0)`, it tries to show the released `layer1`, which causes a crash.

**Fixed code:**
```typescript
const layer1 = new cc.Layer();
const layer2 = new cc.Layer();
const multiplex = new cc.LayerMultiplex(layer1, layer2);
scene.addChild(multiplex);

// Use switchTo instead of switchToAndReleaseMe if you need to go back
multiplex.switchTo(1);
// Later...
multiplex.switchTo(0);  // works fine, layer1 was preserved
```

`switchToAndReleaseMe(n)` releases the CURRENT layer and switches to `n`. Only use it when you're certain the current layer won't be needed again. If you need to switch between layers repeatedly, always use `switchTo(n)` which preserves all layers in memory.

