```typescript
class PauseManager {
    private static _isPaused: boolean = false;

    static toggle(): void {
        if (PauseManager._isPaused) {
            cc.director.resume();
        } else {
            cc.director.pause();
        }
        PauseManager._isPaused = !PauseManager._isPaused;
    }

    static get isPaused(): boolean {
        return cc.director.isPaused();
    }
}
```

