```typescript
class SpriteButton extends cc.Node {
    private _sprite: cc.Sprite;
    private _normalFrame: string;
    private _pressedFrame: string;
    private _callback: () => void;

    constructor(normalFrame: string, pressedFrame: string, callback: () => void) {
        super();
        this._normalFrame = normalFrame;
        this._pressedFrame = pressedFrame;
        this._callback = callback;

        this._sprite = new cc.Sprite(cc.spriteFrameCache.getSpriteFrame(normalFrame));
        this.addChild(this._sprite);

        this.registerTouch();
    }

    private registerTouch(): void {
        cc.eventManager.addListener({
            event: cc.EventListener.TOUCH_ONE_BY_ONE,
            onTouchBegan: (touch: cc.Touch): boolean => {
                const loc = touch.getLocation();
                const box = this._sprite.getBoundingBoxToWorld();
                if (cc.rectContainsPoint(box, loc)) {
                    this._sprite.setSpriteFrame(this._pressedFrame);
                    this._sprite.setScale(0.95);
                    return true;
                }
                return false;
            },
            onTouchEnded: (touch: cc.Touch): void => {
                this._sprite.setSpriteFrame(this._normalFrame);
                this._sprite.setScale(1.0);
                const loc = touch.getLocation();
                const box = this._sprite.getBoundingBoxToWorld();
                if (cc.rectContainsPoint(box, loc)) {
                    this._callback();
                }
            },
            onTouchCancelled: (): void => {
                this._sprite.setSpriteFrame(this._normalFrame);
                this._sprite.setScale(1.0);
            }
        }, this);
    }
}

// Usage:
cc.spriteFrameCache.addSpriteFrames('res/ui.plist', 'res/ui.png');
