output:
The bug is manually setting positions on children in a linear layout. In LINEAR_VERTICAL mode, the layout engine manages positions automatically. Manually setting positions conflicts with the layout.

**Fix:** Remove `setPosition` and use LayoutParameters instead:

```typescript
const layout = new ccui.Layout();
layout.setSize(cc.size(300, 400));
layout.setLayoutType(ccui.Layout.LINEAR_VERTICAL);
for (let i = 0; i < 5; i++) {
    const text = new ccui.Text('Line ' + i, 'Arial', 18);
    const param = new ccui.LinearLayoutParameter();
    param.setGravity(ccui.LinearLayoutParameter.CENTER_HORIZONTAL);
    param.setMargin(new ccui.Margin(0, 10, 0, 0));
    text.setLayoutParameter(param);
    layout.addChild(text);
}
layout.forceDoLayout();
this.addChild(layout);
```

Chain complex action patterns:

```typescript
function bossAttackSequence(boss: cc.Sprite, target: cc.Point): void {
    const startPos = boss.getPosition();

    boss.runAction(cc.sequence(
        // Charge up - glow and grow
        cc.spawn(
            cc.scaleTo(0.5, 1.3).easing(cc.easeSineIn()),
            cc.tintTo(0.5, 255, 100, 100)
        ),
        // Dash at target
        cc.moveTo(0.2, target).easing(cc.easeIn(3)),
        // Impact - shake
        cc.callFunc(() => shakeScreen(boss.getParent())),
        cc.spawn(
            cc.scaleTo(0.1, 1.5),
            cc.tintTo(0.1, 255, 255, 255)
        ),
        // Recover
        cc.delayTime(0.3),
        cc.spawn(
            cc.moveTo(0.5, startPos).easing(cc.easeOut(2)),
            cc.scaleTo(0.3, 1.0)
        )
    ));
}

function shakeScreen(layer: cc.Node): void {
    const orig = layer.getPosition();
    const shakes: cc.FiniteTimeAction[] = [];
    for (let i = 0; i < 6; i++) {
        shakes.push(cc.moveTo(0.04, cc.p(
            orig.x + (Math.random() - 0.5) * 16,
            orig.y + (Math.random() - 0.5) * 16
        )));
    }
    shakes.push(cc.moveTo(0.04, orig));
    layer.runAction(cc.sequence(shakes));
}
