```typescript
interface AnimClip {
    readonly name: string;
    readonly frames: cc.SpriteFrame[];
    readonly fps: number;
    readonly loop: boolean;
}

class SpriteAnimator {
    private _sprite: cc.Sprite;
    private _clips: Map<string, AnimClip> = new Map();
    private _currentClip: string = '';
    private _onComplete: (() => void) | null = null;

    constructor(sprite: cc.Sprite) {
        this._sprite = sprite;
    }

    addClip(name: string, framePrefix: string, count: number, fps: number, loop: boolean): void {
        const frames: cc.SpriteFrame[] = [];
        for (let i = 0; i < count; i++) {
            const idx = i < 10 ? '0' + i : '' + i;
            const frame = cc.spriteFrameCache.getSpriteFrame(framePrefix + idx + '.png');
            if (frame) frames.push(frame);
        }
        this._clips.set(name, { name, frames, fps, loop });
    }

    play(name: string, onComplete?: () => void): void {
        if (this._currentClip === name) return;
        const clip = this._clips.get(name);
        if (!clip || clip.frames.length === 0) return;

        this._currentClip = name;
        this._onComplete = onComplete || null;
        this._sprite.stopAllActions();

        const anim = new cc.Animation(clip.frames, 1 / clip.fps);
        const animate = cc.animate(anim);

        if (clip.loop) {
            this._sprite.runAction(animate.repeatForever());
        } else {
            const seq = cc.sequence(animate, cc.callFunc(() => {
                this._currentClip = '';
                if (this._onComplete) this._onComplete();
            }));
            this._sprite.runAction(seq);
        }
    }

    stop(): void {
        this._sprite.stopAllActions();
        this._currentClip = '';
    }

    getCurrentClip(): string {
        return this._currentClip;
    }
}

// Usage:
cc.spriteFrameCache.addSpriteFrames('res/hero.plist', 'res/hero.png');
const sprite = new cc.Sprite(cc.spriteFrameCache.getSpriteFrame('hero_idle_00.png'));
this.addChild(sprite);

const animator = new SpriteAnimator(sprite);
animator.addClip('idle', 'hero_idle_', 4, 8, true);
animator.addClip('attack', 'hero_attack_', 6, 12, false);
animator.addClip('run', 'hero_run_', 8, 10, true);

animator.play('idle');
// Later:
animator.play('attack', () => {
    animator.play('idle');
});
```

```typescript
// 1. Load the atlas
cc.spriteFrameCache.addSpriteFrames('res/enemies.plist', 'res/enemies.png');

// 2. Create batch node with the SAME texture
const batch = new cc.SpriteBatchNode('res/enemies.png', 200);
this.addChild(batch);

// 3. Create sprites using cached frames and add to batch
