    const frame = cc.spriteFrameCache.getSpriteFrame(frameName);
    const sprite = new cc.Sprite(frame);
    sprite.setPosition(pos);
    batch.addChild(sprite);
    return sprite;
}

// All these sprites render in ONE draw call
