Detect orientation and adjust layout using director methods:

```typescript
class AdaptiveScene extends cc.Scene {
    private _isLandscape: boolean;

    onEnter(): void {
        super.onEnter();
        this.detectOrientation();
        this.layoutForOrientation();
        this.scheduleUpdate();
    }

    private detectOrientation(): void {
        const winSize = cc.director.getWinSize();
        this._isLandscape = winSize.width > winSize.height;
    }

    private layoutForOrientation(): void {
        const winSize = cc.director.getWinSize();
        const cx = winSize.width / 2;
        const cy = winSize.height / 2;

        if (this._isLandscape) {
            this.layoutLandscape(winSize, cx, cy);
        } else {
            this.layoutPortrait(winSize, cx, cy);
        }
    }

    private layoutLandscape(size: cc.Size, cx: number, cy: number): void {
        // Side-by-side layout
        cc.log('Landscape:', size.width, 'x', size.height);
    }

    private layoutPortrait(size: cc.Size, cx: number, cy: number): void {
        // Stacked layout
        cc.log('Portrait:', size.width, 'x', size.height);
    }

    update(dt: number): void {
        // Check for orientation change
        const winSize = cc.director.getWinSize();
        const nowLandscape = winSize.width > winSize.height;
        if (nowLandscape !== this._isLandscape) {
            this._isLandscape = nowLandscape;
            this.layoutForOrientation();
        }
    }
}
```

Use `cc.director.getWinSize()` each frame to detect orientation changes, then re-layout the UI accordingly.

These methods account for letterboxing when the screen aspect ratio doesn't match the design resolution:

```typescript
const visibleSize: cc.Size = cc.director.getVisibleSize();
const origin: cc.Point = cc.director.getVisibleOrigin();

// Position at the visible center
sprite.setPosition(
    origin.x + visibleSize.width / 2,
    origin.y + visibleSize.height / 2
);

// Position at corners of visible area
const topRight = cc.p(
    origin.x + visibleSize.width,
    origin.y + visibleSize.height
);
const bottomLeft = cc.p(origin.x, origin.y);
```

Practical UI layout:
```typescript
class UILayout {
    private _origin: cc.Point;
    private _size: cc.Size;

    constructor() {
        this._origin = cc.director.getVisibleOrigin();
        this._size = cc.director.getVisibleSize();
    }

    topLeft(): cc.Point {
        return cc.p(this._origin.x, this._origin.y + this._size.height);
    }

    topRight(): cc.Point {
        return cc.p(this._origin.x + this._size.width, this._origin.y + this._size.height);
    }

    bottomLeft(): cc.Point {
        return cc.p(this._origin.x, this._origin.y);
    }

    bottomRight(): cc.Point {
        return cc.p(this._origin.x + this._size.width, this._origin.y);
    }

    center(): cc.Point {
        return cc.p(
            this._origin.x + this._size.width / 2,
            this._origin.y + this._size.height / 2
        );
    }
}
```

Difference: `getWinSize()` returns the design resolution. `getVisibleSize()` + `getVisibleOrigin()` return the area actually visible on screen after resolution policy is applied.

`unloadEffect` removes a specific sound effect file from the audio engine's cache, freeing its memory:

```typescript
cc.audioEngine.unloadEffect(url: string): void
```

**Usage:**
```typescript
// Preload effects for current level
cc.audioEngine.preloadEffect('res/audio/sfx_laser.mp3');
cc.audioEngine.preloadEffect('res/audio/sfx_explosion.mp3');

// Use them during gameplay
cc.audioEngine.playEffect('res/audio/sfx_laser.mp3');
cc.audioEngine.playEffect('res/audio/sfx_explosion.mp3');

// Level complete — unload level-specific effects
cc.audioEngine.unloadEffect('res/audio/sfx_laser.mp3');
cc.audioEngine.unloadEffect('res/audio/sfx_explosion.mp3');
```

**When to use:**
- After leaving a level that has unique sound effects
- When memory is tight and certain effects won't be needed again
- During scene transitions to free resources from the previous scene

**When NOT to use:**
- For effects used across multiple scenes (UI clicks, common hits)
- While the effect is still playing — stop it first with `stopEffect`

For bulk cleanup, `end()` releases everything at once. `unloadEffect` is for selective, granular memory management.

The type signature is:

```typescript
cc.eventManager.addListener<T extends cc.EventListener>(
    listener: T,
    nodeOrPriority: cc.Node | number
): T
```

The first parameter is either an `EventListener` instance or a plain object that `cc.EventListener.create` will process. The second parameter can be:

- **`cc.Node`** — the listener is associated with that node and receives events based on the node's scene graph priority
- **`number`** — the listener uses a fixed priority (lower numbers = higher priority, executed first)

The method returns the created/added listener, which you should store for later removal.

Examples:
```typescript
// Node-based priority
const listener = cc.eventManager.addListener({
    event: cc.EventListener.TOUCH_ONE_BY_ONE,
    onTouchBegan: (touch, event) => true
}, myNode);

// Fixed priority (used for custom events)
const customListener = cc.eventManager.addListener({
    event: cc.EventListener.CUSTOM,
    callback: (event) => { /* ... */ }
}, 1);
```

```typescript
const WeaponType = {
    NONE: 'none',
    SWORD: 'sword',
    AXE: 'axe',
    BOW: 'bow',
    STAFF: 'staff'
} as const;

type WeaponTypeValue = typeof WeaponType[keyof typeof WeaponType];

const WEAPON_SLOT = 'weapon_slot';

const WEAPON_ATTACHMENT_MAP: Record<WeaponTypeValue, string | null> = {
    [WeaponType.NONE]: null,
    [WeaponType.SWORD]: 'sword',
    [WeaponType.AXE]: 'axe',
    [WeaponType.BOW]: 'bow',
    [WeaponType.STAFF]: 'staff'
};

class WeaponSystem {
    private skel: sp.SkeletonAnimation;
    private currentWeapon: WeaponTypeValue = WeaponType.NONE;

    constructor(skel: sp.SkeletonAnimation) {
        this.skel = skel;
    }

    equipWeapon(weapon: WeaponTypeValue): void {
        const attachment = WEAPON_ATTACHMENT_MAP[weapon];
        this.skel.setAttachment(WEAPON_SLOT, attachment);
        this.currentWeapon = weapon;
    }

    unequipWeapon(): void {
        this.skel.setAttachment(WEAPON_SLOT, null);
        this.currentWeapon = WeaponType.NONE;
    }

    getCurrentWeapon(): WeaponTypeValue {
        return this.currentWeapon;
    }
}

// Usage:
const hero = new sp.SkeletonAnimation('res/hero/hero.json', 'res/hero/hero.atlas');
hero.setAnimation(0, 'idle', true);

const weapons = new WeaponSystem(hero);
weapons.equipWeapon(WeaponType.SWORD);  // shows sword
weapons.equipWeapon(WeaponType.BOW);    // switches to bow
weapons.unequipWeapon();                // hides weapon
```

`setAttachment` with `null` hides the attachment. The attachment names must match those defined in the Spine editor project for the given slot.

