class AdManager {
    private static readonly AD_SHOWN_KEY = 'last_ad_shown';
    private static readonly AD_INTERVAL_MS = 180000; // 3 minutes

    showInterstitial(): void {
        if (!this.shouldShowAd()) return;

        if (cc.sys.isNative) {
            this.showNativeAd();
        } else {
            this.showWebAd();
        }

        cc.sys.localStorage.setItem(
            AdManager.AD_SHOWN_KEY,
            Date.now().toString()
        );
