    private shouldShowAd(): boolean {
        const raw = cc.sys.localStorage.getItem(AdManager.AD_SHOWN_KEY);
        if (!raw) return true;
        const lastShown = parseInt(raw, 10);
        return (Date.now() - lastShown) >= AdManager.AD_INTERVAL_MS;
    }

    private showNativeAd(): void {
        if (cc.sys.platform === cc.sys.ANDROID) {
            cc.log('Showing Android interstitial');
            // jsb.reflection.callStaticMethod('com/game/AdBridge', 'showInterstitial', '()V');
