instruction:
Complete this code to create a 9-slice-like sprite by compositing 4 corner sprites and stretched edges:

```typescript
function createFramedRect(
    parent: cc.Node,
    atlasFrame: string,
    cornerSize: number,
    totalSize: cc.Size
): cc.Node {
    // TODO: build the framed rectangle from corners and edges
}
```

output:
```typescript
function createFramedRect(
    parent: cc.Node,
    atlasFrame: string,
    cornerSize: number,
    totalSize: cc.Size
): cc.Node {
    const container = new cc.Node();
    container.setContentSize(totalSize);
    parent.addChild(container);

    const tex = cc.spriteFrameCache.getSpriteFrame(atlasFrame).getTexture();
    const texRect = cc.spriteFrameCache.getSpriteFrame(atlasFrame).getRectInPixels();
    const cs = cornerSize;
    const w = totalSize.width;
    const h = totalSize.height;
    const tx = texRect.x;
    const ty = texRect.y;
    const tw = texRect.width;
    const th = texRect.height;

    // Helper to create a sprite from a sub-rect of the texture
    function makeSlice(sx: number, sy: number, sw: number, sh: number): cc.Sprite {
        const frame = new cc.SpriteFrame(tex, cc.rect(tx + sx, ty + sy, sw, sh));
        return new cc.Sprite(frame);
    }

    // Bottom-left corner
    const bl = makeSlice(0, th - cs, cs, cs);
    bl.setAnchorPoint(cc.p(0, 0));
    bl.setPosition(0, 0);
    container.addChild(bl);

    // Bottom-right corner
    const br = makeSlice(tw - cs, th - cs, cs, cs);
    br.setAnchorPoint(cc.p(0, 0));
    br.setPosition(w - cs, 0);
    container.addChild(br);

    // Top-left corner
    const tl = makeSlice(0, 0, cs, cs);
    tl.setAnchorPoint(cc.p(0, 0));
    tl.setPosition(0, h - cs);
    container.addChild(tl);

    // Top-right corner
    const tr = makeSlice(tw - cs, 0, cs, cs);
    tr.setAnchorPoint(cc.p(0, 0));
    tr.setPosition(w - cs, h - cs);
    container.addChild(tr);

    // Edges (stretched)
    const top = makeSlice(cs, 0, tw - cs * 2, cs);
    top.setAnchorPoint(cc.p(0, 0));
    top.setPosition(cs, h - cs);
    top.setScaleX((w - cs * 2) / (tw - cs * 2));
    container.addChild(top);

    const bottom = makeSlice(cs, th - cs, tw - cs * 2, cs);
    bottom.setAnchorPoint(cc.p(0, 0));
    bottom.setPosition(cs, 0);
    bottom.setScaleX((w - cs * 2) / (tw - cs * 2));
    container.addChild(bottom);

    return container;
}
```

instruction:
Review this code for potential issues:

```typescript
function isInsideCircle(point: cc.Point, center: cc.Point, radius: number): boolean {
    return cc.pDistance(point, center) <= radius;
}

function findNearestEnemy(player: cc.Point, enemies: cc.Point[]): number {
    let minDist = Infinity;
    let nearest = -1;
    for (let i = 0; i < enemies.length; i++) {
        const dist = cc.pDistance(player, enemies[i]);
        if (dist < minDist) {
            minDist = dist;
            nearest = i;
        }
    }
    return nearest;
}
```

output:
Issues:

1. **Performance in `findNearestEnemy`**: Uses `cc.pDistance` (which calls `Math.sqrt`) for every enemy. Since we only need relative comparisons, `cc.pDistanceSQ` is more efficient.

2. **`isInsideCircle` is fine** — it needs the actual distance for the threshold comparison. But if called very frequently (every frame for many objects), consider also using squared distance.

3. **Empty array**: `findNearestEnemy` returns `-1` for empty arrays, which is correct.

Improved version:
```typescript
function isInsideCircle(point: cc.Point, center: cc.Point, radius: number): boolean {
    return cc.pDistanceSQ(point, center) <= radius * radius;
}

function findNearestEnemy(player: cc.Point, enemies: cc.Point[]): number {
    let minDistSQ = Infinity;
    let nearest = -1;
    for (let i = 0; i < enemies.length; i++) {
        const distSQ = cc.pDistanceSQ(player, enemies[i]);
        if (distSQ < minDistSQ) {
            minDistSQ = distSQ;
            nearest = i;
        }
    }
    return nearest;
}
```

Using squared distances avoids `Math.sqrt` calls, which is meaningful when checking many entities per frame.

Scale the game layer to simulate zoom, adjusting position to keep focus point centered:

```typescript
function zoomCamera(
    gameLayer: cc.Node, targetScale: number, focusPoint: cc.Point, duration: number
): void {
    const winSize = cc.director.getWinSize();
    const cx = winSize.width / 2;
    const cy = winSize.height / 2;

    // Calculate position to keep focusPoint centered after zoom
    const targetX = cx - focusPoint.x * targetScale;
    const targetY = cy - focusPoint.y * targetScale;

    gameLayer.runAction(cc.spawn(
        cc.scaleTo(duration, targetScale).easing(cc.easeSineInOut()),
        cc.moveTo(duration, cc.p(targetX, targetY)).easing(cc.easeSineInOut())
    ));
}

// Zoom in on the boss
zoomCamera(this.gameLayer, 2.0, cc.p(300, 200), 1.0);

// Zoom back out
