```typescript
class AmbientSoundSystem {
    private sounds: Map<string, number> = new Map();
    private paths: Map<string, string> = new Map();

    addAmbientSound(name: string, path: string, volume: number): void {
        // Remove existing sound with same name
        this.removeAmbientSound(name);

        cc.audioEngine.preloadEffect(path);
        const id = cc.audioEngine.playEffect(path, true, 1.0, 0, volume);
        if (id !== null) {
            this.sounds.set(name, id);
            this.paths.set(name, path);
        }
    }

    removeAmbientSound(name: string): void {
        const id = this.sounds.get(name);
        if (id !== undefined) {
            cc.audioEngine.stopEffect(id);
            this.sounds.delete(name);
            this.paths.delete(name);
        }
    }

    removeAll(): void {
        for (const [name] of this.sounds) {
            this.removeAmbientSound(name);
        }
    }
}

// Usage:
const ambient = new AmbientSoundSystem();
ambient.addAmbientSound('wind', 'res/audio/amb_wind.mp3', 0.3);
ambient.addAmbientSound('rain', 'res/audio/amb_rain.mp3', 0.5);
ambient.addAmbientSound('birds', 'res/audio/amb_birds.mp3', 0.2);

// Remove specific sound
ambient.removeAmbientSound('rain');

// Clean up all
ambient.removeAll();
```

Each ambient sound is a looping effect with the `gain` parameter controlling its individual volume. Sounds are tracked by name for easy removal. `addAmbientSound` removes any existing sound with the same name first to prevent duplicates. `preloadEffect` ensures minimal latency.

instruction:
Find and fix the bug in this action manager code:

```typescript
class GameController {
    private _pausedTargets: cc.Node[];

    pauseGame(): void {
        this._pausedTargets = cc.director.getActionManager().pauseAllRunningActions();
        cc.director.getScheduler().pauseAllTargets();
    }

    resumeGame(): void {
        cc.director.getActionManager().resumeTargets(this._pausedTargets);
    }
}
```

output:
Two bugs:

**Bug 1: Scheduler targets not resumed.** `pauseGame` pauses both actions and scheduler, but `resumeGame` only resumes actions. All scheduled callbacks remain paused.

**Bug 2: `_pausedTargets` not initialized.** If `resumeGame` is called before `pauseGame`, `_pausedTargets` is `undefined`, causing a crash.

Fixed code:
```typescript
class GameController {
    private _pausedActionTargets: cc.Node[] = [];
    private _schedulerPaused: boolean = false;

    pauseGame(): void {
        this._pausedActionTargets = cc.director.getActionManager().pauseAllRunningActions();
        cc.director.getScheduler().pauseAllTargets();
        this._schedulerPaused = true;
        cc.log('Game paused');
    }

    resumeGame(): void {
        // Resume actions
        if (this._pausedActionTargets.length > 0) {
            cc.director.getActionManager().resumeTargets(this._pausedActionTargets);
            this._pausedActionTargets = [];
        }

        // Resume scheduler targets too
        if (this._schedulerPaused) {
            // pauseAllTargets returns paused set, but we didn't store it.
            // Better approach: use cc.director.resume() for global resume
            cc.director.resume();
            this._schedulerPaused = false;
        }

        cc.log('Game resumed');
    }
}
```

Alternatively, use `cc.director.pause()` / `cc.director.resume()` which handle both actions and scheduler together.

