Additive blending makes overlapping colors brighter, perfect for fire, explosions, and glow effects:

```typescript
// Additive blend: output = src_color * 1 + dst_color * 1
const additiveBlend = new cc.BlendFunc(cc.ONE, cc.ONE);

// Apply to a particle system
const particles = new cc.ParticleSystem('res/fire.plist');
particles.setBlendFunc(additiveBlend);
parentNode.addChild(particles);

// Apply to a glow sprite
const glowSprite = new cc.Sprite('res/glow.png');
glowSprite.setBlendFunc(new cc.BlendFunc(cc.ONE, cc.ONE));
glowSprite.setPosition(200, 200);
parentNode.addChild(glowSprite);

// Softer additive (uses source alpha for transparency)
const softAdditive = new cc.BlendFunc(cc.SRC_ALPHA, cc.ONE);
const softGlow = new cc.Sprite('res/soft_glow.png');
softGlow.setBlendFunc(softAdditive);

// Creating a layered glow effect
function createGlowEffect(position: cc.Point): cc.Node {
    const container = new cc.Node();
    container.setPosition(position);

    // Base glow (large, dim)
    const outer = new cc.Sprite('res/glow_circle.png');
    outer.setBlendFunc(new cc.BlendFunc(cc.SRC_ALPHA, cc.ONE));
    outer.setScale(2.0);
    outer.setOpacity(100);
    container.addChild(outer);

    // Core glow (small, bright)
    const inner = new cc.Sprite('res/glow_circle.png');
    inner.setBlendFunc(new cc.BlendFunc(cc.ONE, cc.ONE));
    inner.setScale(0.5);
    container.addChild(inner);

    return container;
}
```

