function inflateRect(rect: cc.Rect, margin: number): cc.Rect {
    return cc.rect(
        rect.x - margin,
        rect.y - margin,
        rect.width + margin * 2,
        rect.height + margin * 2
    );
}

function deflateRect(rect: cc.Rect, margin: number): cc.Rect {
    return inflateRect(rect, -margin);
}

// Usage:
