    cc.log('Precisely on the sprite');
}
```

Build a level manager that loads resources before transitioning:

```typescript
class LevelManager {
    private static _currentLevel: number = 0;

    static loadLevel(levelNum: number): void {
        const levelPath = 'res/levels/level' + levelNum + '.json';
        const assets = [
            levelPath,
            'res/levels/level' + levelNum + '_bg.png'
        ];

        // Show loading scene
        const loading = new LoadingScene();
        cc.director.runScene(loading);

        cc.loader.load(assets, (err) => {
            if (err) {
                cc.error('Failed to load level', levelNum);
                return;
            }

            const levelData = cc.loader.getRes(levelPath);
            LevelManager._currentLevel = levelNum;

            const gameScene = new GameScene();
            gameScene.setLevelData(levelData);
            cc.director.runScene(new cc.TransitionFade(0.5, gameScene));
        });
    }

    static nextLevel(): void {
        // Release current level resources
        cc.loader.release('res/levels/level' + LevelManager._currentLevel + '.json');
        cc.loader.release('res/levels/level' + LevelManager._currentLevel + '_bg.png');

        LevelManager.loadLevel(LevelManager._currentLevel + 1);
    }

    static restartLevel(): void {
        LevelManager.loadLevel(LevelManager._currentLevel);
    }

    static get currentLevel(): number {
        return LevelManager._currentLevel;
    }
}

// Usage:
LevelManager.loadLevel(1);
// After beating level:
LevelManager.nextLevel();
```

```typescript
class SlowMotionController {
    private skel: sp.SkeletonAnimation;
    private targetScale: number = 1.0;
    private currentScale: number = 1.0;
    private restoreSpeed: number = 0;

    constructor(skel: sp.SkeletonAnimation) {
        this.skel = skel;
    }

    triggerSlowMotion(scale: number, duration: number): void {
        this.currentScale = scale;
        this.targetScale = 1.0;
        this.restoreSpeed = (1.0 - scale) / duration;
        this.skel.setTimeScale(scale);
    }

    update(dt: number): void {
        if (this.currentScale < this.targetScale) {
            this.currentScale = Math.min(
                this.currentScale + this.restoreSpeed * dt,
                this.targetScale
            );
            this.skel.setTimeScale(this.currentScale);
        }
    }
}

// Usage in a layer:
class GameLayer extends cc.Layer {
    private hero: sp.SkeletonAnimation;
    private slowMo: SlowMotionController;

    init(): boolean {
        this.hero = new sp.SkeletonAnimation('res/hero/hero.json', 'res/hero/hero.atlas');
        this.hero.setPosition(240, 160);
        this.addChild(this.hero);
        this.hero.setAnimation(0, 'run', true);

        this.slowMo = new SlowMotionController(this.hero);
        this.scheduleUpdate();
        return true;
    }

    onHitConfirm(): void {
        this.slowMo.triggerSlowMotion(0.2, 1.0);
    }

    update(dt: number): void {
        this.slowMo.update(dt);
    }
}
```

Calling `triggerSlowMotion(0.2, 1.0)` drops to 20% speed and linearly restores to normal over 1 second. The controller uses `setTimeScale` which affects all tracks globally.

```typescript
interface TimeOfDayColors {
    startColor: cc.Color;
    endColor: cc.Color;
    startOpacity: number;
    endOpacity: number;
}

const TIME_SCHEMES: Record<string, TimeOfDayColors> = {
    dawn:  { startColor: cc.color(255, 150, 80, 255),  endColor: cc.color(100, 50, 120, 255),  startOpacity: 255, endOpacity: 255 },
    day:   { startColor: cc.color(135, 206, 250, 255), endColor: cc.color(70, 130, 200, 255),  startOpacity: 255, endOpacity: 255 },
    dusk:  { startColor: cc.color(255, 100, 50, 255),  endColor: cc.color(40, 20, 80, 255),   startOpacity: 255, endOpacity: 255 },
    night: { startColor: cc.color(10, 10, 40, 255),    endColor: cc.color(0, 0, 10, 255),     startOpacity: 255, endOpacity: 200 }
};

class DayNightCycle extends cc.Layer {
    private sky: cc.LayerGradient;
    private currentScheme: string = 'day';

    constructor() {
        super();
        this.init();
    }

    init(): boolean {
        const scheme = TIME_SCHEMES[this.currentScheme];
        this.sky = new cc.LayerGradient(
            scheme.startColor,
            scheme.endColor,
            cc.p(0, -1)
        );
        this.addChild(this.sky);
        return true;
    }

    transitionTo(timeOfDay: string): void {
        const scheme = TIME_SCHEMES[timeOfDay];
        if (!scheme) return;

        this.currentScheme = timeOfDay;
        this.sky.setStartColor(scheme.startColor);
        this.sky.setEndColor(scheme.endColor);
        this.sky.setStartOpacity(scheme.startOpacity);
        this.sky.setEndOpacity(scheme.endOpacity);
    }

    getTimeOfDay(): string {
        return this.currentScheme;
    }
}

// Usage:
const cycle = new DayNightCycle();
scene.addChild(cycle, -1);
cycle.transitionTo('dawn');
cycle.transitionTo('night');
```

Four time-of-day presets are stored as color configurations. `transitionTo` updates the gradient's start/end colors and opacities. The gradient direction `cc.p(0, -1)` creates a natural top-to-bottom sky effect. For smooth animated transitions, you could interpolate the color values over time using `scheduleUpdate`.

instruction:
Find and fix the bug in this code that tries to blend two animations:

```typescript
const hero = new sp.SkeletonAnimation('res/hero/hero.json', 'res/hero/hero.atlas');
hero.setMix('walk', 'run', 0.3);
hero.setAnimation(0, 'run', true);
// Later...
hero.setAnimation(0, 'walk', true); // Expected smooth blend, but it snaps
```

output:
The bug is that `setMix` was set for 'walk' -> 'run' but the actual transition is 'run' -> 'walk'. `setMix` is directional — it only defines the blend for the specified from->to pair.

**Fixed code:**
```typescript
const hero = new sp.SkeletonAnimation('res/hero/hero.json', 'res/hero/hero.atlas');

// Define both directions
hero.setMix('walk', 'run', 0.3);
hero.setMix('run', 'walk', 0.3);  // Added: reverse direction

hero.setAnimation(0, 'run', true);
// Later...
hero.setAnimation(0, 'walk', true); // Now blends smoothly over 0.3s
```

`setMix('walk', 'run', 0.3)` only applies when transitioning FROM walk TO run. To get smooth transitions in both directions, you must call `setMix` for each direction explicitly.

Use `touch.getID()` to identify individual fingers:

```typescript
touch.getID(): number | undefined
```

On native platforms (iOS/Android), each finger gets a unique integer ID. On HTML5, it may return `undefined`.

```typescript
class MultiTouchTracker extends cc.Layer {
    private _touchPositions: Map<number, cc.Point> = new Map();
    private _listener: cc.EventListener;

    onEnter(): void {
        super.onEnter();
        this._listener = cc.eventManager.addListener({
            event: cc.EventListener.TOUCH_ALL_AT_ONCE,
            onTouchesBegan: (touches: cc.Touch[], event: cc.Event): void => {
                for (const touch of touches) {
                    const id = touch.getID();
                    if (id !== undefined) {
                        this._touchPositions.set(id, touch.getLocation());
                        cc.log('Finger', id, 'down');
                    }
                }
            },
            onTouchesMoved: (touches: cc.Touch[], event: cc.Event): void => {
                for (const touch of touches) {
                    const id = touch.getID();
                    if (id !== undefined) {
                        this._touchPositions.set(id, touch.getLocation());
                    }
                }
            },
            onTouchesEnded: (touches: cc.Touch[], event: cc.Event): void => {
                for (const touch of touches) {
                    const id = touch.getID();
                    if (id !== undefined) {
                        this._touchPositions.delete(id);
                        cc.log('Finger', id, 'up');
                    }
                }
            }
        }, this);
    }

    onExit(): void {
        cc.eventManager.removeListener(this._listener);
        super.onExit();
    }
}
```

Note: `getID()` returns `undefined` on H5 (browser), so always check before using it as a map key.

Use `node.convertToNodeSpace()` to transform a world-space touch position into a node's local coordinate system:

```typescript
onTouchBegan: (touch: cc.Touch, event: cc.Event): boolean => {
    // touch.getLocation() returns world (GL) coordinates
    const worldPos: cc.Point = touch.getLocation();

    // Convert to node-local coordinates
    const localPos: cc.Point = myNode.convertToNodeSpace(worldPos);

    // Now check if touch is within the node's bounds
    const size = myNode.getContentSize();
    const bounds = cc.rect(0, 0, size.width, size.height);
    if (cc.rectContainsPoint(bounds, localPos)) {
        cc.log('Touched inside node at local:', localPos.x, localPos.y);
        return true;
    }
    return false;
}
```

Note: `getLocation()` gives GL world coordinates. `getLocationInView()` gives screen coordinates. For hit testing against nodes, always use `getLocation()` + `convertToNodeSpace()`.

The coordinate conversion signatures:

```typescript
declare class Node {
    convertToNodeSpace(worldPoint: cc.Point): cc.Point;
    convertToWorldSpace(nodePoint: cc.Point): cc.Point;
    convertToNodeSpaceAR(worldPoint: cc.Point): cc.Point;
    convertToWorldSpaceAR(nodePoint: cc.Point): cc.Point;
    convertTouchToNodeSpace(touch: cc.Touch): cc.Point;
    convertTouchToNodeSpaceAR(touch: cc.Touch): cc.Point;
}
```

- `NodeSpace` uses the node's bottom-left corner as origin
- `NodeSpaceAR` (anchor-relative) uses the anchor point as origin
- Touch versions are convenience wrappers that extract the touch location first

```typescript
const local: cc.Point = node.convertToNodeSpace(cc.p(400, 300));
const world: cc.Point = node.convertToWorldSpace(cc.p(0, 0));
const touchPt: cc.Point = node.convertTouchToNodeSpace(touch);
```

