`swallowTouches: true` prevents touches from propagating to lower-priority listeners. Use this for modal popups:

```typescript
class ModalOverlay extends cc.LayerColor {
    private _listener: cc.EventListener;
    private _contentLayer: cc.Layer;

    constructor() {
        super(cc.color(0, 0, 0, 150)); // semi-transparent black
    }

    onEnter(): void {
        super.onEnter();

        // Block ALL touches to nodes behind the overlay
        this._listener = cc.eventManager.addListener({
            event: cc.EventListener.TOUCH_ONE_BY_ONE,
            swallowTouches: true,
            onTouchBegan: (touch: cc.Touch, event: cc.Event): boolean => {
                // Check if touch is on the overlay background (not content)
                const touchedContent = this.isTouchOnContent(touch);
                if (!touchedContent) {
                    // Tapped outside content — dismiss the overlay
                    this.dismiss();
                }
                return true; // always swallow to block background
            }
        }, this);
    }

    private isTouchOnContent(touch: cc.Touch): boolean {
        if (!this._contentLayer) return false;
        const loc = this._contentLayer.convertToNodeSpace(touch.getLocation());
        const size = this._contentLayer.getContentSize();
        return cc.rectContainsPoint(cc.rect(0, 0, size.width, size.height), loc);
    }

    setContent(layer: cc.Layer): void {
        this._contentLayer = layer;
        this.addChild(layer);
    }

    dismiss(): void {
        this.removeFromParent();
    }

    onExit(): void {
        cc.eventManager.removeListener(this._listener);
        super.onExit();
    }
}
```

The key: `swallowTouches: true` + `return true` from `onTouchBegan` = no touches reach anything behind this layer.

