```typescript
const v = cc.p(3, 4);

// Get vector length (magnitude)
const len: number = cc.pLength(v);  // 5

// Normalize (unit vector, length = 1)
const unit: cc.Point = cc.pNormalize(v);  // cc.p(0.6, 0.8)

// Common pattern: get direction from A to B
const source = cc.p(100, 100);
const target = cc.p(300, 200);
const direction = cc.pNormalize(cc.pSub(target, source));
// direction is a unit vector pointing from source to target

// Move toward target at a fixed speed
const speed = 100;
const velocity = cc.pMult(direction, speed);
// Apply: newPos = cc.pAdd(currentPos, cc.pMult(velocity, dt))
