Complete this code that draws a rounded rectangle using cc.DrawNode:

```typescript
function drawRoundedRect(
    draw: cc.DrawNode,
    origin: cc.Point,
    size: cc.Size,
    cornerRadius: number,
    fillColor: cc.Color,
    lineWidth: number,
    lineColor: cc.Color
): void {
    // TODO: draw a rectangle with rounded corners
}
```

output:
```typescript
function drawRoundedRect(
    draw: cc.DrawNode,
    origin: cc.Point,
    size: cc.Size,
    cornerRadius: number,
    fillColor: cc.Color,
    lineWidth: number,
    lineColor: cc.Color
): void {
    const r = Math.min(cornerRadius, size.width / 2, size.height / 2);
    const x = origin.x;
    const y = origin.y;
    const w = size.width;
    const h = size.height;
    const segs = 8; // segments per corner arc

    const verts: cc.Point[] = [];

    // Bottom-left corner
    for (let i = 0; i <= segs; i++) {
        const a = Math.PI + (Math.PI / 2) * (i / segs);
        verts.push(cc.p(x + r + r * Math.cos(a), y + r + r * Math.sin(a)));
    }
    // Bottom-right corner
    for (let i = 0; i <= segs; i++) {
        const a = (3 * Math.PI / 2) + (Math.PI / 2) * (i / segs);
        verts.push(cc.p(x + w - r + r * Math.cos(a), y + r + r * Math.sin(a)));
    }
    // Top-right corner
    for (let i = 0; i <= segs; i++) {
        const a = (Math.PI / 2) * (i / segs);
        verts.push(cc.p(x + w - r + r * Math.cos(a), y + h - r + r * Math.sin(a)));
    }
    // Top-left corner
    for (let i = 0; i <= segs; i++) {
        const a = (Math.PI / 2) + (Math.PI / 2) * (i / segs);
        verts.push(cc.p(x + r + r * Math.cos(a), y + h - r + r * Math.sin(a)));
    }

    draw.drawPoly(verts, fillColor, lineWidth, lineColor);
}

// Usage:
const draw = new cc.DrawNode();
this.addChild(draw);
drawRoundedRect(
    draw,
    cc.p(50, 50),
    cc.size(200, 100),
    15,
    cc.color(50, 100, 200, 180),
    2,
    cc.color(100, 150, 255, 255)
);
```

