```typescript
class AudioManager {
    private _bgmVolume: number;
    private _sfxVolume: number;
    private _bgmEnabled: boolean;
    private _sfxEnabled: boolean;
    private static readonly BGM_VOL_KEY = 'audio_bgm_vol';
    private static readonly SFX_VOL_KEY = 'audio_sfx_vol';
    private static readonly BGM_ON_KEY = 'audio_bgm_on';
    private static readonly SFX_ON_KEY = 'audio_sfx_on';

    constructor() {
        this._bgmVolume = this.loadFloat(AudioManager.BGM_VOL_KEY, 0.7);
        this._sfxVolume = this.loadFloat(AudioManager.SFX_VOL_KEY, 1.0);
        this._bgmEnabled = this.loadBool(AudioManager.BGM_ON_KEY, true);
        this._sfxEnabled = this.loadBool(AudioManager.SFX_ON_KEY, true);
    }

    private loadFloat(key: string, defaultVal: number): number {
        const raw = cc.sys.localStorage.getItem(key);
        if (!raw) return defaultVal;
        const val = parseFloat(raw);
        return isNaN(val) ? defaultVal : val;
    }

    private loadBool(key: string, defaultVal: boolean): boolean {
        const raw = cc.sys.localStorage.getItem(key);
        if (!raw) return defaultVal;
        return raw === 'true';
    }

    setBgmVolume(vol: number): void {
        this._bgmVolume = cc.clampf(vol, 0, 1);
        cc.sys.localStorage.setItem(AudioManager.BGM_VOL_KEY, this._bgmVolume.toString());
        if (cc.sys.isNative) {
            cc.audioEngine.setMusicVolume(this._bgmVolume);
        }
    }

    setSfxVolume(vol: number): void {
        this._sfxVolume = cc.clampf(vol, 0, 1);
        cc.sys.localStorage.setItem(AudioManager.SFX_VOL_KEY, this._sfxVolume.toString());
        if (cc.sys.isNative) {
            cc.audioEngine.setEffectsVolume(this._sfxVolume);
        }
    }

    toggleBgm(): void {
        this._bgmEnabled = !this._bgmEnabled;
        cc.sys.localStorage.setItem(AudioManager.BGM_ON_KEY, this._bgmEnabled.toString());
    }

    toggleSfx(): void {
        this._sfxEnabled = !this._sfxEnabled;
        cc.sys.localStorage.setItem(AudioManager.SFX_ON_KEY, this._sfxEnabled.toString());
    }

    get bgmVolume(): number { return this._bgmEnabled ? this._bgmVolume : 0; }
    get sfxVolume(): number { return this._sfxEnabled ? this._sfxVolume : 0; }
}
```

`cc.DrawNode.create()` returns `cc.DrawNode`.

`cc.DrawNode` extends `cc.Node`, which means it inherits all standard node methods:

```typescript
// Return type
const draw: cc.DrawNode = cc.DrawNode.create();

// All cc.Node methods are available:
draw.setPosition(100, 200);
draw.setScale(2);
draw.setVisible(false);
draw.setOpacity(128);
draw.setZOrder(10);
draw.setRotation(45);
this.addChild(draw);

// DrawNode-specific methods:
draw.drawDot(cc.p(0, 0), 5, cc.color(255, 0, 0, 255));
draw.clear();
draw.setDrawColor(cc.color(0, 255, 0, 255));
draw.setLineWidth(2);
draw.getBlendFunc(); // returns cc.BlendFunc
```

Since it extends `cc.Node`, you can position, scale, rotate, and parent the DrawNode in the scene graph like any other node. The drawn shapes are in the DrawNode's local coordinate space.

```typescript
class LoadingScreen extends cc.Layer {
    private barBg: cc.LayerColor;
    private barFill: cc.LayerGradient;
    private barWidth: number;
    private barHeight: number;
    private label: cc.LabelTTF;

    constructor() {
        super();
        this.init();
    }

    init(): boolean {
        const winSize = cc.director.getWinSize();

        // Dark background
        const bg = new cc.LayerColor(cc.color(15, 15, 25, 255));
        this.addChild(bg, 0);

        // Progress bar dimensions
        this.barWidth = winSize.width * 0.6;
        this.barHeight = 24;
        const barX = (winSize.width - this.barWidth) / 2;
        const barY = winSize.height / 2 - this.barHeight / 2;

        // Bar background (dark gray)
        this.barBg = new cc.LayerColor(
            cc.color(40, 40, 50, 255),
            this.barWidth, this.barHeight
        );
        this.barBg.setPosition(barX, barY);
        this.addChild(this.barBg, 1);

        // Gradient fill (green to bright green)
        this.barFill = new cc.LayerGradient(
            cc.color(0, 180, 80, 255),
            cc.color(0, 255, 120, 255),
            cc.p(1, 0)
        );
        this.barFill.changeWidthAndHeight(0, this.barHeight);
        this.barFill.setPosition(barX, barY);
        this.addChild(this.barFill, 2);

        // Loading label
        this.label = new cc.LabelTTF('Loading... 0%', 'Arial', 18);
        this.label.setPosition(winSize.width / 2, barY + this.barHeight + 30);
        this.addChild(this.label, 3);

        return true;
    }

    setProgress(percent: number): void {
        const clamped = Math.max(0, Math.min(100, percent));
        const fillWidth = (clamped / 100) * this.barWidth;
        this.barFill.changeWidth(fillWidth);
        this.label.setString('Loading... ' + Math.floor(clamped) + '%');
    }
}

// Usage:
const loading = new LoadingScreen();
scene.addChild(loading);
loading.setProgress(45);
```

The progress bar uses `cc.LayerColor` for the dark background track and `cc.LayerGradient` for a green gradient fill. The gradient direction `cc.p(1, 0)` goes left-to-right, creating a nice color transition as the bar fills. `changeWidth` resizes the fill dynamically.

Spawn coins at the pickup point and animate them to the counter position:

```typescript
function collectCoin(parent: cc.Node, fromPos: cc.Point, toPos: cc.Point, onDone: () => void): void {
    const coin = new cc.Sprite('coin.png');
    coin.setPosition(fromPos);
    coin.setScale(1.2);
    parent.addChild(coin, 100);

    const midX = (fromPos.x + toPos.x) / 2;
    const midY = Math.max(fromPos.y, toPos.y) + 80;

    coin.runAction(cc.sequence(
        cc.spawn(
            cc.bezierTo(0.6, [
                cc.p(midX, midY),
                cc.p(toPos.x, toPos.y + 20),
                toPos
            ]).easing(cc.easeIn(1.5)),
            cc.scaleTo(0.6, 0.5),
            cc.sequence(cc.delayTime(0.3), cc.fadeOut(0.3))
        ),
        cc.callFunc(() => {
            coin.removeFromParent();
            onDone();
        })
    ));

    // Spin while flying
    coin.runAction(cc.rotateBy(0.6, 720));
}

// Usage: collect 5 coins
for (let i = 0; i < 5; i++) {
    const delay = i * 0.1;
    this.scheduleOnce(() => {
        collectCoin(this, cc.p(200, 100), cc.p(400, 290), () => {
            this.coinCount++;
            this.updateCoinLabel();
        });
    }, delay);
}
```

