interface RectCorners {
    bottomLeft: cc.Point;
    bottomRight: cc.Point;
    topRight: cc.Point;
    topLeft: cc.Point;
}

function rectToCorners(rect: cc.Rect): RectCorners {
    return {
        bottomLeft: cc.p(rect.x, rect.y),
        bottomRight: cc.p(rect.x + rect.width, rect.y),
        topRight: cc.p(rect.x + rect.width, rect.y + rect.height),
        topLeft: cc.p(rect.x, rect.y + rect.height)
    };
}

