```typescript
function drawDotGrid(
    draw: cc.DrawNode,
    origin: cc.Point,
    rows: number,
    cols: number,
    spacing: number,
    dotRadius: number,
    color: cc.Color
): void {
    const points: cc.Point[] = [];
    for (let r = 0; r < rows; r++) {
        for (let c = 0; c < cols; c++) {
            points.push(cc.p(
                origin.x + c * spacing,
                origin.y + r * spacing
            ));
        }
    }
    draw.drawDots(points, dotRadius, color);
}

// Usage:
const draw = new cc.DrawNode();
this.addChild(draw);
drawDotGrid(draw, cc.p(50, 50), 5, 8, 30, 3, cc.color(200, 200, 200, 255));
```

This uses `drawDots` for efficiency, batching all dots into one call rather than calling `drawDot` individually.

