Common pattern for game pause:
```typescript
class GamePauseController {
    private _pausedTargets: cc.Node[] = [];

    pause(): void {
        this._pausedTargets = cc.director.getActionManager().pauseAllRunningActions();
        cc.log('Paused', this._pausedTargets.length, 'targets');
