`cc.loader.getXMLHttpRequest()` returns a cross-platform XMLHttpRequest:

```typescript
const xhr = cc.loader.getXMLHttpRequest();
xhr.open('GET', 'https://api.example.com/scores', true);
xhr.setRequestHeader('Content-Type', 'application/json');

xhr.onreadystatechange = function() {
    if (xhr.readyState === 4) {
        if (xhr.status === 200) {
            const data = JSON.parse(xhr.responseText);
            cc.log('Scores received:', data);
        } else {
            cc.error('Request failed:', xhr.status);
        }
    }
};

xhr.send();
```

POST example:
```typescript
function postScore(score: number, callback: (success: boolean) => void): void {
    const xhr = cc.loader.getXMLHttpRequest();
    xhr.open('POST', 'https://api.example.com/scores', true);
    xhr.setRequestHeader('Content-Type', 'application/json');

    xhr.onreadystatechange = function() {
        if (xhr.readyState === 4) {
            callback(xhr.status === 200);
        }
    };

    xhr.send(JSON.stringify({ score: score, timestamp: Date.now() }));
}
```

Using `cc.loader.getXMLHttpRequest()` instead of `new XMLHttpRequest()` ensures compatibility across native (JSB) and browser environments.

```typescript
interface AudioConfig {
    musicVolume: number;
    sfxVolume: number;
    musicEnabled: boolean;
    sfxEnabled: boolean;
}

class AudioManager {
    private config: AudioConfig;
    private activeEffects: Map<string, number> = new Map();

    private static readonly DEFAULT_CONFIG: AudioConfig = {
        musicVolume: 0.7,
        sfxVolume: 0.8,
        musicEnabled: true,
        sfxEnabled: true
    };

    constructor(config?: Partial<AudioConfig>) {
        this.config = { ...AudioManager.DEFAULT_CONFIG, ...config };
        this.applyVolumes();
    }

    private applyVolumes(): void {
        cc.audioEngine.setMusicVolume(
            this.config.musicEnabled ? this.config.musicVolume : 0
        );
        cc.audioEngine.setEffectsVolume(
            this.config.sfxEnabled ? this.config.sfxVolume : 0
        );
    }

    preloadAll(musicPaths: string[], sfxPaths: string[]): void {
        for (const path of musicPaths) {
            cc.audioEngine.preloadMusic(path);
        }
        for (const path of sfxPaths) {
            cc.audioEngine.preloadEffect(path);
        }
    }

    playMusic(path: string, loop: boolean = true): void {
        if (!this.config.musicEnabled) return;
        cc.audioEngine.playMusic(path, loop);
    }

    stopMusic(release: boolean = false): void {
        cc.audioEngine.stopMusic(release);
    }

    playSfx(path: string, loop: boolean = false): number | null {
        if (!this.config.sfxEnabled) return null;
        const id = cc.audioEngine.playEffect(path, loop);
        if (id !== null && loop) {
            this.activeEffects.set(path, id);
        }
        return id;
    }

    stopSfx(path: string): void {
        const id = this.activeEffects.get(path);
        if (id !== undefined) {
            cc.audioEngine.stopEffect(id);
            this.activeEffects.delete(path);
        }
    }

    setMusicVolume(vol: number): void {
        this.config.musicVolume = vol;
        cc.audioEngine.setMusicVolume(vol);
    }

    setSfxVolume(vol: number): void {
        this.config.sfxVolume = vol;
        cc.audioEngine.setEffectsVolume(vol);
    }

    toggleMusic(enabled: boolean): void {
        this.config.musicEnabled = enabled;
        if (!enabled) {
            cc.audioEngine.pauseMusic();
        } else {
            cc.audioEngine.resumeMusic();
        }
        this.applyVolumes();
    }

    cleanup(): void {
        cc.audioEngine.stopAllEffects();
        cc.audioEngine.stopMusic();
        this.activeEffects.clear();
    }
}

// Usage:
const audio = new AudioManager({ musicVolume: 0.5 });
audio.preloadAll(
    ['res/audio/bgm_main.mp3'],
    ['res/audio/sfx_hit.mp3', 'res/audio/sfx_coin.mp3']
);
audio.playMusic('res/audio/bgm_main.mp3');
audio.playSfx('res/audio/sfx_coin.mp3');
```

This manager wraps `cc.audioEngine` with enable/disable toggles, volume tracking, looping effect management, and preloading. The `activeEffects` map tracks looping effects by path for later stopping.

```typescript
class AnimatedCharacter extends cc.Node {
    private _sprite: cc.Sprite;
    private _idleAction: cc.Action;
    private _runAction: cc.Action;
    private _currentAnim: string = '';

    constructor(atlasPath: string, atlasImage: string) {
        super();
        cc.spriteFrameCache.addSpriteFrames(atlasPath, atlasImage);

        const idleFrame = cc.spriteFrameCache.getSpriteFrame('hero_idle_01.png');
        this._sprite = new cc.Sprite(idleFrame);
        this.addChild(this._sprite);

        this._idleAction = this.createAnim('hero_idle', 4, 0.15);
        this._runAction = this.createAnim('hero_run', 8, 0.08);

        this.playIdle();
    }

    private createAnim(prefix: string, count: number, delay: number): cc.Action {
        const frames: cc.SpriteFrame[] = [];
        for (let i = 1; i <= count; i++) {
            const name = prefix + '_' + (i < 10 ? '0' : '') + i + '.png';
            frames.push(cc.spriteFrameCache.getSpriteFrame(name));
        }
        const anim = new cc.Animation(frames, delay);
        return cc.animate(anim).repeatForever();
    }

    playIdle(): void {
        if (this._currentAnim === 'idle') return;
        this._currentAnim = 'idle';
        this._sprite.stopAllActions();
        this._sprite.runAction(this._idleAction.clone());
    }

    playRun(): void {
        if (this._currentAnim === 'run') return;
        this._currentAnim = 'run';
        this._sprite.stopAllActions();
        this._sprite.runAction(this._runAction.clone());
    }

    setFacing(right: boolean): void {
        this._sprite.setFlippedX(!right);
    }
}

// Usage:
const hero = new AnimatedCharacter('res/hero.plist', 'res/hero.png');
hero.setPosition(240, 160);
this.addChild(hero);
hero.playRun();
hero.setFacing(false); // face left
```

```typescript
const UNINTERRUPTIBLE_ANIMS = ['death', 'ultimate', 'stun'] as const;

class AnimationGuard {
    private skel: sp.SkeletonAnimation;

    constructor(skel: sp.SkeletonAnimation) {
        this.skel = skel;
    }

    private isCurrentUninterruptible(): boolean {
        const current = this.skel.getCurrent(0);
        if (!current) return false;
        const name = current.animation.name;
        return (UNINTERRUPTIBLE_ANIMS as readonly string[]).indexOf(name) !== -1;
    }

    trySetAnimation(name: string, loop: boolean): spine.TrackEntry | null {
        if (this.isCurrentUninterruptible()) {
            cc.log('Cannot interrupt: ' + this.skel.getCurrent(0).animation.name);
            return null;
        }
        return this.skel.setAnimation(0, name, loop);
    }

    forceSetAnimation(name: string, loop: boolean): spine.TrackEntry | null {
        return this.skel.setAnimation(0, name, loop);
    }

    getCurrentAnimationName(): string | null {
        const current = this.skel.getCurrent(0);
        return current ? current.animation.name : null;
    }
}

// Usage:
const hero = new sp.SkeletonAnimation('res/hero/hero.json', 'res/hero/hero.atlas');
const guard = new AnimationGuard(hero);

guard.trySetAnimation('idle', true);      // plays idle
guard.forceSetAnimation('death', false);  // forces death
guard.trySetAnimation('run', true);       // blocked — death is uninterruptible
```

`getCurrent(trackIndex)` returns the active `spine.TrackEntry` on that track, or `null` if nothing is playing. This lets you inspect the current animation name before deciding whether to allow a transition.

