```typescript
class SceneStackManager {
    private static _instance: SceneStackManager;
    private _sceneNames: string[] = [];
    private static readonly TRANSITION_DURATION = 0.4;

    static get instance(): SceneStackManager {
        if (!SceneStackManager._instance) {
            SceneStackManager._instance = new SceneStackManager();
        }
        return SceneStackManager._instance;
    }

    runScene(scene: cc.Scene, name: string, useTransition: boolean = true): void {
        this._sceneNames = [name];
        const target = useTransition
            ? new cc.TransitionFade(SceneStackManager.TRANSITION_DURATION, scene)
            : scene;
        cc.director.runScene(target);
        cc.log('Run scene:', name);
    }

    pushScene(scene: cc.Scene, name: string): void {
        this._sceneNames.push(name);
        cc.director.pushScene(scene);
        cc.log('Push scene:', name, '| Stack:', this._sceneNames.join(' > '));
    }

    popScene(): void {
        if (this._sceneNames.length <= 1) {
            cc.warn('Cannot pop root scene');
            return;
        }
        const popped = this._sceneNames.pop();
        cc.director.popScene();
        cc.log('Pop scene:', popped, '| Stack:', this._sceneNames.join(' > '));
    }

    popToRoot(): void {
        this._sceneNames = [this._sceneNames[0]];
        cc.director.popToRootScene();
        cc.log('Pop to root:', this._sceneNames[0]);
    }

    get currentSceneName(): string {
        return this._sceneNames[this._sceneNames.length - 1] || 'none';
    }

    get stackDepth(): number {
        return this._sceneNames.length;
    }
}

// Usage:
const mgr = SceneStackManager.instance;
mgr.runScene(new MenuScene(), 'menu');
mgr.pushScene(new SettingsScene(), 'settings');
mgr.popScene(); // back to menu
```

