Combine `cc.sys.language` for auto-detection with localStorage for user preference:

```typescript
interface LocaleStrings {
    [key: string]: string;
}

class Localization {
    private static readonly LANG_KEY = 'user_language';
    private _strings: LocaleStrings = {};
    private _currentLang: string;

    private static readonly SUPPORTED_LANGS = ['en', 'zh', 'ja', 'ko', 'es', 'fr'];

    constructor() {
        this._currentLang = this.detectLanguage();
        this.loadStrings(this._currentLang);
    }

    private detectLanguage(): string {
        // Check user preference first
        const saved = cc.sys.localStorage.getItem(Localization.LANG_KEY);
        if (saved && Localization.SUPPORTED_LANGS.indexOf(saved) >= 0) {
            return saved;
        }
        // Fall back to system language
        const sysLang = cc.sys.language as string;
        if (Localization.SUPPORTED_LANGS.indexOf(sysLang) >= 0) {
            return sysLang;
        }
        return 'en';
    }

    private loadStrings(lang: string): void {
        const path = cc.path.join('res', 'i18n', lang + '.json');
        cc.loader.loadJson(path, (err, data) => {
            if (err) {
                cc.warn('Failed to load language:', lang, '- falling back to en');
                if (lang !== 'en') this.loadStrings('en');
                return;
            }
            this._strings = data;
        });
    }

    setLanguage(lang: string): void {
        this._currentLang = lang;
        cc.sys.localStorage.setItem(Localization.LANG_KEY, lang);
        this.loadStrings(lang);
    }

    get(key: string): string {
        return this._strings[key] || key;
    }

    get currentLanguage(): string {
        return this._currentLang;
    }
}
```

