```typescript
class CharacterSelectLayer extends cc.Layer {
    private hero: sp.SkeletonAnimation;
    private skins: string[] = ['warrior', 'mage', 'archer', 'rogue'];
    private currentSkinIndex: number = 0;
    private nameLabel: cc.LabelTTF;

    constructor() {
        super();
        this.init();
    }

    init(): boolean {
        const winSize = cc.director.getWinSize();

        this.hero = new sp.SkeletonAnimation('res/hero/hero.json', 'res/hero/hero.atlas');
        this.hero.setPosition(winSize.width / 2, winSize.height / 2 - 40);
        this.addChild(this.hero);

        // Setup blending for all preview animations
        this.hero.setMix('idle', 'run', 0.2);
        this.hero.setMix('run', 'attack', 0.15);
        this.hero.setMix('attack', 'idle', 0.2);

        this.applySkin();
        this.hero.setAnimation(0, 'idle', true);

        this.nameLabel = new cc.LabelTTF(this.skins[0], 'Arial', 24);
        this.nameLabel.setPosition(winSize.width / 2, winSize.height - 60);
        this.addChild(this.nameLabel);

        // Swipe to change skin
        cc.eventManager.addListener({
            event: cc.EventListener.TOUCH_ONE_BY_ONE,
            onTouchBegan: (touch: cc.Touch) => {
                this.onTouchStart(touch);
                return true;
            }
        }, this);

        return true;
    }

    private onTouchStart(touch: cc.Touch): void {
        const loc = touch.getLocation();
        const winSize = cc.director.getWinSize();

        if (loc.x > winSize.width / 2) {
            this.currentSkinIndex = (this.currentSkinIndex + 1) % this.skins.length;
        } else {
            this.currentSkinIndex = (this.currentSkinIndex - 1 + this.skins.length) % this.skins.length;
        }

        this.applySkin();
        this.previewAnimations();
    }

    private applySkin(): void {
        const skinName = this.skins[this.currentSkinIndex];
        this.hero.setSkin(skinName);
        this.hero.setSlotsToSetupPose();
        if (this.nameLabel) {
            this.nameLabel.setString(skinName.toUpperCase());
        }
    }

    private previewAnimations(): void {
        this.hero.setAnimation(0, 'run', false);
        this.hero.addAnimation(0, 'attack', false, 0);
        this.hero.addAnimation(0, 'idle', true, 0);
    }
}
```

Tap the right half to cycle forward through skins, left half to go back. Each skin change triggers a preview sequence (run -> attack -> idle). `setSlotsToSetupPose()` ensures the new skin's attachments are applied correctly.

