    // Shadow
    enableShadow(color?: cc.Color, offset?: cc.Size, blurRadius?: number): void;

    // Glow (TTF only)
    enableGlow(color: cc.Color): void;

    // Gradient
    enableGradient(first: cc.Color, second: cc.Color, direction: cc.Color): void;

    // Disable
    disableEffect(): void;
    disableEffect(effect: number): void;

    // Blend
    getBlendFunc(): cc.BlendFunc;
    setBlendFunc(src: cc.BlendFunc): void;
    setBlendFunc(src: number, dst: number): void;
}
```

