    dialog.setBackGroundColorType(ccui.Layout.BG_COLOR_SOLID);
    dialog.setBackGroundColor(cc.color(50, 50, 70));
    dialog.setBackGroundColorOpacity(255);
    dialog.setPosition((winSize.width - 320) / 2, (winSize.height - 200) / 2);
    overlay.addChild(dialog);

    const titleLabel = new ccui.Text(title, 'Arial', 24);
    titleLabel.setPosition(160, 170);
    dialog.addChild(titleLabel);

    const msgLabel = new ccui.Text(message, 'Arial', 16);
    msgLabel.setTextAreaSize(cc.size(280, 80));
    msgLabel.setPosition(160, 110);
    dialog.addChild(msgLabel);

    const okBtn = new ccui.Button('btn_green.png');
    okBtn.setTitleText('OK');
    okBtn.setTitleFontSize(18);
    okBtn.setPosition(100, 30);
    okBtn.addClickEventListener(() => { overlay.removeFromParent(); onOk(); });
    dialog.addChild(okBtn);

    const cancelBtn = new ccui.Button('btn_red.png');
    cancelBtn.setTitleText('Cancel');
    cancelBtn.setTitleFontSize(18);
    cancelBtn.setPosition(220, 30);
    cancelBtn.addClickEventListener(() => { overlay.removeFromParent(); onCancel(); });
    dialog.addChild(cancelBtn);

    return overlay;
}
```

`ccui.Margin` defines spacing around a widget when used inside a linear or relative layout.

```typescript
const margin = new ccui.Margin(left, top, right, bottom);
```

It is used with `ccui.LinearLayoutParameter` and `ccui.RelativeLayoutParameter`:

```typescript
const param = new ccui.LinearLayoutParameter();
param.setMargin(new ccui.Margin(10, 5, 10, 5));
// left: 10px, top: 5px, right: 10px, bottom: 5px
widget.setLayoutParameter(param);
```

**Important notes:**
- Margins only take effect when the parent Layout uses `LINEAR_HORIZONTAL`, `LINEAR_VERTICAL`, or `RELATIVE` layout types.
- In `ABSOLUTE` layout, margins are ignored since children are freely positioned.
- The margin order is `(left, top, right, bottom)`, similar to CSS but passed as constructor arguments.
- After changing margins, call `layout.forceDoLayout()` to recalculate positions.

instruction:
Review this code:

```typescript
class SettingsScene extends cc.Scene {
    onEnter() {
        super.onEnter();
        const slider = new ccui.Slider();
        slider.loadBarTexture('bar.png');
        slider.loadSlidBallTextures('ball.png', 'ball.png', 'ball.png');
        slider.setMaxPercent(200);
        slider.setPercent(150);
        this.addChild(slider);
    }
}
```

output:
**Issues:**

1. **No position set** - The slider will default to (0,0), likely off-screen or in the corner.
2. **No progress bar texture** - Without `loadProgressBarTexture`, there's no visual feedback for the filled portion.
3. **setMaxPercent(200)** with **setPercent(150)** - While technically valid, using a non-standard max percent can confuse code that expects 0-100 range.

**Fix:**

```typescript
class SettingsScene extends cc.Scene {
    onEnter() {
        super.onEnter();
        const winSize = cc.director.getWinSize();
        const slider = new ccui.Slider();
        slider.loadBarTexture('bar.png');
        slider.loadSlidBallTextures('ball.png', 'ball.png', 'ball.png');
        slider.loadProgressBarTexture('progress.png');
        slider.setPercent(75);
        slider.setPosition(winSize.width / 2, winSize.height / 2);
        this.addChild(slider);
    }
}
```

```typescript
const a = cc.p(0, 0);
const b = cc.p(200, 100);

// Linear interpolation between two points
// alpha=0 returns a, alpha=1 returns b, alpha=0.5 returns midpoint
const quarter = cc.pLerp(a, b, 0.25);  // cc.p(50, 25)
const half = cc.pLerp(a, b, 0.5);      // cc.p(100, 50)
const full = cc.pLerp(a, b, 1.0);      // cc.p(200, 100)

// Midpoint (equivalent to pLerp with alpha=0.5)
const mid = cc.pMidpoint(a, b);  // cc.p(100, 50)

// Common use: smooth movement toward a target
update(dt: number): void {
    const current = this.node.getPosition();
    const target = this._targetPos;
    const smoothed = cc.pLerp(current, target, 0.1); // 10% per frame
    this.node.setPosition(smoothed);
}
```

Signatures:
```typescript
cc.pLerp(a: cc.Point, b: cc.Point, alpha: number): cc.Point
cc.pMidpoint(v1: cc.Point, v2: cc.Point): cc.Point
```

`cc.SpriteBatchNode` renders many sprites sharing the same texture in one draw call:

```typescript
// Load atlas first
cc.spriteFrameCache.addSpriteFrames('res/atlas.plist', 'res/atlas.png');

// Create batch node with the shared texture
const batch = new cc.SpriteBatchNode('res/atlas.png', 100); // 100 = initial capacity
this.addChild(batch);

// Add sprites as children of the batch node (not the layer)
for (let i = 0; i < 50; i++) {
    const s = new cc.Sprite(cc.spriteFrameCache.getSpriteFrame('enemy.png'));
    s.setPosition(Math.random() * 480, Math.random() * 320);
    batch.addChild(s);
}
```

All sprites added to a `SpriteBatchNode` must use the same texture (atlas). This reduces draw calls significantly for scenes with many sprites.

`playEffect` has multiple optional parameters beyond the URL:

```typescript
cc.audioEngine.playEffect(
    url: string,       // path to the sound file
    loop?: boolean,    // repeat? default false
    pitch?: number,    // playback speed/pitch
    pan?: number,      // stereo panning (-1 left, 0 center, 1 right)
    gain?: number      // volume multiplier for this effect
): number | null       // returns audio ID or null
```

**Examples:**
```typescript
// Simple one-shot
cc.audioEngine.playEffect('res/audio/sfx_coin.mp3');

// Looping ambient sound
const windId = cc.audioEngine.playEffect('res/audio/sfx_wind.mp3', true);

// High-pitched, panned right, lower volume
cc.audioEngine.playEffect('res/audio/sfx_hit.mp3', false, 1.5, 0.8, 0.6);

// Low-pitched, panned left
cc.audioEngine.playEffect('res/audio/sfx_explosion.mp3', false, 0.7, -0.8, 1.0);
```

The return value is a numeric audio ID for controlling this specific effect instance, or `null` if playback failed. The `pitch`, `pan`, and `gain` parameters are applied per-effect on top of the global effects volume.

```typescript
declare namespace cc {
    namespace audioEngine {
        /** Play effect. Returns audio ID or null. */
        function playEffect(
            url: string,
            loop?: boolean,
            pitch?: number,
            pan?: number,
            gain?: number
        ): number | null;

        /** Stop a specific effect by audio ID. */
        function stopEffect(audioId: number): void;

        /** Pause a specific effect. */
        function pauseEffect(audioId: number): void;

        /** Resume a specific paused effect. */
        function resumeEffect(audioId: number): void;

        /** Stop all playing effects. */
        function stopAllEffects(): void;

        /** Pause all playing effects. */
        function pauseAllEffects(): void;

        /** Resume all paused effects. */
        function resumeAllEffects(): void;

        /** Unload an effect file from cache. */
        function unloadEffect(url: string): void;

        /** Get global effects volume (0.0–1.0). */
        function getEffectsVolume(): number;

        /** Set global effects volume (0.0–1.0). */
        function setEffectsVolume(volume: number): void;

        /** Preload effect file into memory. */
        function preloadEffect(path: string): void;

        /** Stop all audio and release all resources. */
        function end(): void;
    }
}
```

Multiple effects can play concurrently, each identified by a unique audio ID returned from `playEffect`. The volume set by `setEffectsVolume` applies to all effects globally.

Map `cc.sys.language` values to a typed enum:

```typescript
enum AppLocale {
    EN = 'en',
    ZH = 'zh',
    JA = 'ja',
    KO = 'ko',
    ES = 'es',
    FR = 'fr',
    DE = 'de',
    RU = 'ru',
    PT = 'pt'
}

class LocaleHelper {
    private static readonly LANG_MAP: ReadonlyMap<string, AppLocale> = new Map([
        [cc.sys.LANGUAGE_ENGLISH, AppLocale.EN],
        [cc.sys.LANGUAGE_CHINESE, AppLocale.ZH],
        [cc.sys.LANGUAGE_JAPANESE, AppLocale.JA],
        [cc.sys.LANGUAGE_KOREAN, AppLocale.KO],
        [cc.sys.LANGUAGE_SPANISH, AppLocale.ES],
        [cc.sys.LANGUAGE_FRENCH, AppLocale.FR],
        [cc.sys.LANGUAGE_GERMAN, AppLocale.DE],
        [cc.sys.LANGUAGE_RUSSIAN, AppLocale.RU],
        [cc.sys.LANGUAGE_PORTUGUESE, AppLocale.PT]
    ]);

    static getSystemLocale(): AppLocale {
        const sysLang = cc.sys.language as string;
        return LocaleHelper.LANG_MAP.get(sysLang) || AppLocale.EN;
    }

    static getUserLocale(): AppLocale {
        const saved = cc.sys.localStorage.getItem('user_locale');
        if (saved && Object.values(AppLocale).includes(saved as AppLocale)) {
            return saved as AppLocale;
        }
        return LocaleHelper.getSystemLocale();
    }

    static setUserLocale(locale: AppLocale): void {
        cc.sys.localStorage.setItem('user_locale', locale);
    }

    static isRTL(locale: AppLocale): boolean {
        return false; // Add Arabic/Hebrew if supported
    }
}

// Usage:
const locale: AppLocale = LocaleHelper.getUserLocale();
cc.log('Current locale:', locale); // e.g., 'en'
```

This provides compile-time type safety and maps Cocos2d-x language constants to application-specific values.

Use the bone access methods on the armature:

```typescript
const armature = ccs.Armature.create('hero');
this.addChild(armature);

// Get a bone by name
const headBone: ccs.Bone = armature.getBone('head');

// Get bone at a screen coordinate (useful for hit testing)
const hitBone: ccs.Bone = armature.getBoneAtPoint(touchX, touchY);

// Get all bones as a dictionary
const allBones: object = armature.getBoneDic();

// Create a new bone
const newBone: ccs.Bone = armature.createBone('customBone');

// Add a bone under a parent
armature.addBone(newBone, 'body');

// Remove a bone (recursion=true removes children too)
