const bar = new ccui.LoadingBar('bar_fill.png', 0);
bar.setDirection(ccui.LoadingBar.TYPE_LEFT);
bar.setPosition(240, 100);
this.addChild(bar);

const label = new ccui.Text('0%', 'Arial', 16);
