const hero = new sp.SkeletonAnimation('res/hero/hero.json', 'res/hero/hero.atlas');
hero.setPosition(240, 160);
this.addChild(hero);

const track = hero.setAnimation(0, 'attack', false);
if (track) {
    // Read-only info
    cc.log('Playing: ' + track.animation.name);  // spine.Animation reference
    cc.log('Loop: ' + track.loop);
    cc.log('Current time: ' + track.trackTime);
    cc.log('Duration: ' + track.trackEnd);
    cc.log('Anim time: ' + track.getAnimationTime());

    // Writable properties
    track.timeScale = 1.5;       // per-track speed multiplier
    track.alpha = 0.8;           // blend weight 0–1
    track.loop = true;           // change looping at runtime
