```

output:
```typescript
class SpritePool {
    private _pool: cc.Sprite[] = [];
    private _frameName: string;
    private _active: Set<cc.Sprite> = new Set();

    constructor(frameName: string) {
        this._frameName = frameName;
    }

    preload(count: number): void {
        for (let i = 0; i < count; i++) {
            const sprite = new cc.Sprite(cc.spriteFrameCache.getSpriteFrame(this._frameName));
            sprite.setVisible(false);
            this._pool.push(sprite);
        }
    }

    get(): cc.Sprite {
        let sprite: cc.Sprite;
        if (this._pool.length > 0) {
            sprite = this._pool.pop()!;
        } else {
            sprite = new cc.Sprite(cc.spriteFrameCache.getSpriteFrame(this._frameName));
        }
        sprite.setVisible(true);
        sprite.stopAllActions();
        sprite.setRotation(0);
        sprite.setScale(1);
        sprite.setOpacity(255);
        this._active.add(sprite);
        return sprite;
    }

    release(sprite: cc.Sprite): void {
        if (!this._active.has(sprite)) return;
        this._active.delete(sprite);
        sprite.setVisible(false);
        sprite.stopAllActions();
        sprite.removeFromParent(false);
        this._pool.push(sprite);
    }

    releaseAll(): void {
        for (const s of this._active) {
            s.setVisible(false);
            s.stopAllActions();
            s.removeFromParent(false);
            this._pool.push(s);
        }
        this._active.clear();
    }
}

// Usage:
cc.spriteFrameCache.addSpriteFrames('res/bullets.plist', 'res/bullets.png');
const bulletPool = new SpritePool('bullet_01.png');
bulletPool.preload(50);

// Spawn bullet
const bullet = bulletPool.get();
bullet.setPosition(playerPos);
this.addChild(bullet);

// Recycle when off screen
bulletPool.release(bullet);
```

