Serialize to JSON since localStorage only stores strings:

```typescript
interface GameState {
    level: number;
    score: number;
    playerName: string;
    inventory: string[];
    settings: {
        musicVolume: number;
        sfxVolume: number;
        language: string;
    };
}

const SAVE_KEY = 'game_state';

function saveGameState(state: GameState): void {
    const json = JSON.stringify(state);
    cc.sys.localStorage.setItem(SAVE_KEY, json);
    cc.log('Game state saved');
}

function loadGameState(): GameState {
    const raw = cc.sys.localStorage.getItem(SAVE_KEY);
    if (!raw) {
        cc.log('No save found, returning defaults');
        return getDefaultState();
    }
    try {
        return JSON.parse(raw) as GameState;
    } catch (e) {
        cc.error('Corrupt save data, resetting');
        cc.sys.localStorage.removeItem(SAVE_KEY);
        return getDefaultState();
    }
}

function getDefaultState(): GameState {
    return {
        level: 1,
        score: 0,
        playerName: '',
        inventory: [],
        settings: { musicVolume: 0.8, sfxVolume: 1.0, language: 'en' }
    };
}
```

Always wrap `JSON.parse` in try-catch since stored data could be corrupted.

