    const min = Math.floor(s / 60);
    const sec = s % 60;
    return min + ':' + (sec < 10 ? '0' : '') + sec;
}

this.schedule((dt: number) => {
    timeLeft--;
    timerLabel.setString(formatTime(timeLeft));

    if (timeLeft <= 10) {
        timerLabel.setTextColor(cc.color(255, 50, 50));
        // Pulse effect
        timerLabel.stopAllActions();
        timerLabel.runAction(cc.sequence(
            cc.scaleTo(0.1, 1.2),
            cc.scaleTo(0.2, 1.0)
        ));
    }

    if (timeLeft <= 0) {
        this.unschedule(arguments.callee);
        this.onTimeUp();
    }
}, 1.0);
