```typescript
interface CollisionResult {
    overlaps: boolean;
    overlapX: number;
    overlapY: number;
    pushDirection: cc.Point;
}

function calculateOverlap(
    rectA: cc.Rect,
    rectB: cc.Rect
): CollisionResult {
    if (!cc.rectOverlapsRect(rectA, rectB)) {
        return { overlaps: false, overlapX: 0, overlapY: 0, pushDirection: cc.p(0, 0) };
    }

    const inter = cc.rectIntersection(rectA, rectB);

    // Determine push direction based on centers
    const centerA = cc.p(rectA.x + rectA.width / 2, rectA.y + rectA.height / 2);
    const centerB = cc.p(rectB.x + rectB.width / 2, rectB.y + rectB.height / 2);
    const diff = cc.pSub(centerA, centerB);

    let pushDir: cc.Point;
    if (inter.width < inter.height) {
        pushDir = cc.p(diff.x > 0 ? 1 : -1, 0);
    } else {
        pushDir = cc.p(0, diff.y > 0 ? 1 : -1);
    }

    return {
        overlaps: true,
        overlapX: inter.width,
        overlapY: inter.height,
        pushDirection: pushDir
    };
}

// Usage:
const result = calculateOverlap(player.getBoundingBox(), wall.getBoundingBox());
if (result.overlaps) {
    const minOverlap = Math.min(result.overlapX, result.overlapY);
    const push = cc.pMult(result.pushDirection, minOverlap);
    const newPos = cc.pAdd(player.getPosition(), push);
    player.setPosition(newPos);
}
```

`setStartListener` and `setEndListener` are convenience methods that register callbacks for specific animation lifecycle events, as an alternative to the general `setAnimationListener`:

```typescript
const hero = new sp.SkeletonAnimation('res/hero/hero.json', 'res/hero/hero.atlas');
hero.setPosition(240, 160);
this.addChild(hero);

// Fires when any animation starts playing
hero.setStartListener((trackEntry: spine.TrackEntry) => {
    cc.log('Started: ' + trackEntry.animation.name);
});

// Fires when any animation ends (interrupted or cleared)
hero.setEndListener((trackEntry: spine.TrackEntry) => {
    cc.log('Ended: ' + trackEntry.animation.name);
});

hero.setAnimation(0, 'idle', true);  // triggers start listener
hero.setAnimation(0, 'run', true);   // triggers end for 'idle', start for 'run'
hero.clearTrack(0);                   // triggers end for 'run'
```

Unlike `setAnimationListener`, these individual listeners receive only the `TrackEntry` (no type or event parameters). They apply globally to all tracks. Use these when you only care about start/end events and want simpler callback signatures.

