Complete this code to implement a screen wipe transition using cc.LayerColor:

```typescript
class WipeTransition {
    private wipe: cc.LayerColor;
    private parent: cc.Node;
    // TODO: create wipe, implement wipeIn and wipeOut
}
```

output:
```typescript
class WipeTransition {
    private wipe: cc.LayerColor;
    private parent: cc.Node;
    private winSize: cc.Size;

    constructor(parent: cc.Node) {
        this.parent = parent;
        this.winSize = cc.director.getWinSize();
        this.wipe = new cc.LayerColor(
            cc.color(0, 0, 0, 255), 0, this.winSize.height
        );
        this.wipe.setLocalZOrder(9999);
        this.parent.addChild(this.wipe);
    }

    wipeIn(duration: number, callback: () => void): void {
        this.wipe.changeWidth(0);
        this.wipe.setVisible(true);
        let elapsed = 0;
        const step = (dt: number) => {
            elapsed += dt;
            const p = Math.min(elapsed / duration, 1);
            this.wipe.changeWidth(p * this.winSize.width);
            if (p >= 1) {
                this.parent.unschedule(step);
                callback();
            }
        };
        this.parent.schedule(step, 1 / 60);
    }

    wipeOut(duration: number): void {
        let elapsed = 0;
        const step = (dt: number) => {
            elapsed += dt;
            const p = Math.min(elapsed / duration, 1);
            this.wipe.changeWidth((1 - p) * this.winSize.width);
            this.wipe.setPositionX(p * this.winSize.width);
            if (p >= 1) {
                this.parent.unschedule(step);
                this.wipe.setVisible(false);
            }
        };
        this.parent.schedule(step, 1 / 60);
    }
}

const wipe = new WipeTransition(this);
wipe.wipeIn(0.5, () => { wipe.wipeOut(0.5); });
```

The wipe is a zero-width `cc.LayerColor`. `wipeIn` expands it rightward using `changeWidth`. `wipeOut` shrinks it by moving position right while reducing width.

