output:
```typescript
class SmoothCamera {
    private _camera: cc.Node;
    private _target: cc.Node;
    private _smoothing: number;
    private _offset: cc.Point;
    private _bounds: cc.Rect | null;

    constructor(
        camera: cc.Node,
        target: cc.Node,
        smoothing: number = 0.1,
        offset: cc.Point = cc.p(0, 0),
        bounds: cc.Rect | null = null
    ) {
        this._camera = camera;
        this._target = target;
        this._smoothing = smoothing;
        this._offset = offset;
        this._bounds = bounds;
    }

    update(dt: number): void {
        const targetPos = cc.pAdd(this._target.getPosition(), this._offset);
        const currentPos = this._camera.getPosition();

        // Smooth interpolation
        let newPos = cc.pLerp(currentPos, targetPos, this._smoothing);

        // Clamp to bounds if set
        if (this._bounds) {
            newPos = cc.p(
                cc.clampf(newPos.x, this._bounds.x, this._bounds.x + this._bounds.width),
                cc.clampf(newPos.y, this._bounds.y, this._bounds.y + this._bounds.height)
            );
        }

        this._camera.setPosition(newPos);
    }
}

// Usage:
const camera = new SmoothCamera(
    this._gameLayer,
    this._player,
    0.08,
    cc.p(0, 50),
    cc.rect(-500, -200, 1000, 600)
);
// Call camera.update(dt) in the layer's update method
```

