function createExplosion(parent: cc.Node, pos: cc.Point, count: number): void {
    for (let i = 0; i < count; i++) {
        const particle = new cc.Sprite('spark.png');
        particle.setPosition(pos);
        particle.setScale(0.3 + Math.random() * 0.4);
        particle.setOpacity(255);
        parent.addChild(particle, 100);

        const angle = (i / count) * Math.PI * 2 + Math.random() * 0.5;
        const speed = 80 + Math.random() * 120;
        const dx = Math.cos(angle) * speed;
        const dy = Math.sin(angle) * speed;
        const duration = 0.5 + Math.random() * 0.5;

        particle.runAction(cc.sequence(
            cc.spawn(
                cc.moveBy(duration, cc.p(dx, dy)).easing(cc.easeOut(2)),
                cc.fadeOut(duration),
                cc.scaleTo(duration, 0.1)
            ),
            cc.removeSelf()
        ));
    }
}

