Build a helper that applies common texture configurations:

```typescript
class TextureHelper {
    static applyPixelArt(texture: cc.Texture2D): void {
        // No interpolation — sharp pixels
        texture.setTexParameters(gl.NEAREST, gl.NEAREST, gl.CLAMP_TO_EDGE, gl.CLAMP_TO_EDGE);
    }

    static applySmooth(texture: cc.Texture2D): void {
        // Bilinear filtering — smooth scaling
        texture.setTexParameters(gl.LINEAR, gl.LINEAR, gl.CLAMP_TO_EDGE, gl.CLAMP_TO_EDGE);
    }

    static applyTiled(texture: cc.Texture2D): void {
        // Repeat pattern — for backgrounds
        texture.setTexParameters(gl.LINEAR, gl.LINEAR, gl.REPEAT, gl.REPEAT);
    }

    static applyMirrored(texture: cc.Texture2D): void {
        // Mirror repeat — seamless tiling
        texture.setTexParameters(gl.LINEAR, gl.LINEAR, gl.MIRRORED_REPEAT, gl.MIRRORED_REPEAT);
    }

    static applyTrilinear(texture: cc.Texture2D): void {
        // Highest quality with mipmaps
        texture.setTexParameters(
            gl.LINEAR_MIPMAP_LINEAR,
            gl.LINEAR,
            gl.CLAMP_TO_EDGE,
            gl.CLAMP_TO_EDGE
        );
    }
}

// Usage:
const tex = cc.textureCache.addImage('res/pixel_hero.png');
TextureHelper.applyPixelArt(tex);

const bgTex = cc.textureCache.addImage('res/grass_tile.png');
TextureHelper.applyTiled(bgTex);

// Set parameters: (minFilter, magFilter, wrapS, wrapT)
// minFilter: used when texture is scaled down
// magFilter: used when texture is scaled up
// wrapS: horizontal wrapping
// wrapT: vertical wrapping
```

```typescript
class HeroLayer extends cc.Layer {
    private hero: sp.SkeletonAnimation;

    constructor() {
        super();
        this.init();
    }

    init(): boolean {
        this.hero = new sp.SkeletonAnimation('res/hero/hero.json', 'res/hero/hero.atlas');
        this.hero.setPosition(240, 160);
        this.addChild(this.hero);

        // Setup blending
        this.hero.setMix('idle', 'attack', 0.1);
        this.hero.setMix('attack', 'idle', 0.2);

        // Start idle
        this.hero.setAnimation(0, 'idle', true);

        // Listen for animation completion
        this.hero.setAnimationListener(this, this.onAnimationEvent.bind(this));

        // Enable touch
        cc.eventManager.addListener({
            event: cc.EventListener.TOUCH_ONE_BY_ONE,
            onTouchBegan: () => {
                this.onAttack();
                return true;
            }
        }, this);

        return true;
    }

    private onAttack(): void {
        this.hero.setAnimation(0, 'attack', false);
        this.hero.addAnimation(0, 'idle', true, 0);
    }

    private onAnimationEvent(
        track: spine.TrackEntry, type: number, event: spine.Event
    ): void {
        if (type === sp.AnimationEventType.EVENT && event.data.name === 'attack_hit') {
            cc.log('Deal damage!');
        }
    }
}

const scene = new cc.Scene();
scene.addChild(new HeroLayer());
cc.director.runScene(scene);
```

This creates a hero that idles by default, plays attack on tap, then auto-returns to idle via `addAnimation`. The `setMix` calls ensure smooth crossfades between states. The animation listener detects custom Spine events like 'attack_hit' for gameplay logic.

