```typescript
class HealthBar {
    private _draw: cc.DrawNode;
    private _maxWidth: number;
    private _height: number;

    constructor(parent: cc.Node, width: number, height: number, offsetY: number) {
        this._draw = new cc.DrawNode();
        this._draw.setPosition(cc.p(-width / 2, offsetY));
        parent.addChild(this._draw, 10);
        this._maxWidth = width;
        this._height = height;
    }

    update(ratio: number): void {
        this._draw.clear();
        const w = this._maxWidth;
        const h = this._height;

        // Background (dark gray)
        this._draw.drawRect(
            cc.p(0, 0), cc.p(w, h),
            cc.color(50, 50, 50, 200), 0, null
        );

        // Health fill
        const fillW = w * Math.max(0, Math.min(1, ratio));
        const r = Math.floor(255 * (1 - ratio));
        const g = Math.floor(255 * ratio);
        this._draw.drawRect(
            cc.p(0, 0), cc.p(fillW, h),
            cc.color(r, g, 0, 255), 0, null
        );

        // Border
        this._draw.drawRect(
            cc.p(0, 0), cc.p(w, h),
            null, 1, cc.color(255, 255, 255, 255)
        );
    }
}

// Usage:
const bar = new HealthBar(heroSprite, 60, 6, 40);
