Use mouse move deltas for first-person or orbit camera rotation:

```typescript
class MouseLookCamera extends cc.Layer {
    private _listener: cc.EventListener;
    private _rotationX: number = 0;
    private _rotationY: number = 0;
    private _isLocked: boolean = false;
    private static readonly SENSITIVITY = 0.3;

    onEnter(): void {
        super.onEnter();
        this._listener = cc.eventManager.addListener({
            event: cc.EventListener.MOUSE,
            onMouseDown: (event: cc.EventMouse): void => {
                if (event.getButton() === cc.EventMouse.BUTTON_RIGHT) {
                    this._isLocked = true;
                }
            },
            onMouseUp: (event: cc.EventMouse): void => {
                if (event.getButton() === cc.EventMouse.BUTTON_RIGHT) {
                    this._isLocked = false;
                }
            },
            onMouseMove: (event: cc.EventMouse): void => {
                if (!this._isLocked) return;
                const dx: number = event.getDeltaX();
                const dy: number = event.getDeltaY();
                this._rotationY += dx * MouseLookCamera.SENSITIVITY;
                this._rotationX -= dy * MouseLookCamera.SENSITIVITY;
                this._rotationX = cc.clampf(this._rotationX, -80, 80);
                this.updateCamera();
            }
        }, this);
    }

    private updateCamera(): void {
        cc.log('Camera rotation:', this._rotationX, this._rotationY);
        // Apply rotation to camera node
    }

    onExit(): void {
        cc.eventManager.removeListener(this._listener);
        super.onExit();
    }
}
```

`getDeltaX()` and `getDeltaY()` return the pixel distance the mouse moved since the last frame. Multiply by a sensitivity factor to control rotation speed.

