```typescript
class GameExitManager {
    static exit(): void {
        // Save game state first
        cc.sys.localStorage.setItem('last_exit', Date.now().toString());

        if (cc.sys.isNative) {
            // Native: end director lifecycle
            cc.director.end();
        } else {
            // Web: can't truly close a browser tab from JS
            // Show a "safe to close" message instead
            cc.director.pause();
            const scene = cc.director.getRunningScene();
            const winSize = cc.director.getWinSize();
            const label = new cc.LabelTTF('You can close this tab now', 'Arial', 24);
