```typescript
function createTiledSprite(
    parent: cc.Node,
    texturePath: string,
    areaSize: cc.Size
): cc.SpriteBatchNode {
    cc.textureCache.addImage(texturePath);
    const tex = cc.textureCache.getTextureForKey(texturePath);
    const texSize = tex.getContentSize();

    const batch = new cc.SpriteBatchNode(texturePath);
    parent.addChild(batch);

    const cols = Math.ceil(areaSize.width / texSize.width);
    const rows = Math.ceil(areaSize.height / texSize.height);

    for (let r = 0; r < rows; r++) {
        for (let c = 0; c < cols; c++) {
            const tile = new cc.Sprite(tex);
            tile.setAnchorPoint(cc.p(0, 0));
            tile.setPosition(c * texSize.width, r * texSize.height);
            batch.addChild(tile);
        }
    }

    return batch;
}

// Usage: tile a ground texture across the bottom of the screen
const winSize = cc.director.getWinSize();
const ground = createTiledSprite(this, 'res/ground_tile.png', cc.size(winSize.width, 64));
```

Using `SpriteBatchNode` ensures all tiles share one draw call since they use the same texture.

