```typescript
class GridConverter {
    private _cellSize: cc.Size;
    private _origin: cc.Point;

    constructor(cellSize: cc.Size, origin: cc.Point = cc.p(0, 0)) {
        this._cellSize = cellSize;
        this._origin = origin;
    }

    gridToWorld(col: number, row: number): cc.Point {
        return cc.p(
            this._origin.x + col * this._cellSize.width + this._cellSize.width / 2,
            this._origin.y + row * this._cellSize.height + this._cellSize.height / 2
        );
    }

    worldToGrid(worldPos: cc.Point): {col: number; row: number} {
        const local = cc.pSub(worldPos, this._origin);
        return {
            col: Math.floor(local.x / this._cellSize.width),
            row: Math.floor(local.y / this._cellSize.height)
        };
    }

    getCellRect(col: number, row: number): cc.Rect {
        return cc.rect(
            this._origin.x + col * this._cellSize.width,
            this._origin.y + row * this._cellSize.height,
            this._cellSize.width,
            this._cellSize.height
        );
    }
}

// Usage:
const grid = new GridConverter(cc.size(32, 32), cc.p(16, 16));
const worldPos = grid.gridToWorld(3, 5);  // center of cell (3,5)
const cell = grid.worldToGrid(cc.p(120, 180));  // which cell?
const rect = grid.getCellRect(3, 5);  // bounding rect of cell
```

Use ClippingNode for circular masking with a ccui widget avatar:

```typescript
function createCircularAvatar(imagePath: string, radius: number): cc.Node {
    const container = new cc.Node();

    // Create circular stencil
    const stencil = new cc.DrawNode();
    const segments = 40;
    const vertices: cc.Point[] = [];
    for (let i = 0; i < segments; i++) {
        const angle = (i / segments) * Math.PI * 2;
        vertices.push(cc.p(Math.cos(angle) * radius, Math.sin(angle) * radius));
    }
    stencil.drawPoly(vertices, cc.color(255, 255, 255, 255), 0, cc.color(0, 0, 0, 0));

    const clipper = new cc.ClippingNode(stencil);
    clipper.setAlphaThreshold(0.5);

    const avatar = new ccui.ImageView(imagePath);
    avatar.ignoreContentAdaptWithSize(false);
    avatar.setSize(cc.size(radius * 2, radius * 2));
    clipper.addChild(avatar);

    container.addChild(clipper);

    // Add border ring
    const ring = new cc.DrawNode();
    ring.drawCircle(cc.p(0, 0), radius, 0, segments, false, 2, cc.color(200, 200, 200));
    container.addChild(ring);

    return container;
}

const avatar = createCircularAvatar('player_photo.png', 40);
avatar.setPosition(60, 280);
this.addChild(avatar);
```

instruction:
Review this event handling code for a menu with multiple buttons:

```typescript
class MenuLayer extends cc.Layer {
    onEnter(): void {
        super.onEnter();
        const buttons = ['play', 'settings', 'quit'];
        for (var i = 0; i < buttons.length; i++) {
            const btn = this.getChildByName(buttons[i]);
            cc.eventManager.addListener({
                event: cc.EventListener.TOUCH_ONE_BY_ONE,
                swallowTouches: true,
                onTouchBegan: (touch, event) => {
                    cc.log('Tapped button index:', i);
                    return true;
                }
            }, btn);
        }
    }
}
```

output:
Issues found:

1. **Classic `var` closure bug.** Using `var i` means all listeners share the same `i` variable. By the time any button is tapped, `i` is always 3 (the loop has finished). Every button logs "Tapped button index: 3".

2. **No listener cleanup.** Listeners are created but never removed in `onExit()`.

3. **No hit-testing.** Every button's listener returns `true` unconditionally, so the first button processed swallows all touches.

Fixed code:
```typescript
class MenuLayer extends cc.Layer {
    private _listeners: cc.EventListener[] = [];

    onEnter(): void {
        super.onEnter();
        const buttons = ['play', 'settings', 'quit'];
        for (let i = 0; i < buttons.length; i++) { // FIX: use 'let'
            const btn = this.getChildByName(buttons[i]);
            const listener = cc.eventManager.addListener({
                event: cc.EventListener.TOUCH_ONE_BY_ONE,
                swallowTouches: true,
                onTouchBegan: (touch: cc.Touch, event: cc.Event): boolean => {
                    const loc = btn.convertToNodeSpace(touch.getLocation());
                    const size = btn.getContentSize();
                    if (!cc.rectContainsPoint(cc.rect(0, 0, size.width, size.height), loc)) {
                        return false; // FIX: only claim if inside bounds
                    }
                    cc.log('Tapped button index:', i); // now correct per-button
                    return true;
                }
            }, btn);
            this._listeners.push(listener);
        }
    }

    onExit(): void {
        this._listeners.forEach(l => cc.eventManager.removeListener(l));
        this._listeners = [];
        super.onExit();
    }
}
```

