Combine platform detection with path utilities for adaptive asset loading:

```typescript
class AssetPathResolver {
    private _basePath: string;
    private _quality: 'hd' | 'sd';

    constructor() {
        this._quality = cc.sys.isMobile ? 'sd' : 'hd';
        this._basePath = 'res';
    }

    resolve(category: string, filename: string): string {
        return cc.path.join(this._basePath, this._quality, category, filename);
    }

    resolveSprite(name: string): string {
        const ext = cc.sys.isNative ? '.pvr.ccz' : '.png';
        return this.resolve('sprites', name + ext);
    }

    resolveAudio(name: string): string {
        let ext: string;
        if (cc.sys.isNative) {
            ext = cc.sys.os === cc.sys.OS_IOS ? '.m4a' : '.ogg';
        } else {
            ext = '.mp3';
        }
        return this.resolve('audio', name + ext);
    }

    resolveFont(name: string): string {
        // Use bitmap font on mobile, TTF on desktop
        if (cc.sys.isMobile) {
            return this.resolve('fonts', name + '.fnt');
        }
        return this.resolve('fonts', name + '.ttf');
    }

    resolveLocalized(category: string, filename: string): string {
        const lang = cc.sys.language as string;
        const localizedPath = cc.path.join(this._basePath, this._quality, category, lang, filename);
        return localizedPath;
    }
}

// Usage:
const resolver = new AssetPathResolver();
const heroSprite = resolver.resolveSprite('hero');
// Mobile: 'res/sd/sprites/hero.png'
// Desktop: 'res/hd/sprites/hero.png'
// Native iOS: 'res/sd/sprites/hero.pvr.ccz'

const bgm = resolver.resolveAudio('background_music');
// iOS native: 'res/sd/audio/background_music.m4a'
// Android native: 'res/sd/audio/background_music.ogg'
// Browser: 'res/hd/audio/background_music.mp3'
```

While both can represent a 2D point, `cc.p()` is the standard factory function that creates a proper `cc.Point`:

**cc.p(x, y)**
- Creates a `cc.Point` object recognized by all Cocos2d-x APIs
- Compatible with `cc.pAdd`, `cc.pSub`, `cc.pDistance`, etc.
- Works with `setPosition(point)`, `drawDot(point, ...)`, etc.

**Plain object {x: 100, y: 200}**
- May work in some APIs that only check for `.x` and `.y` properties
- NOT guaranteed to work with all cc.p* math utilities
- May fail in JSB/native builds where C++ expects specific types

```typescript
// Recommended
const pos = cc.p(100, 200);
node.setPosition(pos);
const dist = cc.pDistance(pos, cc.p(0, 0)); // works

// Risky
const obj = {x: 100, y: 200};
node.setPosition(obj);  // may work in HTML5 but not JSB
// cc.pDistance(obj, cc.p(0, 0)); // may fail
```

Always use `cc.p()` for consistency and cross-platform safety.

```typescript
// Rotate a point around a pivot by an angle (in radians)
const point = cc.p(100, 0);
const pivot = cc.p(0, 0);
const angle = Math.PI / 2;  // 90 degrees

const rotated = cc.pRotateByAngle(point, pivot, angle);
// rotated is approximately cc.p(0, 100)

// Practical: arrange items in a circle around a center
const center = cc.p(240, 160);
const radius = 80;
const itemCount = 6;
for (let i = 0; i < itemCount; i++) {
    const angle = (Math.PI * 2 / itemCount) * i;
    const basePoint = cc.p(center.x + radius, center.y);
    const pos = cc.pRotateByAngle(basePoint, center, angle);
    items[i].setPosition(pos);
}
```

Signature:
```typescript
cc.pRotateByAngle(v: cc.Point, pivot: cc.Point, angle: number): cc.Point
```

The angle is in radians. Use `cc.degreesToRadians(deg)` to convert from degrees.

```typescript
class NotificationBanner {
    private banner: cc.LayerColor;
    private label: cc.LabelTTF;
    private bannerHeight: number = 50;

    constructor() {
        const winSize = cc.director.getWinSize();
        this.banner = new cc.LayerColor(
            cc.color(40, 40, 40, 220), winSize.width, this.bannerHeight
        );
        this.banner.setPosition(0, winSize.height);

        this.label = new cc.LabelTTF('', 'Arial', 18);
        this.label.setPosition(winSize.width / 2, this.bannerHeight / 2);
        this.banner.addChild(this.label);
    }

    getNode(): cc.LayerColor { return this.banner; }

    show(parent: cc.Node, message: string, duration: number = 3.0): void {
        const winSize = cc.director.getWinSize();
        const showY = winSize.height - this.bannerHeight;
        this.label.setString(message);
        if (!this.banner.getParent()) parent.addChild(this.banner, 999);
        this.banner.setPositionY(winSize.height);
        this.banner.runAction(cc.sequence(
            cc.moveTo(0.3, cc.p(0, showY)),
            cc.delayTime(duration),
            cc.moveTo(0.3, cc.p(0, winSize.height))
        ));
    }
}

const notif = new NotificationBanner();
notif.show(this, 'Achievement Unlocked!', 2.0);
```

The banner is a `cc.LayerColor` positioned above the screen. `show()` animates it down, holds, then slides back up.

