`onTouchCancelled` fires when the system interrupts a touch — e.g., an incoming phone call, the app going to background, or the OS taking over the gesture.

```typescript
onTouchCancelled: (touch: cc.Touch, event: cc.Event) => void
```

You should treat it as an abnormal end and reset state:

```typescript
class DragDropItem extends cc.Sprite {
    private _listener: cc.EventListener;
    private _originalPos: cc.Point;
    private _isDragging: boolean = false;

    onEnter(): void {
        super.onEnter();
        this._originalPos = this.getPosition();
        this._listener = cc.eventManager.addListener({
            event: cc.EventListener.TOUCH_ONE_BY_ONE,
            swallowTouches: true,
            onTouchBegan: (touch: cc.Touch, event: cc.Event): boolean => {
                this._isDragging = true;
                this.setOpacity(180);
                return true;
            },
            onTouchMoved: (touch: cc.Touch, event: cc.EventTouch): void => {
                const delta = touch.getDelta();
                this.x += delta.x;
                this.y += delta.y;
            },
            onTouchEnded: (touch: cc.Touch, event: cc.Event): void => {
                this._isDragging = false;
                this.setOpacity(255);
                this.tryDrop(touch.getLocation());
            },
            onTouchCancelled: (touch: cc.Touch, event: cc.Event): void => {
                // Reset to original position — touch was interrupted
                this._isDragging = false;
                this.setOpacity(255);
                this.setPosition(this._originalPos);
                cc.log('Touch cancelled, reverting to original position');
            }
        }, this);
    }

    onExit(): void {
        cc.eventManager.removeListener(this._listener);
        super.onExit();
    }
}
```

Always implement `onTouchCancelled` for drag/drop operations to avoid leaving items in an inconsistent state.

These are two different touch handling modes:

**TOUCH_ONE_BY_ONE** — Receives individual touch events. Best for UI elements like buttons. Each callback gets a single `cc.Touch` object. You must return `true` from `onTouchBegan` to claim the touch.

```typescript
cc.eventManager.addListener({
    event: cc.EventListener.TOUCH_ONE_BY_ONE,
    swallowTouches: true,
    onTouchBegan: (touch: cc.Touch, event: cc.Event) => true,
    onTouchMoved: (touch: cc.Touch, event: cc.EventTouch) => {},
    onTouchEnded: (touch: cc.Touch, event: cc.Event) => {}
}, node);
```

**TOUCH_ALL_AT_ONCE** — Receives all active touches in a single callback. Best for multi-touch gestures like pinch-to-zoom. Callbacks receive `cc.Touch[]`.

```typescript
cc.eventManager.addListener({
    event: cc.EventListener.TOUCH_ALL_AT_ONCE,
    onTouchesBegan: (touches: cc.Touch[], event: cc.Event) => {},
    onTouchesMoved: (touches: cc.Touch[], event: cc.Event) => {},
    onTouchesEnded: (touches: cc.Touch[], event: cc.Event) => {}
}, node);
```

Use ONE_BY_ONE for buttons and draggable items; use ALL_AT_ONCE for multi-finger gestures.

```typescript
function checkRectCollision(
    nodeA: cc.Node,
    nodeB: cc.Node
): boolean {
    const boxA: cc.Rect = nodeA.getBoundingBox();
    const boxB: cc.Rect = nodeB.getBoundingBox();
    return cc.rectOverlapsRect(boxA, boxB);
}

// More detailed collision info
function getCollisionInfo(
    nodeA: cc.Node,
    nodeB: cc.Node
): { collides: boolean; overlap: cc.Rect | null } {
    const boxA = nodeA.getBoundingBox();
    const boxB = nodeB.getBoundingBox();

    if (!cc.rectOverlapsRect(boxA, boxB)) {
        return { collides: false, overlap: null };
    }

    return {
        collides: true,
        overlap: cc.rectIntersection(boxA, boxB)
    };
}

// Usage:
const player = new cc.Sprite('res/player.png');
const enemy = new cc.Sprite('res/enemy.png');

if (checkRectCollision(player, enemy)) {
    cc.log('Collision detected!');
}

const info = getCollisionInfo(player, enemy);
if (info.collides && info.overlap) {
    cc.log('Overlap area:', info.overlap.width, 'x', info.overlap.height);
}
```

Use the scheduler for frame-by-frame updates and timed events:

```typescript
class GameLoop extends cc.Layer {
    private _elapsed: number = 0;
    private _fixedTimeStep: number = 1 / 60;
    private _accumulator: number = 0;

    onEnter(): void {
        super.onEnter();
        this.scheduleUpdate();
    }

    update(dt: number): void {
        // Cap delta time to prevent spiral of death
        const cappedDt = Math.min(dt, 0.1);

        // Fixed timestep for physics
        this._accumulator += cappedDt;
        while (this._accumulator >= this._fixedTimeStep) {
            this.fixedUpdate(this._fixedTimeStep);
            this._accumulator -= this._fixedTimeStep;
        }

        // Variable timestep for rendering/interpolation
        this.variableUpdate(cappedDt);

        this._elapsed += cappedDt;
    }

    private fixedUpdate(dt: number): void {
        // Physics, collision detection
        this.updatePhysics(dt);
        this.checkCollisions();
    }

    private variableUpdate(dt: number): void {
        // Visual updates, particle effects
        this.updateAnimations(dt);
        this.updateCamera(dt);
    }

    // Timed events using schedule
    private startTimedEvents(): void {
        this.schedule(this.spawnEnemy, 3.0);
        this.schedule(this.updateDifficulty, 30.0);
        this.scheduleOnce(this.showBoss, 120.0);
    }
}
```

The fixed timestep loop ensures physics is deterministic regardless of frame rate. Use `cc.director.getDeltaTime()` if you need dt outside of the update callback.

