```typescript
// Clamp a value between min and max
const clamped = cc.clampf(150, 0, 100);  // 100
const clamped2 = cc.clampf(-10, 0, 100); // 0
const clamped3 = cc.clampf(50, 0, 100);  // 50

// Linear interpolation between two numbers
const val = cc.lerp(0, 100, 0.25);  // 25
const val2 = cc.lerp(10, 20, 0.5);  // 15

// Common use: clamp health
class Entity {
    private _hp: number = 100;
    private _maxHp: number = 100;

    takeDamage(amount: number): void {
        this._hp = cc.clampf(this._hp - amount, 0, this._maxHp);
    }
}

// Common use: smooth value animation
update(dt: number): void {
    this._currentValue = cc.lerp(this._currentValue, this._targetValue, 0.1);
}
```

Signatures:
