```typescript
const TRACK = {
    BODY: 0,
    ARMS: 1,
    EFFECTS: 2
} as const;

class FighterAnimationSystem {
    private skel: sp.SkeletonAnimation;

    constructor(jsonPath: string, atlasPath: string) {
        this.skel = new sp.SkeletonAnimation(jsonPath, atlasPath);
        this.setupMixes();
        this.setupListener();
    }

    getSkeleton(): sp.SkeletonAnimation {
        return this.skel;
    }

    private setupMixes(): void {
        this.skel.setMix('idle', 'walk', 0.15);
        this.skel.setMix('walk', 'idle', 0.15);
        this.skel.setMix('idle', 'crouch', 0.1);
        this.skel.setMix('crouch', 'idle', 0.1);
    }

    private setupListener(): void {
        this.skel.setAnimationListener(this, (
            track: spine.TrackEntry,
            type: number,
            event: spine.Event
        ) => {
            if (type === sp.AnimationEventType.COMPLETE && !track.loop) {
                this.onNonLoopComplete(track);
            }
        });
    }

    private onNonLoopComplete(track: spine.TrackEntry): void {
        const current = this.skel.getCurrent(TRACK.BODY);
        if (current && current.animation.name !== 'idle') return;
        this.skel.setAnimation(TRACK.BODY, 'idle', true);
    }

    setBodyAnimation(name: string, loop: boolean): void {
        this.skel.setAnimation(TRACK.BODY, name, loop);
    }

    setArmsAnimation(name: string, loop: boolean, alpha: number = 1.0): void {
        const track = this.skel.setAnimation(TRACK.ARMS, name, loop);
        if (track) {
            track.alpha = alpha;
        }
    }

    playEffect(name: string): void {
        const track = this.skel.setAnimation(TRACK.EFFECTS, name, false);
        if (track) {
            track.alpha = 0.8;
        }
    }

    punch(): void {
        this.setBodyAnimation('punch_body', false);
        this.setArmsAnimation('punch_arms', false);
        this.playEffect('punch_vfx');
    }

    block(): void {
        this.setArmsAnimation('block_arms', true, 0.9);
    }

    idle(): void {
        this.setBodyAnimation('idle', true);
        this.skel.clearTrack(TRACK.ARMS);
        this.skel.clearTrack(TRACK.EFFECTS);
    }
}

// Usage:
const fighter = new FighterAnimationSystem('res/fighter/fighter.json', 'res/fighter/fighter.atlas');
const skel = fighter.getSkeleton();
skel.setPosition(240, 80);
this.addChild(skel);
fighter.idle();
fighter.punch();
```

Track 0 handles body locomotion, track 1 handles arm overlays (blocking, punching), and track 2 handles visual effects. Each track can be controlled independently with different alpha values for partial blending.

`cc.AffineTransform` is a 2D affine transformation matrix with components (a, b, c, d, tx, ty):

```typescript
// Create an identity-like transform
const t = cc.affineTransformMake(1, 0, 0, 1, 0, 0);

// Create a translation transform
const translate = cc.affineTransformMake(1, 0, 0, 1, 100, 50);

// Matrix layout:
// | a  b  0 |
// | c  d  0 |
// | tx ty 1 |
```

The matrix encodes scale, rotation, and translation in a single 2D transformation. It's used internally by Cocos2d-x for node transforms and can be manipulated directly for advanced coordinate conversions.

Factory: `cc.affineTransformMake(a, b, c, d, tx, ty): cc.AffineTransform`

```typescript
declare namespace cc {
    class LayerMultiplex extends Layer {
        /**
         * Create a multiplex layer with one or more child layers.
         * @param layers - Layers to manage (variadic)
         */
        constructor(...layers: Layer[]);

        /**
         * Static factory method.
         */
        static create(...layers: Layer[]): LayerMultiplex;

        /**
         * Add a layer to the multiplex at the next available index.
         */
        addLayer(layer: Layer): void;

        /**
         * Switch to layer at index n. Hides current, shows n.
         * Current layer remains in memory.
         */
        switchTo(n: number): void;

        /**
         * Switch to layer at index n AND release the current layer.
         * The current layer is removed and freed — cannot be switched back to.
         */
        switchToAndReleaseMe(n: number): void;
    }
}
```

`LayerMultiplex` manages an ordered list of layers, displaying only one at a time. Layers are indexed starting at 0 in the order they were passed to the constructor or added via `addLayer`.

