output:
```typescript
class SfxPool {
    private effects: string[];
    private activeIds: number[] = [];

    private static readonly MIN_PITCH = 0.9;
    private static readonly MAX_PITCH = 1.1;

    constructor(effectPaths: string[]) {
        this.effects = effectPaths;
        for (const path of this.effects) {
            cc.audioEngine.preloadEffect(path);
        }
    }

    playRandom(): number | null {
        const index = Math.floor(Math.random() * this.effects.length);
        const path = this.effects[index];
        const pitch = SfxPool.MIN_PITCH +
            Math.random() * (SfxPool.MAX_PITCH - SfxPool.MIN_PITCH);

        const id = cc.audioEngine.playEffect(path, false, pitch, 0, 1.0);
        if (id !== null) {
            this.activeIds.push(id);
        }
        return id;
    }

    stopAll(): void {
        for (const id of this.activeIds) {
            cc.audioEngine.stopEffect(id);
        }
        this.activeIds = [];
    }
}

// Usage:
const hitSounds = new SfxPool([
    'res/audio/sfx_hit1.mp3',
    'res/audio/sfx_hit2.mp3',
    'res/audio/sfx_hit3.mp3'
]);
hitSounds.playRandom();  // plays random hit sound with slight pitch variation
hitSounds.stopAll();
```

The pool preloads all effects in the constructor. `playRandom` picks a random effect and applies a pitch variation between 0.9 and 1.1 using the `pitch` parameter of `playEffect`. Active IDs are tracked for `stopAll`.

