output:
```typescript
class LongPressDetector {
    private _node: cc.Node;
    private _callback: () => void;
    private _listener: cc.EventListener;
    private _schedulerKey: string;
    private _triggered: boolean = false;
    private static readonly HOLD_DURATION = 0.8;

    constructor(node: cc.Node, callback: () => void) {
        this._node = node;
        this._callback = callback;
        this._schedulerKey = 'longpress_' + Date.now();
    }

    enable(): void {
        this._listener = cc.eventManager.addListener({
            event: cc.EventListener.TOUCH_ONE_BY_ONE,
            swallowTouches: true,
            onTouchBegan: (touch: cc.Touch, event: cc.Event): boolean => {
                const loc = this._node.convertToNodeSpace(touch.getLocation());
                const size = this._node.getContentSize();
                if (!cc.rectContainsPoint(cc.rect(0, 0, size.width, size.height), loc)) {
                    return false;
                }
                this._triggered = false;
                this._node.scheduleOnce(() => {
                    this._triggered = true;
                    this._callback();
                }, LongPressDetector.HOLD_DURATION);
                return true;
            },
            onTouchMoved: (touch: cc.Touch, event: cc.EventTouch): void => {
                const dist = cc.pLength(cc.pSub(touch.getLocation(), touch.getStartLocation()));
                if (dist > 10) {
                    this._node.unscheduleAllCallbacks();
                }
            },
            onTouchEnded: (touch: cc.Touch, event: cc.Event): void => {
                this._node.unscheduleAllCallbacks();
            },
            onTouchCancelled: (touch: cc.Touch, event: cc.Event): void => {
                this._node.unscheduleAllCallbacks();
            }
        }, this._node);
    }

    disable(): void {
        this._node.unscheduleAllCallbacks();
        cc.eventManager.removeListener(this._listener);
    }
}
```

The detector schedules a delayed callback on touch start. If the finger moves more than 10px or lifts before 0.8s, the scheduled callback is cancelled.

Use the `durationTo` parameter in the `play` method to smoothly blend from the current animation to a new one:

```typescript
const armature = ccs.Armature.create('hero');
this.addChild(armature);

// Start with idle (no blend needed for first animation)
armature.animation.play('idle', -1, -1);

// Later, blend to walk over 8 frames
armature.animation.play('walk', 8, -1);

// Blend to run over 5 frames
armature.animation.play('run', 5, -1);
```

The `durationTo` parameter specifies how many frames the blend transition takes:
- `-1` = no blending, immediate switch
- `0` = instant switch (same as -1)
- `5-10` = smooth blend, good for walk/run transitions
- Higher values = slower, smoother transitions

This creates natural-looking transitions between animation states, similar to animation blend trees in 3D engines.

