Practical toggle pattern:
```typescript
class GameController {
    togglePause(target: cc.Node): void {
        const scheduler = cc.director.getScheduler();
        if (scheduler.isTargetPaused(target)) {
            scheduler.resumeTarget(target);
            cc.log('Resumed');
        } else {
            scheduler.pauseTarget(target);
            cc.log('Paused');
        }
    }

    pauseAllExcept(keepRunning: cc.Node[]): void {
        const scheduler = cc.director.getScheduler();
        scheduler.pauseAllTargets();
        for (const node of keepRunning) {
            scheduler.resumeTarget(node);
        }
    }
}
```

`isTargetPaused` returns `true` if `pauseTarget` or `pauseAllTargets` was called and the target has not been resumed yet.

