output:
```typescript
class CharacterController {
    private skel: sp.SkeletonAnimation;
    private currentState: string = 'idle';

    constructor(skel: sp.SkeletonAnimation) {
        this.skel = skel;
        this.skel.setMix('idle', 'walk', 0.2);
        this.skel.setMix('walk', 'idle', 0.2);
        this.skel.setMix('walk', 'run', 0.3);
        this.skel.setMix('run', 'walk', 0.3);
        this.skel.setMix('idle', 'run', 0.25);
        this.skel.setMix('run', 'idle', 0.25);
        this.skel.setAnimation(0, 'idle', true);
    }

    updateSpeed(speed: number): void {
        let targetState: string;
        if (speed <= 0) {
            targetState = 'idle';
        } else if (speed < 5) {
            targetState = 'walk';
        } else {
            targetState = 'run';
        }

        if (targetState !== this.currentState) {
            this.skel.setAnimation(0, targetState, true);
            this.currentState = targetState;
        }
    }
}
```

The constructor sets up bidirectional mix transitions between all animation pairs so any state change crossfades smoothly. `updateSpeed` only calls `setAnimation` when the target state differs from the current one, avoiding unnecessary animation restarts.

