Tag actions and retrieve them later:

```typescript
const mgr = cc.director.getActionManager();

// Create and tag an action
const moveAction = cc.moveTo(2.0, cc.p(500, 300));
moveAction.setTag(100);
sprite.runAction(moveAction);

// Later, find the action by tag
const action = mgr.getActionByTag(100, sprite);
if (action) {
    cc.log('Action found, is running');
} else {
    cc.log('Action finished or not found');
}

// Remove action by tag
mgr.removeActionByTag(100, sprite);
```

Practical example — interruptible movement:
```typescript
class MovableCharacter extends cc.Sprite {
    private static readonly MOVE_TAG = 1;

    moveTo(target: cc.Point): void {
        const mgr = cc.director.getActionManager();

        // Stop any current movement
        mgr.removeActionByTag(MovableCharacter.MOVE_TAG, this);

        // Calculate duration from distance
        const dist = cc.pDistance(this.getPosition(), target);
        const duration = dist / 200; // 200 px/s

        const move = cc.moveTo(duration, target);
        move.setTag(MovableCharacter.MOVE_TAG);
        this.runAction(move);
    }

    isMoving(): boolean {
        const mgr = cc.director.getActionManager();
        return mgr.getActionByTag(MovableCharacter.MOVE_TAG, this) !== null;
    }
}
```

