const color: cc.Color = cc.hexToColor('#FF8800');
cc.log(color.r, color.g, color.b); // 255, 136, 0

// cc.Color to hex string
const hex: string = cc.colorToHex(cc.color(255, 136, 0));
cc.log(hex); // '#ff8800'

// Practical example: apply color from config
