Selective pause pattern (pause game but keep UI):
```typescript
class SelectivePause {
    private _pausedTargets: cc.Class[] = [];
    private _uiNodes: cc.Node[] = [];

    registerUI(node: cc.Node): void {
        this._uiNodes.push(node);
    }

    pauseGameplay(): void {
        const scheduler = cc.director.getScheduler();
        // Pause everything
        scheduler.pauseAllTargets();

        // Resume UI nodes
        for (const ui of this._uiNodes) {
            scheduler.resumeTarget(ui);
        }
    }

    resumeGameplay(): void {
        const scheduler = cc.director.getScheduler();
        scheduler.resumeTargets(this._pausedTargets);
    }
}
```

Cocos2d-x provides global type-check functions that return type-narrowed booleans:

```typescript
cc.isFunction(obj): obj is Function
cc.isNumber(obj): obj is number
cc.isString(obj): obj is string
cc.isArray(obj): obj is any[]
cc.isUndefined(obj): obj is undefined
cc.isObject(obj): obj is object
```

Examples:
```typescript
function processValue(val: unknown): void {
    if (cc.isString(val)) {
        cc.log('String value:', val.toUpperCase());
    } else if (cc.isNumber(val)) {
        cc.log('Number value:', val.toFixed(2));
    } else if (cc.isArray(val)) {
        cc.log('Array with', val.length, 'items');
    } else if (cc.isFunction(val)) {
        val();
    } else if (cc.isObject(val)) {
        cc.log('Object:', JSON.stringify(val));
    } else if (cc.isUndefined(val)) {
        cc.warn('Value is undefined');
    }
}

// Useful for validating config/data
function setSpeed(speed: unknown): void {
    if (!cc.isNumber(speed)) {
        cc.error('Speed must be a number, got:', typeof speed);
        return;
    }
    this._speed = speed;
}
```

These are type guards in TypeScript, so the compiler narrows the type inside the `if` block.

