```typescript
class ScreenFade {
    private overlay: cc.LayerColor;
    private parent: cc.Node;

    constructor(parent: cc.Node) {
        this.parent = parent;
        this.overlay = new cc.LayerColor(cc.color(0, 0, 0, 0));
        this.overlay.setContentSize(cc.director.getWinSize());
        this.overlay.setLocalZOrder(9999);
        this.parent.addChild(this.overlay);
    }

    fadeOut(duration: number, callback: () => void): void {
        this.overlay.setOpacity(0);
        this.overlay.runAction(
            cc.sequence(
                cc.fadeTo(duration, 255),
                cc.callFunc(callback)
            )
        );
    }

    fadeIn(duration: number): void {
        this.overlay.setOpacity(255);
        this.overlay.runAction(cc.fadeTo(duration, 0));
    }
}

// Usage:
const fade = new ScreenFade(this);
fade.fadeOut(0.5, () => {
    // Load next scene
    cc.director.runScene(new NextScene());
    fade.fadeIn(0.5);
});
```

The overlay starts fully transparent (alpha 0). `fadeOut` animates opacity to 255 (black), then triggers the callback. `fadeIn` animates from 255 back to 0. Using `cc.fadeTo` with `cc.sequence` and `cc.callFunc` chains the actions smoothly.

```typescript
class TabPanel extends cc.LayerColor {
    constructor(color: cc.Color, label: string) {
        super(color);
        this.init();
        const winSize = cc.director.getWinSize();

        const text = new cc.LabelTTF(label, 'Arial', 32);
        text.setPosition(winSize.width / 2, winSize.height / 2);
        this.addChild(text);
    }
}

class TabbedInterface extends cc.Layer {
    private multiplex: cc.LayerMultiplex;
    private tabNames: string[];
    private currentTab: number = 0;

    constructor(tabs: { name: string; color: cc.Color }[]) {
        super();
        this.tabNames = tabs.map(t => t.name);

        const panels = tabs.map(t => new TabPanel(t.color, t.name));
        this.multiplex = new cc.LayerMultiplex(...panels);
        this.addChild(this.multiplex);

        this.createTabButtons(tabs);
    }

    private createTabButtons(tabs: { name: string; color: cc.Color }[]): void {
        const winSize = cc.director.getWinSize();
        const tabWidth = winSize.width / tabs.length;

        tabs.forEach((tab, index) => {
            const btn = new cc.LayerColor(
                cc.color(80, 80, 80, 255),
                tabWidth - 4, 40
            );
            btn.setPosition(index * tabWidth + 2, winSize.height - 44);
            this.addChild(btn, 10);

            const label = new cc.LabelTTF(tab.name, 'Arial', 16);
            label.setPosition(tabWidth / 2, 20);
            btn.addChild(label);
        });
    }

    switchTab(index: number): void {
        if (index === this.currentTab) return;
        if (index < 0 || index >= this.tabNames.length) return;

        this.multiplex.switchTo(index);
        this.currentTab = index;
    }
}

// Usage:
const tabbed = new TabbedInterface([
    { name: 'Inventory', color: cc.color(40, 60, 80, 255) },
    { name: 'Stats',     color: cc.color(60, 40, 80, 255) },
    { name: 'Skills',    color: cc.color(80, 60, 40, 255) }
]);
scene.addChild(tabbed);
tabbed.switchTab(1);
```

Each tab is a `TabPanel` (extending `cc.LayerColor`) managed by `cc.LayerMultiplex`. Tab buttons are `cc.LayerColor` rectangles positioned at the top. `switchTab` delegates to `multiplex.switchTo` while tracking the active index.

**cc.SpriteBatchNode** batches all child sprites into a single draw call, but requires all children to share the same texture.

**Use SpriteBatchNode when:**
- Many sprites share one atlas texture (bullets, particles, tiles)
- Draw call count is a bottleneck
- Sprites don't need different blend modes

**Add sprites directly when:**
- Sprites use different textures
- Each sprite needs a different blend function
- You have few sprites (optimization is unnecessary)
- Sprites need to be in different z-order layers relative to non-sprite nodes

```typescript
// WITH batch node: 1 draw call for 100 sprites
cc.spriteFrameCache.addSpriteFrames('res/bullets.plist', 'res/bullets.png');
const batch = new cc.SpriteBatchNode('res/bullets.png', 100);
this.addChild(batch);
for (let i = 0; i < 100; i++) {
    const bullet = new cc.Sprite(cc.spriteFrameCache.getSpriteFrame('bullet.png'));
    batch.addChild(bullet);
}

// WITHOUT batch node: 100 draw calls
for (let i = 0; i < 100; i++) {
    const bullet = new cc.Sprite('res/bullet.png');
    this.addChild(bullet);
}
```

In modern Cocos2d-x with auto-batching, direct child sprites using the same texture may already be batched by the renderer, reducing the need for explicit SpriteBatchNode usage.

