```

output:
```typescript
class CrossfadeSprite extends cc.Node {
    private _spriteA: cc.Sprite;
    private _spriteB: cc.Sprite;

    constructor(textureA: string, textureB: string) {
        super();
        this._spriteA = new cc.Sprite(textureA);
        this._spriteB = new cc.Sprite(textureB);
        this._spriteB.setOpacity(0);
        this.addChild(this._spriteA, 0);
        this.addChild(this._spriteB, 1);
    }

    crossfade(duration: number, onComplete?: () => void): void {
        this._spriteA.stopAllActions();
        this._spriteB.stopAllActions();

        this._spriteA.runAction(cc.fadeOut(duration));

        const fadeIn = cc.fadeIn(duration);
        if (onComplete) {
            this._spriteB.runAction(cc.sequence(fadeIn, cc.callFunc(onComplete)));
        } else {
            this._spriteB.runAction(fadeIn);
        }
    }

    swap(): void {
        const temp = this._spriteA;
        this._spriteA = this._spriteB;
        this._spriteB = temp;
        this._spriteA.setOpacity(255);
        this._spriteB.setOpacity(0);
    }
}

// Usage:
const cf = new CrossfadeSprite('res/day.png', 'res/night.png');
cf.setPosition(240, 160);
this.addChild(cf);
cf.crossfade(2.0, () => cc.log('Crossfade done'));
```

instruction:
Find and fix the bug in this scene transition code:

```typescript
class GameLayer extends cc.Layer {
    onGameOver(): void {
        const gameOverScene = new GameOverScene();
        cc.director.pushScene(gameOverScene);
        cc.director.purgeCachedData();
    }
}
```

output:
The bug is calling `purgeCachedData()` **after** `pushScene()`. When you push a scene, the current scene stays in memory on the stack. Purging cached data immediately after push will:

1. Destroy textures that the current (background) game scene still references
2. Possibly destroy textures needed by the new GameOverScene
3. Cause visual glitches or crashes when popping back

Fixed code:
```typescript
class GameLayer extends cc.Layer {
    onGameOver(): void {
        // Option 1: Push without purging (recommended for push/pop)
        const gameOverScene = new GameOverScene();
        cc.director.pushScene(gameOverScene);
        // Do NOT purge — the game scene is still on the stack
    }
}

// If you want to purge, use runScene instead (replaces, not pushes):
class GameLayer2 extends cc.Layer {
    onGameOver(): void {
        cc.director.purgeCachedData(); // purge BEFORE running new scene
        const gameOverScene = new GameOverScene();
        cc.director.runScene(new cc.TransitionFade(0.5, gameOverScene));
    }
}
```

Rule: only purge when using `runScene` (old scene is destroyed), never with `pushScene` (old scene stays alive).

Grid actions can be sequenced with regular actions using cc.stopGrid:

```typescript
// Apply ripple effect then clean up
node.runAction(cc.sequence(
    cc.ripple3D(1.5, cc.size(32, 24), cc.p(240, 160), 240, 4, 160),
    cc.stopGrid(),
    cc.callFunc(() => cc.log('Ripple complete'))
));

// Reuse grid for multiple effects
node.runAction(cc.sequence(
    cc.shaky3D(1.0, cc.size(15, 10), 5, false),
    cc.reuseGrid(1), // reuse the grid for next effect
    cc.waves3D(1.5, cc.size(15, 10), 3, 20),
    cc.stopGrid()
));
```

Always call `cc.stopGrid()` after grid actions to restore normal rendering. Use `cc.reuseGrid(times)` to chain multiple grid effects without recreating the grid mesh.

Use callFunc to swap textures between action phases:

```typescript
class AnimatedCharacter extends cc.Sprite {
    attack(): void {
        const windupFrames = this.buildAnim('attack_windup_', 3, 0.08);
        const strikeFrames = this.buildAnim('attack_strike_', 4, 0.06);
        const recoverFrames = this.buildAnim('attack_recover_', 3, 0.1);

        this.runAction(cc.sequence(
            cc.animate(windupFrames),
            cc.callFunc(() => this.checkHitbox()),
            cc.animate(strikeFrames),
            cc.animate(recoverFrames),
            cc.callFunc(() => this.setIdle())
        ));
    }

    private buildAnim(prefix: string, count: number, delay: number): cc.Animation {
        const frames: cc.SpriteFrame[] = [];
        for (let i = 1; i <= count; i++) {
            const frame = cc.spriteFrameCache.getSpriteFrame(prefix + i + '.png');
            if (frame) frames.push(frame);
        }
        return new cc.Animation(frames, delay);
    }

    private setIdle(): void {
        this.setSpriteFrame(cc.spriteFrameCache.getSpriteFrame('hero_idle.png'));
    }
}
```

instruction:
Find and fix the bug:

```typescript
const v = cc.p(0, 0);
const normalized = cc.pNormalize(v);
const moved = cc.pMult(normalized, 100);
node.setPosition(moved);
```

output:
The bug is normalizing a zero-length vector `cc.p(0, 0)`. Normalizing a zero vector involves dividing by zero, which produces `NaN` values. The resulting `moved` point will be `cc.p(NaN, NaN)`, causing the node to disappear.

Fixed code:
```typescript
const v = cc.p(0, 0);
const len = cc.pLength(v);
if (len > cc.FLT_EPSILON) {
    const normalized = cc.pNormalize(v);
    const moved = cc.pMult(normalized, 100);
    node.setPosition(moved);
}
```

Always check that a vector has non-zero length before normalizing. Use `cc.FLT_EPSILON` (float epsilon) for the comparison to handle floating-point imprecision.

