```typescript
function showNotification(message: string, parent: cc.Node): void {
    const winSize = cc.director.getWinSize();

    const banner = new ccui.Layout();
    banner.setSize(cc.size(winSize.width, 50));
    banner.setBackGroundColorType(ccui.Layout.BG_COLOR_SOLID);
    banner.setBackGroundColor(cc.color(30, 150, 30));
    banner.setBackGroundColorOpacity(230);
    banner.setPosition(0, winSize.height); // above screen

    const label = new ccui.Text(message, 'Arial', 18);
    label.setPosition(winSize.width / 2, 25);
    banner.addChild(label);

    parent.addChild(banner, 1000);

    const slideIn = cc.moveTo(0.3, cc.p(0, winSize.height - 50));
    const wait = cc.delayTime(2.0);
    const slideOut = cc.moveTo(0.3, cc.p(0, winSize.height));
    const remove = cc.callFunc(() => banner.removeFromParent());

    banner.runAction(cc.sequence(
        slideIn.easing(cc.easeBackOut()),
        wait,
        slideOut,
        remove
    ));
}
