```typescript
interface VisionCone {
    readonly position: cc.Point;
    readonly direction: cc.Point;  // unit vector
    readonly range: number;
    readonly halfAngle: number;    // radians
}

function isInVisionCone(cone: VisionCone, target: cc.Point): boolean {
    // Distance check
    const distSQ = cc.pDistanceSQ(cone.position, target);
    if (distSQ > cone.range * cone.range) return false;

    // Angle check
    const toTarget = cc.pNormalize(cc.pSub(target, cone.position));
    const angle = cc.pAngle(cone.direction, toTarget);
    return angle <= cone.halfAngle;
}

// Usage:
const guardVision: VisionCone = {
    position: cc.p(200, 200),
    direction: cc.pNormalize(cc.p(1, 0)),  // facing right
    range: 150,
    halfAngle: 45 * cc.RAD  // 90 degree total cone
};

const playerPos = cc.p(300, 220);

if (isInVisionCone(guardVision, playerPos)) {
    cc.log('Player spotted!');
}

// Update guard facing direction
function setGuardFacing(guard: VisionCone, angleDeg: number): VisionCone {
    const rad = angleDeg * cc.RAD;
    return {
        ...guard,
        direction: cc.p(Math.cos(rad), Math.sin(rad))
    };
}
```

