Here's an event-driven architecture with a central GameManager and decoupled UI listeners:

```typescript
// Shared event constants
const Notifications = {
    HEALTH_CHANGED: 'notify:health',
    COINS_COLLECTED: 'notify:coins',
    ENEMY_KILLED: 'notify:enemy_killed',
    GAME_OVER: 'notify:game_over'
} as const;

// GameManager dispatches events — knows nothing about UI
class GameManager {
    private _health: number = 100;
    private _coins: number = 0;
    private _kills: number = 0;

    takeDamage(amount: number): void {
        this._health = Math.max(0, this._health - amount);
        cc.eventManager.dispatchCustomEvent(Notifications.HEALTH_CHANGED, {
            current: this._health, max: 100
        });
        if (this._health <= 0) {
            cc.eventManager.dispatchCustomEvent(Notifications.GAME_OVER, {
                coins: this._coins, kills: this._kills
            });
        }
    }

    collectCoin(): void {
        this._coins++;
        cc.eventManager.dispatchCustomEvent(Notifications.COINS_COLLECTED, {
            total: this._coins
        });
    }
}

// HealthBar listens only for health changes
class HealthBar extends cc.Node {
    private _listener: cc.EventListener;
    onEnter(): void {
        super.onEnter();
        this._listener = cc.eventManager.addCustomListener(
            Notifications.HEALTH_CHANGED,
            (event: cc.Event) => {
                const data = event.getUserData<{ current: number; max: number }>();
                this.updateBar(data.current / data.max);
            }
        );
    }
    onExit(): void {
        cc.eventManager.removeListener(this._listener);
        super.onExit();
    }
}

// CoinCounter listens only for coin events
class CoinCounter extends cc.Node {
    private _listener: cc.EventListener;
    onEnter(): void {
        super.onEnter();
        this._listener = cc.eventManager.addCustomListener(
            Notifications.COINS_COLLECTED,
            (event: cc.Event) => {
                const data = event.getUserData<{ total: number }>();
                this.updateLabel(data.total);
            }
        );
    }
    onExit(): void {
        cc.eventManager.removeListener(this._listener);
        super.onExit();
    }
}
```

This pattern keeps components fully decoupled — GameManager only dispatches, UI only listens.

