Use a horizontal ScrollView with level buttons:

```typescript
const LEVEL_COUNT = 30;
const COLS_PER_ROW = 5;
const BTN_SIZE = 60;
const GAP = 15;
const rows = Math.ceil(LEVEL_COUNT / COLS_PER_ROW);
const pageWidth = COLS_PER_ROW * (BTN_SIZE + GAP) + GAP;
const pages = Math.ceil(rows / 3);
const innerWidth = pages * 320;

const sv = new ccui.ScrollView();
sv.setSize(cc.size(320, 240));
sv.setDirection(ccui.ScrollView.DIR_HORIZONTAL);
sv.setInnerContainerSize(cc.size(innerWidth, 240));
sv.setBounceEnabled(true);
sv.setPosition(80, 40);

for (let i = 0; i < LEVEL_COUNT; i++) {
    const page = Math.floor(i / 15);
    const local = i % 15;
    const col = local % COLS_PER_ROW;
    const row = Math.floor(local / COLS_PER_ROW);
    const x = page * 320 + GAP + col * (BTN_SIZE + GAP) + BTN_SIZE / 2;
    const y = 240 - GAP - row * (BTN_SIZE + GAP) - BTN_SIZE / 2;

    const btn = new ccui.Button('level_btn.png');
    btn.setScale9Enabled(true);
    btn.setSize(cc.size(BTN_SIZE, BTN_SIZE));
    btn.setTitleText(String(i + 1));
    btn.setTitleFontSize(20);
    btn.setPosition(x, y);
    btn.addClickEventListener(() => this.startLevel(i));
    sv.getInnerContainer().addChild(btn);
}

this.addChild(sv);
```

Use cc.actionTween with a custom update to interpolate colors:

```typescript
function colorGradientAction(
    node: cc.Node, fromColor: cc.Color, toColor: cc.Color, duration: number
): void {
    const tweenNode = new cc.Node();
    tweenNode.updateTweenAction = function(value: number, key: string) {
        if (key === 'colorT') {
            const t = value / 100;
            const r = Math.round(fromColor.r + (toColor.r - fromColor.r) * t);
            const g = Math.round(fromColor.g + (toColor.g - fromColor.g) * t);
            const b = Math.round(fromColor.b + (toColor.b - fromColor.b) * t);
            node.setColor(cc.color(r, g, b));
        }
    };
    node.addChild(tweenNode);
    tweenNode.runAction(cc.sequence(
        cc.actionTween(duration, 'colorT', 0, 100),
        cc.removeSelf()
    ));
}

// Usage: transition from blue to red over 2 seconds
colorGradientAction(sprite, cc.color(0, 100, 255), cc.color(255, 50, 0), 2.0);
```

