```typescript
class DebugLayer extends cc.Layer {
    private _draw: cc.DrawNode;
    private _target: cc.Node;

    constructor(target: cc.Node) {
        super();
        this._target = target;
    }

    onEnter(): void {
        super.onEnter();
        this._draw = cc.DrawNode.create();
        this.addChild(this._draw);
        this.scheduleUpdate();
    }

    update(dt: number): void {
        this._draw.clear();
        const box = this._target.getBoundingBoxToWorld();
        this._draw.drawRect(
            cc.p(box.x, box.y),
            cc.p(box.x + box.width, box.y + box.height),
            null,   // no fill
            1,
            cc.color(255, 0, 0, 255)
        );
    }
}

// Usage:
const hero = new cc.Sprite('res/hero.png');
this.addChild(hero);
const debug = new DebugLayer(hero);
this.addChild(debug);
```

The key pattern is calling `clear()` every frame before redrawing, so the rectangle follows the target node.

